const RUNTIME_CONFIG =
  typeof window !== "undefined" &&
  window.GAME_RUNTIME_CONFIG &&
  typeof window.GAME_RUNTIME_CONFIG === "object"
    ? window.GAME_RUNTIME_CONFIG
    : {};

function getRuntimeConfig(path, fallbackValue) {
  if (!path) return fallbackValue;
  const keys = String(path)
    .split(".")
    .map((item) => item.trim())
    .filter(Boolean);
  let cursor = RUNTIME_CONFIG;
  for (const key of keys) {
    if (!cursor || typeof cursor !== "object" || !(key in cursor)) {
      return fallbackValue;
    }
    cursor = cursor[key];
  }
  return cursor === undefined ? fallbackValue : cursor;
}

function toPositiveInt(value, fallbackValue) {
  const num = Number(value);
  if (!Number.isFinite(num) || num <= 0) return fallbackValue;
  return Math.round(num);
}

