      eventCards: mastersYearChoices,
      miniCards: mastersMiniActions,
      miniNotice: mastersMiniNotice,
      projectProgress: mastersProjectProgress,
      termTimeInfo: mastersTermTimeInfo,
      fxNote: mastersFxNote,
      eventNotice: mastersEventNotice,
