function applyDevDataPatchFromTextarea() {
  if (!state.devMode) {
    if (devDataNote) devDataNote.textContent = "仅开发者模式可用。";
    return;
  }
  const raw = devDataTextarea?.value?.trim();
  if (!raw) {
    if (devDataNote) devDataNote.textContent = "请输入 JSON 补丁。";
    return;
  }
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (error) {
    if (devDataNote) devDataNote.textContent = "JSON 解析失败，请检查格式。";
    return;
  }
  const result = applyDataPatchObject(parsed, { runtime: false });
  if (devDataNote) devDataNote.textContent = result.message;
}

function renderDevPanel() {
  if (!devPanel) return;
  devPanel.classList.toggle("hidden", !state.devMode);
  if (devRegressionPanel) devRegressionPanel.classList.toggle("hidden", !state.devMode);
  if (devTuningPanel) devTuningPanel.classList.toggle("hidden", !state.devMode);
  if (devDataPanel) devDataPanel.classList.toggle("hidden", !state.devMode);
  if (CHAT_PUBLIC_RELEASE && !state.devMode && chatAiSettings.apiKey) {
    chatAiSettings = normalizeChatAiSettings({
      ...chatAiSettings,
      mode: "mimo",
      apiKey: "",
    });
    saveChatAiSettings();
  }
  if (state.devMode && devTextarea && !devTextarea.value) {
    devTextarea.value = serializeStateForDev({ includeFlowTemplates: true });
  }
  if (state.devMode) {
    fillDevTuneInputsFromState();
  }
  applyChatAiUiMode();
}

function initChatRoles() {
  if (!chatRole) return;
  const current = chatRole.value;
  const roles = getChatRoles();
  chatRole.innerHTML = "";
  roles.forEach((role) => {
    const option = document.createElement("option");
    option.value = role.id;
    option.textContent = role.name;
    chatRole.appendChild(option);
  });
  const hasCurrent = roles.some((role) => role.id === current);
  const nextId = hasCurrent ? current : roles[0]?.id;
  if (nextId) {
    chatRole.value = nextId;
    ensureChatRoleState(nextId);
  }
  updateChatControls();
}

function buildAppealUpdateLines() {
  const candidates = [];
  const addCandidate = (score, line, minScore = 0) => {
    if (Number.isFinite(score) && score > minScore) {
      candidates.push({ score, line });
    }
  };

  if (Number.isFinite(state.stats.gpa)) {
    addCandidate(
      (state.stats.gpa / 4) * 100,
      `更新：GPA 目前为 ${state.stats.gpa.toFixed(2)}，持续提升。`,
    );
  }
  if (Number.isFinite(state.stats.test)) {
    addCandidate(
      (state.stats.test / 1600) * 100,
      `更新：标化/语言成绩 ${Math.round(state.stats.test)}，近期刷新。`,
    );
  }
  if (Number.isFinite(state.stats.english)) {
    addCandidate(
      (state.stats.english / 120) * 100,
      `更新：英语成绩 ${Math.round(state.stats.english)}，已补交最新成绩报告。`,
    );
  }

  addCandidate(state.stats.awards ?? 0, `新增奖项/竞赛成果：奖项影响 ${Math.round(state.stats.awards ?? 0)} / 100。`, 5);
  addCandidate(state.stats.activities ?? 0, `项目进展：活动深度 ${Math.round(state.stats.activities ?? 0)} / 100。`, 5);
  addCandidate(state.stats.leadership ?? 0, `新增领导力证据：领导力 ${Math.round(state.stats.leadership ?? 0)} / 100。`, 5);
  addCandidate(state.stats.essayTrack ?? 0, `文书迭代更新：文书进度 ${Math.round(state.stats.essayTrack ?? 0)} / 100。`, 5);
  addCandidate(state.stats.recStrength ?? 0, `推荐信更新：推荐强度 ${Math.round(state.stats.recStrength ?? 0)} / 100。`, 5);
  addCandidate(state.stats.reputation ?? 0, `影响力更新：社会影响 ${Math.round(state.stats.reputation ?? 0)} / 100。`, 5);

  const projectLabels = {
    "research-track": "科研主线",
    "writing-archive": "写作专栏",
    "art-portfolio": "作品集",
    "startup-track": "创业项目",
    "impact-project": "社区影响力",
  };
  const streak = Object.entries(state.projectStreaks || {})
    .filter(([, value]) => value >= 1)
    .sort((a, b) => b[1] - a[1])[0];
  if (streak) {
    const [key, value] = streak;
    addCandidate(70 + value * 5, `项目进展：${projectLabels[key] || key} 连续推进 ${value} 学期，形成阶段性成果。`);
  }

  const lines = candidates
    .sort((a, b) => b.score - a.score)
    .map((item) => item.line)
    .filter((line, index, arr) => arr.indexOf(line) === index)
    .slice(0, 4);

  if (!lines.length) {
    return [
      "更新：已补交最新成绩与阶段性报告。",
      "新增：持续推进长期项目并整理成果材料。",
      "更新：近期参与竞赛/研究并补充相关证明。",
    ];
  }
  if (lines.length === 1) {
    lines.push("更新：已补交推荐人补充说明与阶段性成果。");
  }
  return lines;
}

function getAppealEvidenceSelection() {
  const selected = state.chatContext?.appealEvidence;
  if (!Array.isArray(selected)) return [];
  return selected.filter((id, index, arr) => arr.indexOf(id) === index);
}

function setAppealEvidenceSelection(ids) {
  if (!state.chatContext) return;
  const normalized = (ids || [])
    .filter((id) => APPEAL_EVIDENCE_OPTIONS.some((item) => item.id === id))
    .slice(0, APPEAL_EVIDENCE_SLOT_LIMIT);
  state.chatContext.appealEvidence = normalized;
}

function evaluateAppealEvidence() {
  const selectedIds = getAppealEvidenceSelection();
  const selectedItems = selectedIds
    .map((id) => APPEAL_EVIDENCE_OPTIONS.find((item) => item.id === id))
    .filter(Boolean);
  let bonus = 0;
  const lines = [];
  selectedItems.forEach((item) => {
    const quality = clamp(item.quality ? item.quality() : 0.6, 0, 1);
    const weighted = item.weight * (0.7 + quality * 0.6);
    bonus += weighted;
    if (item.line) {
      lines.push(item.line());
    }
  });
  const cap = selectedItems.length >= 3 ? 0.16 : 0.12;
  return {
    selectedIds,
    selectedItems,
    selectedCount: selectedItems.length,
    bonus: clamp(bonus, 0, cap),
    lines: lines.slice(0, 4),
    hasStrongEvidence: selectedItems.length > 0 && bonus >= 0.04,
  };
}

function autoFillAppealEvidence() {
  const ranked = APPEAL_EVIDENCE_OPTIONS.map((item) => ({
    id: item.id,
    score: (item.quality ? item.quality() : 0.5) * item.weight,
  }))
    .filter((item) => item.score > 0.006)
    .sort((a, b) => b.score - a.score)
    .slice(0, APPEAL_EVIDENCE_SLOT_LIMIT)
    .map((item) => item.id);
  setAppealEvidenceSelection(ranked);
  return ranked;
}

function toggleAppealEvidenceChoice(evidenceId) {
  const current = getAppealEvidenceSelection();
  if (current.includes(evidenceId)) {
    setAppealEvidenceSelection(current.filter((id) => id !== evidenceId));
    return;
  }
  if (current.length >= APPEAL_EVIDENCE_SLOT_LIMIT) {
    if (appealEvidenceNote) {
      appealEvidenceNote.textContent = `附件槽位已满（最多 ${APPEAL_EVIDENCE_SLOT_LIMIT} 个）。`;
    }
    return;
  }
  setAppealEvidenceSelection([...current, evidenceId]);
}

function renderAppealEvidenceChoices(canAppeal) {
  if (!appealEvidencePanel || !appealEvidenceChoices || !appealEvidenceNote) return;
  appealEvidencePanel.style.display = canAppeal ? "block" : "none";
  if (!canAppeal) {
    appealEvidenceChoices.innerHTML = "";
    appealEvidenceNote.textContent = "";
    return;
  }
  const selected = new Set(getAppealEvidenceSelection());
  const evidenceEval = evaluateAppealEvidence();
  appealEvidenceChoices.innerHTML = "";
  APPEAL_EVIDENCE_OPTIONS.forEach((item) => {
    const active = selected.has(item.id);
    const quality = clamp(item.quality ? item.quality() : 0.6, 0, 1);
    const card = document.createElement("button");
    card.type = "button";
    card.className = `choice${active ? " active" : ""}`;
    card.innerHTML = `<strong>${item.name}</strong><p>${item.desc}</p><small>证据质量 ${Math.round(
      quality * 100,
    )}% · 权重 ${(item.weight * 100).toFixed(1)}%</small>`;
    card.addEventListener("click", () => {
      toggleAppealEvidenceChoice(item.id);
      renderAppealEvidenceChoices(true);
    });
    appealEvidenceChoices.appendChild(card);
  });
  appealEvidenceNote.textContent = `已选 ${evidenceEval.selectedCount} / ${APPEAL_EVIDENCE_SLOT_LIMIT}，预计申诉加成 ${(evidenceEval.bonus * 100).toFixed(
    1,
  )}%。`;
}

function buildAppealTemplate(school) {
  const undergradResult = state.results.find((item) => item.id === school.id);
  const gradResult = (state.gradResults || []).find((item) => item.id === school.id);
  const targetResult = gradResult || undergradResult;
  const isGradAppeal = !!gradResult;
  const appealMajorId = isGradAppeal
    ? gradResult.majorId || getGradApplyMajorIdForProgramType(gradResult.programType)
    : state.majorId;
  const major = MAJORS.find((item) => item.id === appealMajorId);
  const statusLine =
    targetResult?.status === "候补"
      ? "感谢候补通知，我仍将贵校作为最优先选择。"
      : "我理解录取竞争激烈，仍希望补充重要更新。";
  const updates = buildAppealUpdateLines();
  const evidenceEval = evaluateAppealEvidence();
  const updatePool = evidenceEval.lines.length ? evidenceEval.lines : updates;
  const updateLines = updatePool.length
    ? updatePool.map((line) => `- ${line}`).join("\n")
    : "- 更新：近期完成新的项目成果与学术进展。";
  const evidenceLine = evidenceEval.selectedItems.length
    ? `附件目录：${evidenceEval.selectedItems.map((item) => item.name).join("、")}。`
    : "附件目录：已附成绩/项目/推荐相关补充材料。";
  return `尊敬的 ${school.name} 招生委员会：\n` +
    `您好！我是 ${state.playerName || "申请者"}，申请贵校 ${major?.name || "意向专业"}。\n` +
    `${isGradAppeal ? `本次为${getGradProgramTypeLabel(gradResult.programType)}阶段复核申请。\n` : ""}` +
    `${statusLine}\n` +
    `我想补充以下更新：\n` +
    `${updateLines}\n` +
    `${evidenceLine}\n` +
    `（可选）如学校允许，我愿意捐款 US$____ 以支持学校发展。\n` +
    `这些更新体现了我在学术与长期投入上的提升，也更匹配贵校的培养方向。\n` +
    `若有可能，恳请您重新考虑我的申请。非常感谢您的时间与评审。\n` +
    `此致\n敬礼\n${state.playerName || "申请者"}`;
}

function getAdmissionsUndergradResult(schoolId) {
  return (state.results || []).find((item) => item.id === schoolId) || null;
}

function getAdmissionsGradResult(schoolId) {
  return (state.gradResults || []).find((item) => item.id === schoolId) || null;
}

function canApplyCombinedDoctoralForSchool(school, result) {
  if (!school || !result || result.status !== "录取") return false;
  if (!state.finalChoice || state.finalChoice !== school.id) return false;
  if (state.mastersStarted || state.phdStarted) return false;
  const windowKey = getUndergradCombinedWindowKey(school.id);
  if (!windowKey) return false;
  if (windowKey === "pre_undergrad") {
    return true;
  }
  const academic = clamp(result.academicScore ?? 0, 0, 1);
  const fit = clamp(result.fitScore ?? 0, 0, 1);
  if (windowKey === "late_undergrad") {
    const profile = state.undergradProfile || getDefaultUndergradProfile();
    const ugGpa = clamp(((profile.gpa || 2.9) - 2.2) / 1.8, 0, 1);
    const ugResearch = clamp((profile.research || 0) / 100, 0, 1);
    const ugLeadership = clamp((profile.leadership || 0) / 100, 0, 1);
    const ugStressControl = clamp(1 - (profile.stress || 0) / 100, 0, 1);
    const score =
      academic * 0.2 + fit * 0.22 + ugGpa * 0.23 + ugResearch * 0.23 + ugLeadership * 0.07 + ugStressControl * 0.05;
    return score >= 0.7 && ugResearch >= 0.62 && ugGpa >= 0.68;
  }
  const awards = clamp((state.stats.awards ?? 0) / 100, 0, 1);
  const activities = clamp((state.stats.activities ?? 0) / 100, 0, 1);
  const essay = clamp((state.stats.essayTrack ?? 0) / 100, 0, 1);
  const score = academic * 0.36 + fit * 0.26 + awards * 0.2 + activities * 0.12 + essay * 0.06;
  return score >= 0.74 && academic >= 0.68 && fit >= 0.72;
}

function canApplyMsPhdForSchool(school, gradResult = null) {
  if (!school) return false;
  if (state.msPhdApproved && state.msPhdSchoolId === school.id) return false;
  const windowKey = getMastersCombinedWindowKey(school.id);
  if (!windowKey) return false;
  if (windowKey === "late_masters") {
    if (!(state.mastersStarted && state.mastersSchoolId === school.id && !state.phdStarted)) return false;
    const profile = state.mastersProfile || getDefaultMastersProfile();
    const gpa = clamp((profile.gpa - 2.4) / 1.6, 0, 1);
    const research = clamp((profile.research || 0) / 100, 0, 1);
    const thesis = clamp((profile.thesis || 0) / 100, 0, 1);
    const stressControl = clamp(1 - (profile.stress || 0) / 100, 0, 1);
    const score = gpa * 0.3 + research * 0.38 + thesis * 0.24 + stressControl * 0.08;
    return score >= 0.62 && research >= 0.52;
  }
  if (!gradResult || gradResult.status !== "录取") return false;
  if (gradResult.revealed === false) return false;
  if (gradResult.programType === "phd") return false;
  if (state.selectedGradOfferId && state.selectedGradOfferId !== school.id) return false;
  if (state.postGradPath !== POSTGRAD_PATHS.MASTERS && !state.mastersStarted) return false;
  if (windowKey === "pre_masters") {
    return true;
  }
  const chance = evaluateMastersChance(school, { programMode: "msphd" });
  return chance >= 0.1;
}

function getPendingCombinedAnnouncements() {
  if (!Array.isArray(state.pendingCombinedAnnouncements)) {
    state.pendingCombinedAnnouncements = [];
  }
  return state.pendingCombinedAnnouncements;
}

function queueCombinedDecisionAnnouncement({ type, school, passed, windowKey, appliedTerm = 0 }) {
  if (!school?.id || !type || !windowKey) return;
  const queue = getPendingCombinedAnnouncements();
  const existingIndex = queue.findIndex((item) => item && item.type === type && item.schoolId === school.id && item.windowKey === windowKey && !item.announced);
  const payload = {
    type,
    schoolId: school.id,
    schoolName: school.name || "",
    roleId: `admissions-${school.id}`,
    passed: !!passed,
    windowKey,
    appliedTerm: Math.max(0, Number(appliedTerm || 0)),
    announced: false,
  };
  if (existingIndex >= 0) {
    queue.splice(existingIndex, 1, payload);
  } else {
    queue.push(payload);
  }
}

function isCombinedAnnouncementDue(entry) {
  if (!entry || entry.announced) return false;
  const windowKey = String(entry.windowKey || "");
  const appliedTerm = Math.max(0, Number(entry.appliedTerm || 0));
  if (windowKey === "pre_undergrad") {
    return !!state.undergradStarted || !!state.undergradGraduated;
  }
  if (windowKey === "late_undergrad") {
    if (state.undergradGraduated) return true;
    if (!state.undergradStarted) return false;
    return getHigherEdCurrentTermNumber("undergrad") > appliedTerm;
  }
  if (windowKey === "pre_masters") {
    return !!state.mastersStarted || !!state.mastersGraduated;
  }
  if (windowKey === "late_masters") {
    if (state.mastersGraduated) return true;
    if (!state.mastersStarted) return false;
    return getHigherEdCurrentTermNumber("masters") > appliedTerm;
  }
  return false;
}

function buildCombinedAnnouncementMessage(entry) {
  const schoolName = entry.schoolName || "当前学校";
  if (entry.type === "bsms") {
    return entry.passed
      ? `${schoolName} 已自动公布连读结果：你通过了本硕连读预审。后续在本科毕业选择去向时，可直接选择直入硕士。`
      : `${schoolName} 已自动公布连读结果：你本轮未通过本硕连读预审，后续仍可按常规硕士申请推进。`;
  }
  if (entry.type === "bsmsphd") {
    return entry.passed
      ? `${schoolName} 已自动公布连读结果：你通过了本硕博连读预审。后续在本科毕业时可选择直入连读通道。`
      : `${schoolName} 已自动公布连读结果：你本轮未通过本硕博连读预审，后续仍可按常规硕士/博士路径推进。`;
  }
  return entry.passed
    ? `${schoolName} 已自动公布连读结果：你通过了硕博连读评估。后续在硕士毕业时可直接进入博士阶段。`
    : `${schoolName} 已自动公布连读结果：你本轮未通过硕博连读评估，后续仍可按常规申博推进。`;
}

function flushPendingCombinedAnnouncements() {
  const queue = getPendingCombinedAnnouncements();
  if (!queue.length) return;
  let changed = false;
  queue.forEach((entry) => {
    if (!isCombinedAnnouncementDue(entry)) return;
    const message = buildCombinedAnnouncementMessage(entry);
    addChatMessage("ai", message, { targetRole: entry.roleId || `admissions-${entry.schoolId}` });
    state.log.unshift(message);
    entry.announced = true;
    changed = true;
  });
  if (changed) {
    state.pendingCombinedAnnouncements = queue.filter((entry) => entry && !entry.announced);
  }
}

function getAdmissionsQuickActions(roleId, school) {
  if (!isAdmissionsRole(roleId) || !school) return [];
  const actions = [];
  const ugResult = getAdmissionsUndergradResult(school.id);
  const gradResult = getAdmissionsGradResult(school.id);
  const undergradWindowKey = getUndergradCombinedWindowKey(school.id);
  const mastersWindowKey = getMastersCombinedWindowKey(school.id);
  const showCombinedWindow =
    ugResult &&
    ugResult.status === "录取" &&
    state.finalChoice === school.id &&
    !state.mastersStarted &&
    !state.phdStarted;
  if (
    showCombinedWindow &&
    canApplyCombinedDegreeForSchool(school, ugResult) &&
    hasUnusedCombinedWindow(state.combinedDegreeLastWindow, undergradWindowKey, state.combinedDegreeApproved)
  ) {
    actions.push({
      id: `apply-bsms-${school.id}`,
      label: "申请本硕连读",
      desc: "自动提交连读预审申请",
      prompt: "申请本硕连读",
    });
  }
  if (
    showCombinedWindow &&
    hasUnusedCombinedWindow(state.directPhdLastWindow, undergradWindowKey, state.directPhdApproved) &&
    canApplyCombinedDoctoralForSchool(school, ugResult)
  ) {
    actions.push({
      id: `apply-bsmsphd-${school.id}`,
      label: "申请本硕博连读",
      desc: "自动提交本硕博贯通预审",
      prompt: "申请本硕博连读",
    });
  }
  if (
    canApplyMsPhdForSchool(school, gradResult) &&
    hasUnusedCombinedWindow(state.msPhdLastWindow, mastersWindowKey, state.msPhdApproved)
  ) {
    actions.push({
      id: `apply-msphd-${school.id}`,
      label: "申请硕博连读",
      desc: "自动提交硕博连读评估",
      prompt: "申请硕博连读",
    });
  }
  return actions;
}

function queueAdmissionsCombinedPrompt(schoolId) {
  if (!schoolId) return;
  const roleId = `admissions-${schoolId}`;
  const session = getAdmissionsDialogueSession(roleId);
  if (!session) return;
  session.combinedPromptPending = true;
}

function triggerPendingAdmissionsCombinedPrompt() {
  if (!state.started || state.termIndex !== 7) return;
  const store = getAdmissionsDialogueStore();
  if (!store) return;
  const pendingRoleId = Object.keys(store).find((roleId) => store[roleId]?.combinedPromptPending);
  if (!pendingRoleId) return;
  const school = getAdmissionsSchoolByRole(pendingRoleId);
  const session = store[pendingRoleId];
  if (!school || !session) return;
  const actions = getAdmissionsQuickActions(pendingRoleId, school);
  session.combinedPromptPending = false;
  if (chatRole && Array.from(chatRole.options || []).some((option) => option.value === pendingRoleId)) {
    chatRole.value = pendingRoleId;
    ensureChatRoleState(pendingRoleId);
  }
  if (!session.combinedPromptShown) {
    const content = actions.length
      ? `你已被录取。当前窗口已开放连读申请，可直接点击：${actions.map((action) => action.label).join(" / ")}。`
      : "你已被录取。你可以在本窗口咨询连读申请条件；满足规则的开放窗口会自动出现申请按钮。";
    addChatMessage("ai", content, {
      targetRole: pendingRoleId,
    });
    session.combinedPromptShown = true;
  }
  updateChatControls();
}

function renderChatActionPanel(actions = []) {
  if (!chatActionPanel) return;
  if (!actions.length) {
    chatActionPanel.innerHTML = "";
    chatActionPanel.classList.remove("visible");
    chatActionPanel.classList.add("hidden");
    return;
  }
  chatActionPanel.innerHTML = "";
  actions.forEach((action) => {
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "chat-action-btn";
    btn.dataset.chatActionPrompt = action.prompt;
    btn.innerHTML = `<strong>${action.label}</strong><small>${action.desc || ""}</small>`;
    chatActionPanel.appendChild(btn);
  });
  chatActionPanel.classList.remove("hidden");
  chatActionPanel.classList.add("visible");
}

function normalizeChatAiSettings(input) {
  const source = input && typeof input === "object" ? input : {};
  const allowDeveloperConfig = CHAT_PUBLIC_RELEASE && !!state?.devMode;
  const mode =
    CHAT_PUBLIC_RELEASE && !allowDeveloperConfig
      ? "mimo"
      : CHAT_AI_ALLOWED_MODES.has(source.mode)
        ? source.mode
        : CHAT_AI_DEFAULTS.mode;
  const rawModel = typeof source.model === "string" ? source.model : CHAT_AI_DEFAULTS.model;
  const normalizedRawModel = rawModel.trim();
  const modelRaw =
    normalizedRawModel === "mimo-1" || normalizedRawModel === "mimo-v2.5-pro"
      ? CHAT_AI_DEFAULTS.model
      : normalizedRawModel;
  const baseRaw = typeof source.baseUrl === "string" ? source.baseUrl : CHAT_AI_DEFAULTS.baseUrl;
  const keyRaw = typeof source.apiKey === "string" ? source.apiKey : CHAT_AI_DEFAULTS.apiKey;
  return {
    mode,
    model: modelRaw.trim() || CHAT_AI_DEFAULTS.model,
    baseUrl: baseRaw.trim() || CHAT_AI_DEFAULTS.baseUrl,
    apiKey: CHAT_PUBLIC_RELEASE && !allowDeveloperConfig ? "" : keyRaw.trim(),
  };
}

function getEffectiveChatAiApiKey(inputKey = "") {
  const explicitKey = String(inputKey || "").trim();
  if (explicitKey) return explicitKey;
  const sessionKey = String(chatAiSettings?.apiKey || "").trim();
  if (sessionKey) return sessionKey;
  return CHAT_AI_AUTO_KEY;
}

function saveChatAiSettings() {
  try {
    const payload =
      CHAT_PUBLIC_RELEASE
        ? {
            mode: state?.devMode ? chatAiSettings.mode : "mimo",
            model: chatAiSettings.model,
            baseUrl: chatAiSettings.baseUrl,
            apiKey: "",
          }
        : chatAiSettings;
    localStorage.setItem(CHAT_AI_SETTINGS_STORAGE_KEY, JSON.stringify(payload));
  } catch (error) {
    // ignore storage failures (private mode / quota)
  }
}

function loadChatAiSettings() {
  try {
    const raw = localStorage.getItem(CHAT_AI_SETTINGS_STORAGE_KEY);
    if (!raw) {
      chatAiSettings = normalizeChatAiSettings(CHAT_AI_DEFAULTS);
      return;
    }
    const parsed = JSON.parse(raw);
    chatAiSettings = normalizeChatAiSettings(parsed);
  } catch (error) {
    chatAiSettings = normalizeChatAiSettings(CHAT_AI_DEFAULTS);
  }
}

function renderChatAiSettings() {
  if (chatAiMode) chatAiMode.value = chatAiSettings.mode;
  if (chatAiModel) chatAiModel.value = chatAiSettings.model;
  if (chatAiBaseUrl) chatAiBaseUrl.value = chatAiSettings.baseUrl;
  if (chatAiKey) chatAiKey.value = chatAiSettings.apiKey;
}

function applyChatAiUiMode() {
  const allowDeveloperConfig = CHAT_PUBLIC_RELEASE && !!state?.devMode;
  const showSettings = CHAT_AI_SHOW_SETTINGS || allowDeveloperConfig;
  if (chatAiPanelTitle) {
    chatAiPanelTitle.textContent = CHAT_PUBLIC_RELEASE ? (allowDeveloperConfig ? "开发者 AI 设置" : "AI 驱动") : "AI 设置";
  }
  if (chatAiPanelTag) {
    chatAiPanelTag.textContent = CHAT_PUBLIC_RELEASE ? (allowDeveloperConfig ? "开发者模式" : "公开版") : "本地保存";
  }
  if (chatAiConfigControls) {
    chatAiConfigControls.classList.toggle("hidden", !showSettings);
  }
  if (chatAiPublicNote) {
    chatAiPublicNote.classList.toggle("hidden", showSettings);
    if (CHAT_PUBLIC_RELEASE && allowDeveloperConfig) {
      chatAiPublicNote.textContent = "开发者模式下可临时填写你自己的 API Key；留空则自动沿用内置 AI。你的自定义 Key 仅本次会话使用，不会保存到公开版。";
    } else {
      chatAiPublicNote.textContent = "公开版默认由内置 AI 驱动；包含静态文件打开方式。若服务暂不可用，会自动切换为离线规则。";
    }
  }
  if (chatAiPanel) {
    chatAiPanel.classList.toggle("public-mode", CHAT_PUBLIC_RELEASE);
  }
  renderChatAiSettings();
  refreshChatAiStatus();
}

function setChatAiStatus(message) {
  if (!chatAiStatus) return;
  chatAiStatus.textContent = message;
}

function refreshChatAiStatus() {
  const allowDeveloperConfig = CHAT_PUBLIC_RELEASE && !!state?.devMode;
  if (CHAT_PUBLIC_RELEASE && !allowDeveloperConfig && chatAiSettings.mode === "mimo") {
    setChatAiStatus(`公开版默认使用内置 AI：${chatAiSettings.model} · 任意打开方式可用 · 异常时自动切离线`);
    return;
  }
  if (chatAiSettings.mode !== "mimo") {
    setChatAiStatus("当前使用离线规则引擎。");
    return;
  }
  const keyState = chatAiSettings.apiKey ? "已自动配置 API Key" : "未配置 API Key";
  if (CHAT_PUBLIC_RELEASE && allowDeveloperConfig) {
    const userKeyState = chatAiSettings.apiKey
      ? "已填写你的 API Key（仅本次）"
      : "未填写你的 API Key（将自动使用内置 API）";
    setChatAiStatus(`开发者模式：${chatAiSettings.model} · ${userKeyState}`);
    return;
  }
  setChatAiStatus(`当前使用 MiMo：${chatAiSettings.model} · ${keyState}`);
}

function isStaticFileMode() {
  return typeof window !== "undefined" && String(window.location?.protocol || "") === "file:";
}

function getStaticModeLaunchCommand() {
  if (typeof window === "undefined") return "npm start";
  const rawPath = decodeURIComponent(String(window.location?.pathname || ""));
  const projectDir = rawPath.replace(/\/[^/]*$/, "") || ".";
  return `cd "${projectDir}" && npm start`;
}

function renderFileModeBanner() {
  if (!fileModeBanner) return;
  const show = CHAT_PUBLIC_RELEASE && isStaticFileMode() && !fileModeBannerDismissed && !canUseDirectChatRoute();
  fileModeBanner.classList.toggle("hidden", !show);
  if (!show) return;
  if (fileModeCommand) {
    fileModeCommand.textContent = getStaticModeLaunchCommand();
  }
  if (fileModeBannerText) {
    fileModeBannerText.textContent =
      state.devMode
        ? "当前通过 file:// 打开。公开版内置 AI 无法直接调用；你可以在开发者模式里填写自己的 API Key，或改用本地服务 / 线上版测试内置 AI。"
        : "当前通过 file:// 打开。公开版内置 AI 会自动切换为离线规则；如需测试内置 AI，请改用本地服务或线上发布地址打开。";
  }
}

