function normalizeText(input) {
  return input.toLowerCase().replace(/[^a-z0-9\u4e00-\u9fa5]/g, "");
}

function findSchoolByText(text) {
  const content = normalizeText(text);
  const aliases = {
    mit: "mit",
    harvard: "harvard",
    stanford: "stanford",
    ucla: "ucla",
    berkeley: "ucberkeley",
    oxford: "oxford",
    cambridge: "cambridge",
    nus: "nus",
    ntu: "ntu",
  };
  for (const [key, id] of Object.entries(aliases)) {
    if (content.includes(key)) return UNIVERSITIES.find((u) => u.id === id);
  }
  return UNIVERSITIES.find((school) => content.includes(normalizeText(school.name)));
}

function findSchoolsByText(text, limit = 2) {
  const content = normalizeText(text);
  const aliases = {
    mit: "mit",
    harvard: "harvard",
    stanford: "stanford",
    ucla: "ucla",
    berkeley: "ucberkeley",
    oxford: "oxford",
    cambridge: "cambridge",
    nus: "nus",
    ntu: "ntu",
    sydney: "sydney",
  };
  const picked = [];
  const used = new Set();
  Object.entries(aliases).forEach(([key, id]) => {
    if (picked.length >= limit) return;
    if (!content.includes(key) || used.has(id)) return;
    const school = UNIVERSITIES.find((item) => item.id === id);
    if (school) {
      picked.push(school);
      used.add(id);
    }
  });
  UNIVERSITIES.forEach((school) => {
    if (picked.length >= limit) return;
    if (used.has(school.id)) return;
    if (!content.includes(normalizeText(school.name))) return;
    picked.push(school);
    used.add(school.id);
  });
  return picked;
}

function buildExecutionChecklist(limit = 3) {
  const steps = [];
  if (state.termIndex <= 5) {
    const recommendation = getCounselorEventRecommendation();
    if (recommendation.picks?.length) {
      steps.push(`按中介建议先做：${recommendation.picks[0].title}`);
    }
    const mini = getMiniActionSuggestions(1);
    if (mini.length) steps.push(`补一个小行动：${mini[0]}`);
    if (state.cash < 4000) steps.push("预算偏紧，优先低成本项目或考虑一次贷款。");
    if ((state.stats.stress ?? 0) > 78) steps.push("先降压力再冲刺，避免过劳债务累积。");
  } else if (state.termIndex === 6) {
    const stage = getApplicationStage();
    if (!state.essayChoices.length) steps.push("先确定文书主题（最多 2 个）。");
    if (!state.recChoice) steps.push("确定推荐人策略并补强推荐关系。");
    if (stage === APPLICATION_STAGES.ED_APPLY) {
      if (state.selectedSchools.size !== 1) steps.push("ED 阶段先锁定 1 所最匹配学校。");
    } else if (state.selectedSchools.size < 3) {
      steps.push("RD 阶段建议至少 3 所，保证保底/匹配/冲刺结构。");
    }
  } else {
    if (state.results.some((item) => item.status === "候补") && !state.waitlistUpdated) {
      steps.push("先更新候补结果，再决定是否申诉。");
    }
    if (!state.finalChoice && state.results.some((item) => item.status === "录取")) {
      steps.push("从录取学校中尽快确定最终去向。");
    }
    if (state.finalChoice) {
      steps.push("完成录取后行动（签证/住宿/奖助谈判）以降低落地风险。");
      if (!state.undergradStarted) {
        steps.push("可启动本科四年模拟，提前规划毕业去向。");
      } else if (state.undergradGraduated && !state.mastersStarted && !state.phdStarted && !state.postGradPath) {
        steps.push("本科已毕业，先选择硕士申请或直接就业（博士路径需先完成硕士）。");
      }
      if (state.mastersStarted && !state.mastersGraduated) {
        steps.push("硕士进行中：优先提高论文进度与研究强度。");
      }
      if (state.mastersGraduated && !state.phdStarted && state.postGradPath !== POSTGRAD_PATHS.JOB) {
        steps.push("硕士毕业后可申博；若走硕博连读可直接启动博士阶段。");
      }
      if (state.phdStarted && !state.phdGraduated) {
        steps.push("博士进行中：保持每学期研究与发表产出。");
      }
      if (state.phdGraduated && !state.jobOutcome) {
        steps.push("博士已毕业：立即选择公司并提交求职投递。");
      }
      if (state.jobOutcome && Array.isArray(state.jobOutcome.applications)) {
        const waiting = state.jobOutcome.applications.filter((item) => item.status === "面试中").length;
        if (waiting > 0) {
          steps.push(`还有 ${waiting} 家待面试：到交流室切换对应公司面试官完成问答评估。`);
        }
      }
    }
  }
  if (!steps.length) steps.push("保持当前节奏，重点追踪短板补强。");
  return Array.from(new Set(steps)).slice(0, limit);
}

function compareSchoolsForReply(schoolA, schoolB) {
  if (!schoolA || !schoolB) return "";
  const eva = evaluateApplication(schoolA, { preview: true });
  const evb = evaluateApplication(schoolB, { preview: true });
  const tierA = getSchoolTierByChance(eva.chance).label;
  const tierB = getSchoolTierByChance(evb.chance).label;
  const aidA = calculateAidOffer(schoolA, getRoundChoiceForSchool(schoolA.id));
  const aidB = calculateAidOffer(schoolB, getRoundChoiceForSchool(schoolB.id));
  const fitA = Math.round(eva.fitScore * 100);
  const fitB = Math.round(evb.fitScore * 100);
  const chanceA = Math.round(eva.chance * 100);
  const chanceB = Math.round(evb.chance * 100);
  return `${schoolA.name}（${tierA}，匹配 ${fitA}，机会 ${chanceA}% ，净费用约 ${formatUsd(
    aidA.netCost,
  )}/年） vs ${schoolB.name}（${tierB}，匹配 ${fitB}，机会 ${chanceB}% ，净费用约 ${formatUsd(
    aidB.netCost,
  )}/年）。`;
}

function adjustRelationship(roleId, text) {
  ensureChatRoleState(roleId);
  const polite = ["谢谢", "感谢", "麻烦", "请"];
  const harsh = ["不行", "太烂", "烦", "讨厌", "没用"];
  let delta = 0;
  if (polite.some((w) => text.includes(w))) delta += 2;
  if (harsh.some((w) => text.includes(w))) delta -= 2;
  state.chatRelationships[roleId] = clamp((state.chatRelationships[roleId] || 50) + delta, 0, 100);
}

function upsertMemoryNoteByPrefix(memory, prefix, value) {
  if (!Array.isArray(memory) || !prefix) return;
  for (let i = memory.length - 1; i >= 0; i -= 1) {
    if (String(memory[i] || "").startsWith(prefix)) {
      memory.splice(i, 1);
    }
  }
  if (value) {
    memory.push(`${prefix}${value}`);
  }
}

function extractPreferenceNotes(intent, text, roleId) {
  const notes = [];
  const content = String(text || "").toLowerCase();
  if (
    intent.finance ||
    /没钱|预算|花费|成本|贵|省钱|学费|生活费|资金/.test(content)
  ) {
    notes.push(["pref:budget:", "tight"]);
  }
  if (
    intent.stress ||
    /压力|焦虑|崩|累|休息|睡眠|透支|过劳/.test(content)
  ) {
    notes.push(["pref:stress:", "control"]);
  }
  if (
    intent.school &&
    /藤校|top|qs前|名校|冲刺|梦校/.test(content)
  ) {
    notes.push(["pref:schoolTier:", "elite"]);
  }
  if (
    intent.school &&
    /保底|稳|平衡|匹配|风险/.test(content)
  ) {
    notes.push(["pref:schoolTier:", "balanced"]);
  }
  if (intent.aid || /奖学金|全奖|资助|need|merit/.test(content)) {
    notes.push(["pref:aid:", "priority"]);
  }
  if (
    intent.project &&
    /科研|论文|实验|导师|发表|课题/.test(content)
  ) {
    notes.push(["pref:path:", "research"]);
  }
  if (
    intent.project &&
    /实习|就业|公司|岗位|面试|薪资/.test(content)
  ) {
    notes.push(["pref:path:", "career"]);
  }
  if (
    intent.appeal ||
    /申诉|复议|重新考虑|补充材料/.test(content)
  ) {
    notes.push(["pref:appeal:", "active"]);
  }
  if (intent.major && state.majorId) {
    notes.push(["pref:major:", getMajorName(state.majorId)]);
  }
  if ((roleId === "counselor" || roleId === "peer" || isAdmissionsRole(roleId)) && intent.school) {
    const school = findSchoolByText(text);
    if (school) {
      notes.push(["pref:targetSchool:", school.name]);
    }
  }
  return notes;
}

function updateChatMemory(roleId, text) {
  ensureChatRoleState(roleId);
  const memory = state.chatMemory[roleId] || [];
  const intent = detectIntent(text);
  updateRoleMemoryCard(roleId, intent, text);
  const notes = [];
  const allowSchool = roleId === "counselor" || roleId === "peer" || isAdmissionsRole(roleId);
  if (intent.school) notes.push("topic:school");
  if (intent.finance) notes.push("topic:finance");
  if (intent.essay) notes.push("topic:essay");
  if (intent.stress) notes.push("topic:stress");
  if (intent.results) notes.push("topic:results");
  if (intent.project) notes.push("topic:project");
  if (intent.round) notes.push("topic:round");
  if (intent.test) notes.push("topic:test");
  if (intent.gapYear) notes.push("topic:gap");
  if (intent.loan) notes.push("topic:loan");
  if (intent.aid) notes.push("topic:aid");
  if (intent.compare) notes.push("topic:compare");
  if (intent.checklist) notes.push("topic:checklist");
  if (intent.postAdmit) notes.push("topic:postadmit");
  if (intent.combinedProgram) notes.push("topic:combined");
  if (intent.interview) notes.push("topic:interview");
  if (intent.incident) notes.push("topic:incident");
  if (intent.appeal) notes.push("topic:appeal");
  if (intent.stageProgress) notes.push("topic:progress");
  if (intent.graduate) notes.push("topic:graduate");
  if (intent.career) notes.push("topic:career");
  const school = findSchoolByText(text);
  if (allowSchool && school) notes.push(`school:${school.name}`);

  extractPreferenceNotes(intent, text, roleId).forEach(([prefix, value]) => {
    upsertMemoryNoteByPrefix(memory, prefix, value);
  });

  notes.forEach((note) => {
    if (!memory.includes(note)) memory.push(note);
  });
  const memoryLimit = getMemoryLimitForRole(roleId);
  state.chatMemory[roleId] = memory.slice(-memoryLimit);
}

function getMemoryLine(roleId) {
  const memory = state.chatMemory[roleId] || [];
  if (!memory.length) return "";
  const isPreference = (note) => String(note || "").startsWith("pref:");
  const allowed = (note) => {
    if (isPreference(note)) return true;
    if (roleId === "family") {
      return (
        note.includes("topic:stress") ||
        note.includes("topic:finance") ||
        note.includes("topic:results") ||
        note.includes("topic:gap") ||
        note.includes("topic:loan") ||
        note.includes("topic:postadmit") ||
        note.includes("topic:checklist") ||
        note.includes("topic:progress") ||
        note.includes("topic:career")
      );
    }
    if (roleId === "peer") {
      return (
        note.includes("topic:school") ||
        note.includes("topic:results") ||
        note.includes("topic:project") ||
        note.includes("topic:test") ||
        note.includes("topic:compare") ||
        note.includes("topic:checklist") ||
        note.includes("topic:career") ||
        note.includes("topic:graduate") ||
        note.startsWith("school:")
      );
    }
    if (isAdmissionsRole(roleId)) {
      return (
        note.includes("topic:results") ||
        note.includes("topic:school") ||
        note.includes("topic:combined") ||
        note.includes("topic:postadmit") ||
        note.startsWith("school:")
      );
    }
    return true;
  };
  const labelFor = (note) => {
    if (note.startsWith("school:")) return `关注 ${note.replace("school:", "")}`;
    if (note === "pref:budget:tight") return "预算优先";
    if (note === "pref:stress:control") return "控压优先";
    if (note === "pref:schoolTier:elite") return "目标偏冲刺";
    if (note === "pref:schoolTier:balanced") return "目标偏平衡";
    if (note === "pref:aid:priority") return "重视奖助";
    if (note === "pref:path:research") return "偏研究路线";
    if (note === "pref:path:career") return "偏就业路线";
    if (note === "pref:appeal:active") return "重视申诉机会";
    if (note.startsWith("pref:major:")) return `关注专业 ${note.replace("pref:major:", "")}`;
    if (note.startsWith("pref:targetSchool:")) return `目标 ${note.replace("pref:targetSchool:", "")}`;
    if (note === "topic:school") return "选校";
    if (note === "topic:finance") return "预算";
    if (note === "topic:essay") return "文书";
    if (note === "topic:stress") return "压力";
    if (note === "topic:results") return "结果";
    if (note === "topic:project") return "项目";
    if (note === "topic:round") return "轮次";
    if (note === "topic:test") return "标化";
    if (note === "topic:gap") return "再读一年";
    if (note === "topic:loan") return "贷款";
    if (note === "topic:aid") return "奖助";
    if (note === "topic:compare") return "学校对比";
    if (note === "topic:checklist") return "执行清单";
    if (note === "topic:postadmit") return "录取后准备";
    if (note === "topic:combined") return "连读申请";
    if (note === "topic:interview") return "面试";
    if (note === "topic:incident") return "意外事件";
    if (note === "topic:appeal") return "申诉";
    if (note === "topic:progress") return "阶段进度";
    if (note === "topic:graduate") return "研究生路径";
    if (note === "topic:career") return "就业路径";
    return note;
  };
  const filtered = memory.filter(allowed);
  const preferenceItems = filtered.filter(isPreference).slice(-1).map(labelFor);
  const topicItems = filtered.filter((note) => !isPreference(note)).slice(-1).map(labelFor);
  const items = [...topicItems, ...preferenceItems].filter(Boolean).slice(-2);
  if (!items.length) return "";
  const prefix = isAdmissionsRole(roleId) ? "你提过" : roleId === "peer" ? "你之前说过" : "我记得你提过";
  return `${prefix}${items.join("、")}。`;
}

function getWeaknessSummary() {
  const entries = [
    ["学术", (state.stats.gpa - 2) / 2],
    ["标化", (state.stats.test - 800) / 800],
    ["活动", state.stats.activities / 100],
    ["领导力", state.stats.leadership / 100],
    ["文书", state.stats.essay / 100],
    ["推荐", (state.stats.recStrength ?? 0) / 100],
    ["社会评价", (state.stats.reputation ?? 0) / 100],
  ];
  return entries.sort((a, b) => a[1] - b[1]).slice(0, 2).map((item) => item[0]);
}

function getStrengthSummary() {
  const entries = [
    ["学术", (state.stats.gpa - 2) / 2],
    ["标化", (state.stats.test - 800) / 800],
    ["活动", state.stats.activities / 100],
    ["领导力", state.stats.leadership / 100],
    ["文书", state.stats.essay / 100],
    ["社会评价", (state.stats.reputation ?? 0) / 100],
  ];
  return entries.sort((a, b) => b[1] - a[1]).slice(0, 2).map((item) => item[0]);
}

function buildSchoolSuggestions() {
  if (!state.started || !state.essayChoices.length || !state.recChoice) {
    return "先确定文书主题与推荐人，我再给更准的选校建议。";
  }
  const stage = getApplicationStage();
  const thresholds = getTierThresholds();
  const scored = UNIVERSITIES.map((school) => ({
    school,
    chance: calculateChance(school, { preview: true }),
  })).sort((a, b) => b.chance - a.chance);
  if (stage === APPLICATION_STAGES.ED_APPLY) {
    const top = scored[0];
    if (!top) return "当前没有可推荐学校。";
    const tier = getSchoolTierByChance(top.chance).label;
    return `ED 建议优先：${top.school.name}（${tier}，命中率约 ${Math.round(top.chance * 100)}%）。`;
  }
  const safety = scored.filter((s) => s.chance >= thresholds.safety).slice(0, 2);
  const match = scored
    .filter((s) => s.chance >= thresholds.match && s.chance < thresholds.safety)
    .slice(0, 2);
  const reach = scored.filter((s) => s.chance < thresholds.match).slice(0, 2);
  const list = (arr) => arr.map((s) => s.school.name).join(" / ") || "暂无";
  return `选校建议：保底 ${list(safety)}；匹配 ${list(match)}；冲刺 ${list(reach)}。`;
}

function pickVariant(list, key) {
  if (!list || !list.length) return "";
  const store = state.chatContext?.lastPick || {};
  const lastIndex = store[key];
  let index = Math.floor(Math.random() * list.length);
  if (list.length > 1 && index === lastIndex) {
    index = (index + 1) % list.length;
  }
  store[key] = index;
  state.chatContext.lastPick = store;
  return list[index];
}

function maybeIncludeMemory(roleId) {
  const memoryLine = getMemoryLine(roleId);
  if (!memoryLine) return "";
  const relationship = state.chatRelationships[roleId] ?? 50;
  const base = roleId === "family" || roleId === "peer" ? 0.28 : 0.35;
  const chance = clamp(base + (relationship - 50) / 100, 0.18, 0.7);
  return Math.random() < chance ? memoryLine : "";
}

function getRoleDialogueState(roleId) {
  if (!state.chatContext.roleState) {
    state.chatContext.roleState = {};
  }
  if (!state.chatContext.roleState[roleId]) {
    state.chatContext.roleState[roleId] = {
      turns: 0,
      lastIntent: null,
      mode: "general",
      goal: "维持沟通",
      pendingTask: null,
      urgency: "mid",
      lastAdvice: "",
    };
  }
  return state.chatContext.roleState[roleId];
}

function getAdmissionsDialogueStore() {
  if (!state.chatContext || typeof state.chatContext !== "object") return null;
  if (!state.chatContext.admissionsSessions || typeof state.chatContext.admissionsSessions !== "object") {
    state.chatContext.admissionsSessions = {};
  }
  return state.chatContext.admissionsSessions;
}

function getAdmissionsDialogueSession(roleId) {
  if (!isAdmissionsRole(roleId)) return null;
  const store = getAdmissionsDialogueStore();
  if (!store) return null;
  if (!store[roleId] || typeof store[roleId] !== "object") {
    store[roleId] = {
      pendingQuestion: "",
      topic: "general",
      turn: 0,
      lastAskedAt: 0,
      lastQuality: 0,
    };
  }
  return store[roleId];
}

function clearAdmissionsDialogueSession(roleId) {
  const session = getAdmissionsDialogueSession(roleId);
  if (!session) return;
  session.pendingQuestion = "";
  session.turn = 0;
  session.lastAskedAt = 0;
}

function setAdmissionsPendingQuestion(roleId, question, topic = "general", turn = 1) {
  const session = getAdmissionsDialogueSession(roleId);
  if (!session) return;
  session.pendingQuestion = question || "";
  session.topic = topic || "general";
  session.turn = Math.max(1, Number(turn) || 1);
  session.lastAskedAt = Date.now();
}

function looksLikeExplicitQuestion(text = "") {
  return /[?？]|为什么|怎么|请问|能否|what|why|how|can/i.test(text);
}

function inferAdmissionsFollowupTopic(intent, userText = "") {
  if (intent.appeal || /申诉|复议|补充材料|更新/.test(userText)) return "update";
  if (intent.results) return "update";
  if (intent.finance || intent.loan || intent.aid) return "finance";
  if (intent.project || intent.incident) return "project";
  if (intent.major || intent.school || intent.graduate || intent.stageProgress) return "fit";
  return "motivation";
}

function buildAdmissionsFollowupQuestion(school, topic = "general", refine = false) {
  const schoolName = school?.name || "该校";
  const poolByTopic = {
    fit: [
      `请具体说一下你最近一段经历如何匹配 ${schoolName} 的培养方向？`,
      `如果只能补充一个“专业匹配”证据，你会提交哪一项？`,
      `你打算在入学后的前两学期重点推进什么学术方向？`,
    ],
    update: [
      `若本轮允许补充更新，你最想补哪条“新增成果”？`,
      `你最近有可量化的新进展吗？建议给出一项最强更新。`,
      `如果要提交一封补充说明，你会突出哪两个核心变化？`,
    ],
    finance: [
      `你对净费用的可接受区间大概是多少？`,
      `你更看重奖助覆盖比例，还是项目匹配度？`,
      `如果需要在预算和排名间取舍，你会怎么选？`,
    ],
    project: [
      "最近哪项项目能最直接体现你的执行力和持续投入？",
      "如果本学期再补一项经历，你会优先补科研、实习还是领导力？",
      "你打算如何把现有项目讲成一条连续成长主线？",
    ],
    motivation: [
      `你申请 ${schoolName} 的核心动机是什么？`,
      "你希望通过这个项目解决什么长期目标？",
      "如果被录取，你最想加入哪类课程或研究组？",
    ],
    general: [
      "你最希望我们优先理解你哪一部分优势？",
      "如果只能补充一句话，你想强调什么？",
      "你最担心评审忽略你哪项信息？",
    ],
  };
  const key = poolByTopic[topic] ? topic : "general";
  const list = poolByTopic[key];
  if (!list?.length) return "";
  const picked = pickVariant(list, `admissions-followup-${school?.id || "school"}-${key}-${refine ? "r" : "p"}`);
  if (!refine) return picked;
  const refinePrefix = pickVariant(
    ["我再追问一个更具体的点：", "我继续补一个细节问题：", "我们把这个点再细化一下："],
    `admissions-followup-prefix-${school?.id || "school"}-${key}`,
  );
  return `${refinePrefix}${picked}`;
}

function evaluateAdmissionsAnswerQuality(text = "", topic = "general") {
  const normalized = (text || "").trim().toLowerCase();
  if (!normalized) {
    return { score: 10, label: "信息不足", tip: "建议给出具体项目、结果和量化变化。" };
  }
  const keywordMap = {
    fit: ["项目", "课程", "研究", "实习", "匹配", "专业", "方向", "成果", "导师"],
    update: ["新增", "更新", "成绩", "奖项", "论文", "推荐", "活动", "证明", "附件"],
    finance: ["预算", "费用", "资助", "奖学金", "贷款", "学费", "生活费", "金额"],
    project: ["负责", "推进", "结果", "影响", "改进", "复盘", "困难", "解决"],
    motivation: ["目标", "兴趣", "方向", "原因", "计划", "发展", "长期"],
    general: ["项目", "结果", "计划", "目标", "更新"],
  };
  const words = keywordMap[topic] || keywordMap.general;
  const matched = words.filter((word) => normalized.includes(word)).length;
  const lengthScore = clamp(normalized.length / 5, 0, 26);
  const keywordScore = Math.min(34, matched * 6);
  const numberBonus = /\d/.test(normalized) ? 10 : 0;
  const structureBonus = /(因为|所以|结果|因此|改进|复盘|例如)/.test(normalized) ? 10 : 0;
  let penalty = 0;
  if (normalized.length < 18) penalty += 10;
  if (/不知道|不清楚|没想好|随便/.test(normalized)) penalty += 20;
  const score = clamp(Math.round(30 + lengthScore + keywordScore + numberBonus + structureBonus - penalty), 5, 100);
  if (score >= 80) {
    return { score, label: "信息完整", tip: "信息已足够进入评估参考。" };
  }
  if (score >= 62) {
    return { score, label: "基本完整", tip: "建议再补一条可量化结果。"};
  }
  return { score, label: "细节不足", tip: "建议按“背景-行动-结果”补充并附量化信息。"};
}

function handleAdmissionsPendingFollowup(roleId, school, userText, intent) {
  const session = getAdmissionsDialogueSession(roleId);
  if (!session || !session.pendingQuestion) return null;
  const text = String(userText || "").trim();
  if (!text) return null;
  if (looksLikeExplicitQuestion(text)) {
    clearAdmissionsDialogueSession(roleId);
    return null;
  }
  if (isCombinedDegreeIntent(text) || isCombinedDoctoralIntent(text) || isMsPhdIntent(text) || isAppealIntent(text)) {
    clearAdmissionsDialogueSession(roleId);
    return null;
  }

  const evaluated = evaluateAdmissionsAnswerQuality(text, session.topic);
  session.lastQuality = evaluated.score;
  if ((session.turn || 1) < 2 && evaluated.score < 78) {
    const refineQuestion = buildAdmissionsFollowupQuestion(school, session.topic, true);
    setAdmissionsPendingQuestion(roleId, refineQuestion, session.topic, (session.turn || 1) + 1);
    return `已收到你的补充（完整度 ${evaluated.score}/100，${evaluated.label}）。${evaluated.tip} ${refineQuestion}`;
  }
  clearAdmissionsDialogueSession(roleId);
  return `已收到你的补充（完整度 ${evaluated.score}/100，${evaluated.label}）。这部分会纳入后续评估参考。`;
}

function maybeAttachAdmissionsFollowup(roleId, school, intent, replyText, userText = "") {
  if (!isAdmissionsRole(roleId) || !school) return replyText;
  const session = getAdmissionsDialogueSession(roleId);
  if (!session || session.pendingQuestion) return replyText;
  const text = String(replyText || "").trim();
  if (!text) return replyText;
  if (/[?？]$/.test(text)) return text;
  if (/请先|仅在|当前没有|不可用|无法|未开放|请先拆|已评估完成|已通过预审|本轮未通过/.test(text)) {
    return text;
  }
  const topic = inferAdmissionsFollowupTopic(intent, userText);
  const shouldAsk = intent.greet || intent.school || intent.major || intent.results || intent.appeal || Math.random() < 0.55;
  if (!shouldAsk) return text;
  const question = buildAdmissionsFollowupQuestion(school, topic, false);
  if (!question) return text;
  setAdmissionsPendingQuestion(roleId, question, topic, 1);
  return `${text} ${question}`;
}

function detectPrimaryIntentKey(intent) {
  const ordered = [
    "interview",
    "appeal",
    "incident",
    "results",
    "career",
    "graduate",
    "school",
    "compare",
    "finance",
    "loan",
    "aid",
    "essay",
    "project",
    "test",
    "stress",
    "checklist",
    "postAdmit",
    "combinedProgram",
    "stageProgress",
    "gapYear",
    "round",
    "major",
    "time",
    "donation",
  ];
  return ordered.find((key) => intent[key]) || "general";
}

function inferUrgencyFromState() {
  if (state.termIndex === 6) return "high";
  if (state.termIndex === 7) return "high";
  if ((state.stats.stress ?? 0) >= 80) return "high";
  if (state.cash <= 2000) return "high";
  return "mid";
}

function buildRolePendingTask(roleId, mode) {
  if (roleId === "counselor") {
    if (mode === "portfolio") {
      const structure = getSelectedSchoolStructureProfile();
      return structure.total
        ? `先把选校结构修到保底${Math.max(2, Math.round(structure.total * 0.2))}+匹配${Math.max(
            2,
            Math.round(structure.total * 0.25),
          )}。`
        : "先选学校，再做结构校准。";
    }
    if (mode === "essay") return "先补文书进度到 60+，再冲高位学校。";
    if (mode === "finance") return "先锁预算上限，再选高成本项目。";
    if (mode === "appeal") return "先补有效更新与附件，再发申诉信。";
    if (mode === "execution") return "按清单逐项完成，避免申请季堆任务。";
    if (mode === "support") return "先降压力，避免过劳惩罚。";
  }
  if (roleId === "family") {
    if (mode === "finance") return "先确认预算边界，再决定是否贷款。";
    if (mode === "results") return "先看候补更新，再决定申诉或再读一年。";
    return "先稳节奏，避免压力失控。";
  }
  if (roleId === "peer") {
    if (mode === "compare") return "先做两校对比，再决定冲刺名单。";
    if (mode === "execution") return "先完成一个高价值项目。";
    return "先把短板补到及格线以上。";
  }
  if (isInterviewerRole(roleId)) {
    return "按问题结构作答：场景 -> 行动 -> 结果 -> 复盘。";
  }
  if (isAdmissionsRole(roleId)) {
    if (mode === "combined") return "请提供连读申请意向与学术规划。";
    if (mode === "appeal") return "请提交具体新增成果与证明附件。";
    return "请围绕专业匹配与近期更新沟通。";
  }
  return null;
}

function advanceRoleDialogueState(roleId, intent, userText = "") {
  const roleState = getRoleDialogueState(roleId);
  if (typeof roleState.turns !== "number") roleState.turns = 0;
  if (!roleState.mode) roleState.mode = "general";
  if (!roleState.goal) roleState.goal = "保持沟通";
  roleState.turns += 1;
  const primaryIntent = detectPrimaryIntentKey(intent);
  roleState.lastIntent = primaryIntent;
  roleState.urgency = inferUrgencyFromState();

  if (roleId === "counselor") {
    if (intent.results || intent.donation || intent.appeal) roleState.mode = "appeal";
    else if (intent.combinedProgram) roleState.mode = "execution";
    else if (intent.school || intent.compare || intent.round) roleState.mode = "portfolio";
    else if (intent.finance || intent.loan || intent.aid) roleState.mode = "finance";
    else if (intent.essay) roleState.mode = "essay";
    else if (
      intent.project ||
      intent.test ||
      intent.checklist ||
      intent.planTerm ||
      intent.planEssay ||
      intent.career ||
      intent.graduate ||
      intent.stageProgress ||
      intent.incident
    ) {
      roleState.mode = "execution";
    } else if (intent.stress || intent.complaint) roleState.mode = "support";
    else roleState.mode = "general";
    roleState.goal =
      roleState.mode === "portfolio"
        ? "优化选校结构"
        : roleState.mode === "finance"
          ? "控制预算与风险"
          : roleState.mode === "appeal"
            ? "提升复议成功率"
            : roleState.mode === "essay"
              ? "增强文书竞争力"
              : roleState.mode === "execution"
                ? "推进可执行清单"
                : roleState.mode === "support"
                  ? "控制压力"
                  : "保持稳定推进";
  } else if (roleId === "family") {
    roleState.mode =
      intent.finance || intent.loan
        ? "finance"
        : intent.results || intent.appeal || intent.career || intent.stageProgress
          ? "results"
          : "support";
    roleState.goal = roleState.mode === "finance" ? "保障预算可控" : "稳住节奏与心态";
  } else if (roleId === "peer") {
    roleState.mode =
      intent.compare || intent.school
        ? "compare"
        : intent.checklist || intent.career || intent.graduate || intent.stageProgress
          ? "execution"
          : "social";
    roleState.goal = roleState.mode === "compare" ? "快速比较策略" : "同伴互助";
  } else if (isInterviewerRole(roleId)) {
    roleState.mode = "interview";
    roleState.goal = "完成结构化面试评估";
  } else if (isAdmissionsRole(roleId)) {
    if (isCombinedDegreeIntent(userText) || intent.combinedProgram) {
      roleState.mode = "combined";
      roleState.goal = "评估本硕连读申请";
    } else {
      roleState.mode = isAppealIntent(userText) || intent.appeal ? "appeal" : "review";
      roleState.goal = roleState.mode === "appeal" ? "复核补充材料" : "说明评审逻辑";
    }
  } else {
    roleState.mode = "general";
    roleState.goal = "保持沟通";
  }
  roleState.pendingTask = buildRolePendingTask(roleId, roleState.mode);
  return roleState;
}

function buildStatefulReplyPrefix(roleId, roleState) {
  if (!roleState) return "";
  if (roleId === "counselor") {
    const urgencyTag = roleState.urgency === "high" ? "高优先级" : "常规优先级";
    const counselor = COUNSELORS.find((item) => item.id === state.counselorId);
    const quality = formatQualityLabel(getCounselorQuality(counselor));
    return `当前模式：${roleState.mode}（${urgencyTag}） · 目标：${roleState.goal} · 建议质量：${quality}。`;
  }
  if (roleId === "family") {
    return `当前关注：${roleState.goal}。`;
  }
  if (roleId === "peer") {
    return `当前节奏：${roleState.mode === "compare" ? "对比决策" : "同步进度"}。`;
  }
  if (isInterviewerRole(roleId)) {
    return "当前流程：结构化面试问答评估。";
  }
  if (isAdmissionsRole(roleId)) {
    if (roleState.mode === "combined") return "当前流程：连读资格评估。";
    return `当前流程：${roleState.mode === "appeal" ? "复核补充材料" : "常规评审沟通"}。`;
  }
  return "";
}

function describeFitLevel(fitScore) {
  if (fitScore >= 0.78) return "高度匹配";
  if (fitScore >= 0.65) return "较匹配";
  if (fitScore >= 0.5) return "一般匹配";
  return "偏弱匹配";
}

function getTopWeakStats(limit = 2) {
  const pairs = [
    ["学术", (state.stats.gpa - 2) / 2],
    ["标化", (state.stats.test - 800) / 800],
    ["活动", state.stats.activities / 100],
    ["领导力", state.stats.leadership / 100],
    ["文书", state.stats.essay / 100],
    ["推荐", (state.stats.recStrength ?? 0) / 100],
    ["社会评价", (state.stats.reputation ?? 0) / 100],
  ];
  return pairs.sort((a, b) => a[1] - b[1]).slice(0, limit).map((item) => item[0]);
}

function getMiniActionSuggestions(limit = 2) {
  if (!MINI_ACTIONS?.length) return [];
  const needs = {
    test: (state.stats.test ?? 0) < 1350,
    english: (state.stats.english ?? 0) < 100,
    essayTrack: (state.stats.essayTrack ?? 0) < 45,
    recStrength: (state.stats.recStrength ?? 0) < 45,
    reputation: (state.stats.reputation ?? 0) < 45,
  };
  const scores = MINI_ACTIONS.map((action) => {
    let score = 0;
    if (needs.test && (action.effects?.test || 0) > 0) score += 2.2;
    if (needs.english && (action.effects?.english || 0) > 0) score += 2;
    if (needs.essayTrack && (action.effects?.essayTrack || 0) > 0) score += 2;
    if (needs.recStrength && (action.effects?.recStrength || 0) > 0) score += 2;
    if (needs.reputation && (action.effects?.reputation || 0) > 0) score += 1.5;
    if ((action.effects?.essay || 0) > 0 && state.stats.essay < 60) score += 1;
    if ((action.effects?.leadership || 0) > 0 && state.stats.leadership < 60) score += 1;
    score -= (action.cost || 0) / 500;
    return { action, score };
  })
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
    .map((item) => item.action.name);
  return scores;
}

function scoreMiniAction(action) {
  if (!action) return -999;
  const needs = {
    test: (state.stats.test ?? 0) < 1350,
    english: (state.stats.english ?? 0) < 100,
    essayTrack: (state.stats.essayTrack ?? 0) < 55,
    recStrength: (state.stats.recStrength ?? 0) < 55,
    reputation: (state.stats.reputation ?? 0) < 50,
  };
  let score = 0;
  if (needs.test && (action.effects?.test || 0) > 0) score += 2.3;
  if (needs.english && (action.effects?.english || 0) > 0) score += 2.1;
  if (needs.essayTrack && (action.effects?.essayTrack || 0) > 0) score += 2.2;
  if (needs.recStrength && (action.effects?.recStrength || 0) > 0) score += 2.2;
  if (needs.reputation && (action.effects?.reputation || 0) > 0) score += 1.6;
  if ((action.effects?.essay || 0) > 0 && state.stats.essay < 60) score += 1.2;
  if ((action.effects?.leadership || 0) > 0 && state.stats.leadership < 60) score += 1;
  score -= (action.cost || 0) / 400;
  return score;
}

function getAppActionSuggestions(limit = 2) {
  if (state.termIndex !== 6) return [];
  const available = APP_ACTIONS.filter((action) => !state.appActionsUsed.has(action.id));
  if (!available.length) return [];
  const scores = available
    .map((action) => {
      let score = 0;
      if ((action.effects?.essayTrack || 0) > 0 && (state.stats.essayTrack ?? 0) < 55) score += 2;
      if ((action.effects?.recStrength || 0) > 0 && (state.stats.recStrength ?? 0) < 55) score += 2;
      if ((action.effects?.test || 0) > 0 && state.stats.test < 1350) score += 1.5;
      score -= (action.cost || 0) / 3000;
      score -= (action.time || 0) / 3;
      return { action, score };
    })
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
    .map((item) => item.action.name);
  return scores;
}

function planTermWithAI() {
  if (!state.started || state.termIndex > 5) {
    return { ok: false, message: "当前阶段无法规划本学期。", picks: [] };
  }
  if (!state.currentEvents.length) {
    return { ok: false, message: "当前没有可选项目。", picks: [] };
  }
  const profile = PROFILES.find((item) => item.id === state.profileId);
  const major = MAJORS.find((item) => item.id === state.majorId);
  const scoredEvents = state.currentEvents
    .map((event) => ({ event, score: scoreEventForCounselor(event, major, profile) }))
    .sort((a, b) => b.score - a.score);

  const chosenIds = new Set();
  let chosenProjectId = null;
  let usedTime = 0;
  scoredEvents.forEach(({ event }) => {
    const time = getEventTime(event);
    if (event.projectId && chosenProjectId && event.projectId !== chosenProjectId) return;
    if (usedTime + time > state.timeBudget) return;
    chosenIds.add(event.id);
    if (event.projectId) {
      chosenProjectId = event.projectId;
    }
    usedTime += time;
  });

  if (!chosenIds.size) {
    return { ok: false, message: "本学期可用时间不足，无法安排项目。", picks: [] };
  }

  state.selectedEventIds = new Set(chosenIds);
  state.selectedMiniIds = new Set();
  let remainingTime = Math.max(0, state.timeBudget - usedTime);
  const miniLimit = Math.min(AI_MINI_LIMIT, remainingTime);
  const miniCandidates = MINI_ACTIONS.map((action) => ({ action, score: scoreMiniAction(action) }))
    .sort((a, b) => b.score - a.score);

  miniCandidates.forEach(({ action }) => {
    if (state.selectedMiniIds.size >= miniLimit) return;
    if (action.time > remainingTime) return;
    state.selectedMiniIds.add(action.id);
    remainingTime -= action.time;
  });

  updateEventCount();
  renderEvents();
  updateUI();

  const pickedTitles = Array.from(chosenIds)
    .map((id) => state.currentEvents.find((item) => item.id === id))
    .filter(Boolean)
    .map((item) => item.title);
  const miniPicked = Array.from(state.selectedMiniIds)
    .map((id) => MINI_ACTIONS.find((item) => item.id === id))
    .filter(Boolean)
    .map((item) => item.name);
  const msg = `已安排：${pickedTitles.join(" / ")}${miniPicked.length ? `；小行动：${miniPicked.join(" / ")}` : ""}`;
  return { ok: true, message: msg, picks: pickedTitles };
}

function planSchoolListWithAI() {
  if (!state.started || state.termIndex !== 6) {
    return { ok: false, message: "当前阶段无法生成选校名单。" };
  }
  if (!state.essayChoices.length || !state.recChoice) {
    return { ok: false, message: "先选择文书主题与推荐人策略再生成选校。" };
  }
  const scored = UNIVERSITIES.map((school) => ({
    school,
    chance: calculateChance(school, { preview: true }),
  })).sort((a, b) => b.chance - a.chance);
  const thresholds = getTierThresholds();
  const stage = getApplicationStage();
  const targetCount =
    stage === APPLICATION_STAGES.ED_APPLY ? 1 : Math.min(10, UNIVERSITIES.length);

  const picks = [];
  const used = new Set();
  const addFrom = (list, count) => {
    list.forEach((item) => {
      if (picks.length >= count) return;
      if (used.has(item.school.id)) return;
      picks.push(item);
      used.add(item.school.id);
    });
  };
  const safety = scored.filter((item) => item.chance >= thresholds.safety);
  const match = scored.filter(
    (item) => item.chance >= thresholds.match && item.chance < thresholds.safety,
  );
  const reach = scored.filter((item) => item.chance < thresholds.match);
  if (stage === APPLICATION_STAGES.ED_APPLY) {
    addFrom(match.length ? match : scored, 1);
  } else {
    addFrom(safety, 3);
    addFrom(match, 7);
    addFrom(reach, targetCount);
  }
  if (picks.length < targetCount) {
    scored.forEach((item) => {
      if (picks.length >= targetCount) return;
      if (used.has(item.school.id)) return;
      picks.push(item);
      used.add(item.school.id);
    });
  }

  state.selectedSchools = new Set(picks.slice(0, targetCount).map((item) => item.school.id));
  updateSchoolCount();
  renderSchoolList();
  initChatRoles();
  updateUI();
  const summary = picks
    .slice(0, targetCount)
    .map((item) => item.school.name)
    .join(" / ");
  if (stage === APPLICATION_STAGES.ED_APPLY) {
    return { ok: true, message: `已生成 ED 候选学校：${summary}` };
  }
  return { ok: true, message: `已生成 ${targetCount} 校草案：${summary}` };
}

function assignEssaysWithAI() {
  if (!state.started || state.termIndex !== 6) {
    return { ok: false, message: "当前阶段无法分配文书主题。" };
  }
  if (!state.essayChoices.length) {
    return { ok: false, message: "先选择文书主题再分配到学校。" };
  }
  if (!state.selectedSchools.size) {
    return { ok: false, message: "请先选择申请学校。" };
  }

  const assignments = {};
  Array.from(state.selectedSchools).forEach((id) => {
    const school = UNIVERSITIES.find((item) => item.id === id);
    if (!school) return;
    let bestChoice = state.essayChoices[0];
    let bestScore = -1;
    state.essayChoices.forEach((choiceId) => {
      const score = computeEssayFit(school, choiceId);
      if (score > bestScore) {
        bestScore = score;
        bestChoice = choiceId;
      }
    });
    assignments[id] = bestChoice;
  });

  state.schoolEssays = { ...state.schoolEssays, ...assignments };
  renderSchoolList();
  updateUI();
  return { ok: true, message: "已为所选学校自动分配文书主题。" };
}

function handleAiPlanTerm() {
  const result = planTermWithAI();
  if (aiPlanNote) {
    aiPlanNote.textContent = result.message;
  }
}

function handleAiSchoolPlan() {
  const result = planSchoolListWithAI();
  if (aiSchoolNote) {
    aiSchoolNote.textContent = result.message;
  }
}

function handleAiEssayAssign() {
  const result = assignEssaysWithAI();
  if (aiEssayNote) {
    aiEssayNote.textContent = result.message;
  }
}

function formatFollowUp(roleId, intent) {
  if (roleId === "counselor") {
    const pool = [
      "你更偏好学术冲刺还是活动亮点？",
      "预算上限大概是多少？我可以调整策略。",
      "更看重录取概率还是匹配度？",
      "你更愿意把精力放在标化还是项目？",
      "你希望这学期主打研究、实习还是领导力？",
      "要不要我直接给你一套可执行的本学期组合？",
    ];
    return pickVariant(pool, `${roleId}-followup-${intent ? JSON.stringify(intent) : "general"}`);
  }
  if (roleId === "family") {
    const pool = [
      "最近压力大不大？",
      "要不要一起算一下预算？",
      "你最近最担心哪件事？",
      "这学期你最想先稳住哪一块？",
    ];
    return pickVariant(pool, `${roleId}-followup`);
  }
  if (roleId === "peer") {
    const pool = [
      "你打算冲几所学校？",
      "你文书进度到哪了？",
      "最近有参加什么比赛吗？",
      "你这学期主线项目选了哪个方向？",
    ];
    return pickVariant(pool, `${roleId}-followup`);
  }
  return "";
}

function recordFollowUp(question) {
  if (!question) return;
  state.chatContext.lastQuestion = {
    text: question,
    ts: Date.now(),
  };
}

function consumeFollowUp() {
  const last = state.chatContext.lastQuestion;
  state.chatContext.lastQuestion = null;
  return last;
}

function getActiveHigherEdStage() {
  if (state.undergradStarted && !state.undergradGraduated) return "undergrad";
  if (state.mastersStarted && !state.mastersGraduated) return "masters";
  if (state.phdStarted && !state.phdGraduated) return "phd";
  return null;
}

function buildHigherEdTermFocusLine(stage) {
  if (!stage) return "";
  ensureHigherEdTermPrepared(stage);
  const termState = getHigherEdStageTermState(stage);
  const events = getHigherEdActionPool(stage);
  const selected = new Set(termState.selectedEventIds || []);
  const scoredEvents = events
    .map((event) => ({
      event,
      score: scoreHigherEdAction(event, stage),
    }))
    .sort((a, b) => b.score - a.score);
  const topEvents = scoredEvents.slice(0, 2).map((item) => item.event.name);
  const miniScored = getHigherEdMiniActions(stage)
    .map((action) => {
      const fx = action.effects || {};
      const base =
        stage === "undergrad"
          ? (fx.gpa || 0) * 20 + (fx.research || 0) * 0.8 + (fx.internship || 0) * 0.8 + (fx.leadership || 0) * 0.8
          : stage === "masters"
            ? (fx.gpa || 0) * 20 + (fx.research || 0) * 0.95 + (fx.thesis || 0) * 0.95 + (fx.internship || 0) * 0.55
            : (fx.research || 0) * 1.05 + (fx.publication || 0) * 1.05 + (fx.teaching || 0) * 0.7 + (fx.internship || 0) * 0.45;
      return {
        action,
        score: base - (fx.stress || 0) * 1.1 - getHigherEdMiniCost(stage, action) / 450,
      };
    })
    .sort((a, b) => b.score - a.score);
  const topMini = miniScored.slice(0, 2).map((item) => item.action.name);

  const selectedEvents = events.filter((event) => selected.has(event.id));
  const selectedMini = getHigherEdMiniActions(stage).filter((item) => (termState.selectedMiniIds || []).includes(item.id));
  const usedTime =
    selectedEvents.reduce((sum, event) => sum + getHigherEdEventTime(stage, event), 0) +
    selectedMini.reduce((sum, action) => sum + Number(action.time || 0), 0);
  const usedCost =
    selectedEvents.reduce((sum, event) => sum + getHigherEdEventCost(stage, event), 0) +
    selectedMini.reduce((sum, action) => sum + getHigherEdMiniCost(stage, action), 0);
  const timeLeft = Math.max(0, (termState.timeBudget || 0) - usedTime);
  const cashLeft = Math.max(0, state.cash - usedCost);
  const eventLine = topEvents.length ? `重点推荐：${topEvents.join(" / ")}` : "重点推荐：当前事件池已空";
  const miniLine = topMini.length ? `小行动：${topMini.join(" / ")}` : "小行动：优先恢复性安排";
  const pickLine = selectedEvents.length
    ? `已选重点 ${selectedEvents.length} 项（${selectedEvents.map((item) => item.name).join(" / ")}）`
    : "尚未锁定重点项目";
  return `${eventLine}；${miniLine}。${pickLine}。剩余时间 ${timeLeft} 点，预计可用资金 ${formatUsd(cashLeft)}。`;
}

function buildCounselorAdvice(intent) {
  const weakStats = getTopWeakStats(2).join("、");
  const recommendation = getCounselorEventRecommendation();
  const mini = getMiniActionSuggestions(2);
  const appActions = getAppActionSuggestions(2);
  const cashLine = state.cash < 3000 ? "预算有点紧，建议优先低成本项目。" : "预算还算稳。";
  const higherEdStage = getActiveHigherEdStage();

  if (higherEdStage) {
    const stageLabel = getHigherEdStageLabel(higherEdStage);
    const focusLine = buildHigherEdTermFocusLine(higherEdStage);
    const stress = Math.round((getHigherEdProfile(higherEdStage)?.stress || 0));
    return `${stageLabel}阶段建议：${focusLine} 当前压力 ${stress}/100。`;
  }

  if (state.termIndex <= 5) {
    const miniLine = mini.length ? `小行动推荐：${mini.join(" / ")}` : "小行动：按节奏补强即可。";
    return `${recommendation.line} ${miniLine} ${cashLine} 重点补强：${weakStats}。`;
  }
  if (state.termIndex === 6) {
    const appLine = appActions.length ? `申请季行动建议：${appActions.join(" / ")}` : "申请季行动已完成得很充分。";
    return `${appLine} 文书进度 ${(state.stats.essayTrack ?? 0)} / 100，推荐关系 ${(state.stats.recStrength ?? 0)} / 100。`;
  }
  if (state.finalChoice && !state.undergradStarted) {
    return "你已确定去向，可开始本科8学期模拟并提前规划毕业分流。";
  }
  if (state.undergradGraduated && !state.mastersStarted && !state.phdStarted && !state.postGradPath) {
    return "本科已毕业，下一步建议在硕士与就业之间尽快决策（博士需硕士后申请）。";
  }
  if (state.mastersStarted && !state.mastersGraduated) {
    return "硕士阶段建议优先保证研究与论文进度，别把压力推太高。";
  }
  if (state.mastersGraduated && !state.phdStarted && state.postGradPath !== POSTGRAD_PATHS.JOB) {
    return state.msPhdApproved
      ? "你有硕博连读通道，可直接进入博士，或转就业路径。"
      : "硕士已毕业，建议在博士申请与就业之间尽快决策。";
  }
  if (state.phdStarted && !state.phdGraduated) {
    return "博士阶段重点是发表、课题推进和产业协同，建议保持学期稳定输出。";
  }
  if (state.phdGraduated && !state.jobOutcome) {
    return "博士已毕业，建议马上提交公司投递，并在交流室用面试官问答完成评估。";
  }
  return `放榜季保持冷静，候补和最终去向都可以再优化。`;
}

function buildJourneyDigestLine() {
  if (!state.started) return "当前未开始旅程。";
  if (state.termIndex <= 5) {
    return `高中阶段 ${TERMS[state.termIndex]?.name || ""}：时间点数 ${state.timeUsed} / ${state.timeBudget}。`;
  }
  if (state.termIndex === 6) {
    return `申请季：时间点数 ${state.timeUsed} / ${state.timeBudget}，已选学校 ${state.selectedSchools?.size || 0} 所。`;
  }
  if (state.undergradStarted && !state.undergradGraduated) {
    const ts = getHigherEdStageTermState("undergrad");
    const selected = (ts.selectedEventIds || []).length;
    return `本科第 ${getHigherEdCurrentTermNumber("undergrad")} 学期：已选重点 ${selected} 项，时间点数 ${ts.timeUsed || 0} / ${ts.timeBudget || 0}。`;
  }
  if (state.mastersStarted && !state.mastersGraduated) {
    const ts = getHigherEdStageTermState("masters");
    const selected = (ts.selectedEventIds || []).length;
    return `硕士第 ${getHigherEdCurrentTermNumber("masters")} 学期：已选重点 ${selected} 项，时间点数 ${ts.timeUsed || 0} / ${ts.timeBudget || 0}。`;
  }
  if (state.phdStarted && !state.phdGraduated) {
    const ts = getHigherEdStageTermState("phd");
    const selected = (ts.selectedEventIds || []).length;
    return `博士第 ${getHigherEdCurrentTermNumber("phd")} 学期：已选重点 ${selected} 项，时间点数 ${ts.timeUsed || 0} / ${ts.timeBudget || 0}。`;
  }
  if (state.postGradPath === POSTGRAD_PATHS.JOB || state.jobOutcome) {
    const apps = state.jobOutcome?.applications || [];
    return `求职阶段：已投递 ${apps.length} 家，录用 ${state.jobOutcome?.offerCount || 0} 家。`;
  }
  return "当前处于放榜/去向决策阶段。";
}

function isAppealIntent(text) {
  const content = text.toLowerCase();
  const keywords = [
    "申诉",
    "复议",
    "重新考虑",
    "重新录取",
    "重新入取",
    "appeal",
    "reconsider",
    "补充材料",
    "补充",
    "更新",
    "新增",
    "写信",
    "请求考虑",
    "waitlist",
    "候补转正",
  ];
  return keywords.some((word) => content.includes(word));
}

function isCombinedDegreeIntent(text) {
  const content = (text || "").toLowerCase();
  const keywords = [
    "本硕连读",
    "本硕",
    "连读",
    "4+1",
    "combined degree",
    "combined",
    "直硕",
  ];
  return keywords.some((word) => content.includes(word));
}

function isCombinedDoctoralIntent(text) {
  const content = (text || "").toLowerCase();
  const keywords = [
    "本硕博连读",
    "本硕博",
    "本硕博贯通",
    "本博连读",
    "本硕博项目",
    "本硕博直通",
    "直博",
  ];
  return keywords.some((word) => content.includes(word));
}

function isMsPhdIntent(text) {
  const content = (text || "").toLowerCase();
  const keywords = [
    "硕博连读",
    "硕转博",
    "msphd",
    "masterphd",
    "master-phd",
  ];
  return keywords.some((word) => content.includes(word));
}

function extractDonationAmount(text) {
  if (!text) return 0;
  const lowered = text.toLowerCase();
  const triggers = ["捐", "捐款", "donate", "donation", "赞助", "捐赠"];
  if (!triggers.some((t) => lowered.includes(t))) return 0;
  const regex = /(\d+(?:\.\d+)?)(\s*)(万|千|k|w|m|百万)?/gi;
  let match;
  let maxAmount = 0;
  while ((match = regex.exec(lowered))) {
    const value = parseFloat(match[1]);
    if (!Number.isFinite(value)) continue;
    let amount = value;
    const unit = match[3];
    if (unit === "万" || unit === "w") amount *= 10000;
    if (unit === "千" || unit === "k") amount *= 1000;
    if (unit === "m" || unit === "百万") amount *= 1000000;
    if (amount > maxAmount) maxAmount = amount;
  }
  return Math.round(maxAmount);
}

function computeDonationBonus(amount) {
  if (!amount || amount <= 0) return 0;
  const bonus = (amount / 100000) * DONATION_BONUS_MAX;
  return clamp(bonus, 0, DONATION_BONUS_MAX);
}

function evaluateAppealChance(roleId, text, result, donationBonus = 0, evidenceBonus = 0) {
  const cleaned = text.toLowerCase().replace(/\s/g, "");
  const length = cleaned.length;
  const updateKeywords = [
    "更新",
    "补充",
    "新增",
    "近况",
    "获奖",
    "竞赛",
    "比赛",
    "项目",
    "研究",
    "论文",
    "发表",
    "奖学金",
    "实习",
    "成绩",
    "gpa",
    "sat",
    "act",
    "ap",
    "ib",
    "领导",
  ];
  const politeKeywords = ["谢谢", "感谢", "麻烦", "抱歉", "请"];
  const updateHits = updateKeywords.filter((word) => cleaned.includes(word)).length;
  const hasUpdate = updateHits > 0;
  let chance = result.status === "候补" ? APPEAL_CONFIG.baseWaitlist : APPEAL_CONFIG.baseReject;
  chance += clamp(length / 180, 0, 0.12);
  if (hasUpdate) {
    chance += 0.08 + Math.min(0.04, updateHits * 0.02);
  }
  if (politeKeywords.some((word) => cleaned.includes(word))) {
    chance += 0.02;
  }
  const counselor = COUNSELORS.find((item) => item.id === state.counselorId);
  const quality = getCounselorQuality(counselor);
  const qualityLabel = quality >= 0.75 ? "high" : quality >= 0.5 ? "mid" : "low";
  chance *= APPEAL_CONFIG.counselorMultiplier[qualityLabel] || 1;
  const statBoost =
    ((state.stats.essayTrack ?? 0) + (state.stats.recStrength ?? 0) + (state.stats.reputation ?? 0)) / 300;
  chance += statBoost * 0.08;
  chance += evidenceBonus;
  chance += donationBonus;
  const relationship = state.chatRelationships[roleId] ?? getDefaultRelationship(roleId);
  chance += (relationship - 50) / 500;
  const cap = result.status === "候补" ? APPEAL_CONFIG.maxWaitlist : APPEAL_CONFIG.maxReject;
  return { chance: clamp(chance, 0.05, cap), length, hasUpdate };
}

function getAdmissionsAppealKey(stage, schoolId, programType = "masters") {
  if (!schoolId) return "";
  if (stage === "undergrad") return `ug:${schoolId}`;
  const normalized = programType === "phd" ? "phd" : programType === "msphd" ? "msphd" : "masters";
  return `grad:${normalized}:${schoolId}`;
}

function hasAdmissionsAppeal(appealKey, legacySchoolId = null) {
  if (!appealKey) return false;
  if (!state.appealsUsed || typeof state.appealsUsed !== "object") {
    state.appealsUsed = {};
  }
  if (state.appealsUsed[appealKey]) return true;
  if (legacySchoolId && state.appealsUsed[legacySchoolId]) return true;
  return false;
}

function markAdmissionsAppeal(appealKey, legacySchoolId = null) {
  if (!appealKey) return;
  if (!state.appealsUsed || typeof state.appealsUsed !== "object") {
    state.appealsUsed = {};
  }
  state.appealsUsed[appealKey] = true;
  if (legacySchoolId && state.appealsUsed[legacySchoolId]) {
    delete state.appealsUsed[legacySchoolId];
  }
}

function handleAdmissionsAppeal(roleId, school, result, text) {
  const memoryLine = getMemoryLine(roleId);
  const changedReply = "结果已改变，请拆信查看。";
  const unchangedReply = "结果未改变。";
  const appealKey = getAdmissionsAppealKey("undergrad", school.id);
  if (result.status === "录取") {
    return `${memoryLine} 你已经获得录取，无需再申诉。`;
  }
  if (result.status === "撤回") {
    return `${memoryLine} 该申请已撤回，无法进行申诉流程。`;
  }
  if (hasAdmissionsAppeal(appealKey, school.id)) {
    if (result.appealReviewed) {
      if (result.appealResultChanged && result.revealed === false) {
        return changedReply;
      }
      if (!result.appealResultChanged) {
        return unchangedReply;
      }
    }
    return `${memoryLine} 该学校已提交过一次申诉。`;
  }
  const donationAmount =
    state.chatContext?.appealDonation && state.chatContext.appealDonation > 0
      ? state.chatContext.appealDonation
      : extractDonationAmount(text);
  const evidenceEval = evaluateAppealEvidence();
  const baseEval = evaluateAppealChance(roleId, text, result, 0, evidenceEval.bonus);
  if ((baseEval.length < 20 && evidenceEval.selectedCount === 0) || (!baseEval.hasUpdate && evidenceEval.selectedCount === 0)) {
    const donationHint = donationAmount
      ? "捐款需要搭配具体更新信息才会计入。"
      : "";
    const evidenceHint = evidenceEval.selectedCount
      ? "当前附件仍不足以形成有效更新，建议补充更强证据。"
      : "可先在“申诉附件槽位”补充成绩/项目/推荐证据。";
    return `${memoryLine} 申诉需要具体补充信息（如新奖项/成绩/项目进展）。${evidenceHint}${donationHint}`;
  }

  let donationBonus = 0;
  let donationLine = "";
  if (donationAmount > 0) {
    if (donationAmount > state.cash) {
      donationLine = "捐款金额超出当前可用资金，未计入。";
    } else {
      state.cash -= donationAmount;
      donationBonus = computeDonationBonus(donationAmount);
      state.log.unshift(`申诉捐款：${formatUsd(donationAmount)}（${school.name}）`);
      donationLine = `已记录捐款 ${formatUsd(donationAmount)}。`;
    }
  }
  if (evidenceEval.selectedItems.length) {
    state.log.unshift(`申诉附件：${school.name} · ${evidenceEval.selectedItems.map((item) => item.name).join("、")}`);
  }
  state.chatContext.appealDonation = 0;
  if (donationRange && donationValue) {
    donationRange.value = "0";
    donationValue.textContent = formatUsd(0);
  }

  const finalEval = donationBonus
    ? evaluateAppealChance(roleId, text, result, donationBonus, evidenceEval.bonus)
    : baseEval;
  markAdmissionsAppeal(appealKey, school.id);
  const roll = Math.random();
  let newStatus = null;
  if (result.status === "候补") {
    if (roll <= finalEval.chance) newStatus = "录取";
  } else if (result.status === "拒绝") {
    if (roll <= finalEval.chance * 0.35) {
      newStatus = "录取";
    } else if (roll <= finalEval.chance) {
      newStatus = "候补";
    }
  }

  if (newStatus) {
    const evaluation = evaluateApplication(school, { preview: true, roundOverride: result.roundChoice });
    let aidPercent = result.aidPercent;
    let netCost = result.netCost;
    let aidDelay = result.aidDelay;
    let netCostFirstYear = result.netCostFirstYear;
    let aidFirstYear = result.aidFirstYear;
    let renewalPolicy = result.renewalPolicy || null;
    let estimatedFourYearCost = result.estimatedFourYearCost ?? null;
    if (newStatus === "录取") {
      const aid = calculateAidOffer(school, result.roundChoice);
      aidPercent = aid.aidPercent;
      netCost = aid.netCost;
      const delay = applyAidDelayToOffer(school, aidPercent, netCost);
      aidDelay = delay.aidDelay;
      netCostFirstYear = delay.netCostFirstYear;
      aidFirstYear = delay.aidFirstYear;
      renewalPolicy = buildRenewalPolicy(school, aidPercent || 0);
      const estimated = estimateFourYearCost({
        ...school,
        status: "录取",
        aidPercent,
        netCost,
        aidDelay,
        netCostFirstYear,
        renewalPolicy,
      });
      estimatedFourYearCost = estimated ? estimated.total : null;
    } else {
      aidPercent = null;
      netCost = null;
      aidDelay = false;
      netCostFirstYear = null;
      aidFirstYear = null;
      renewalPolicy = null;
      estimatedFourYearCost = null;
      state.waitlistUpdated = false;
    }
    const reasons = getDecisionReasons(school, evaluation, newStatus, result.roundChoice);
    result.status = newStatus;
    result.aidPercent = aidPercent;
    result.netCost = netCost;
    result.aidDelay = aidDelay;
    result.netCostFirstYear = netCostFirstYear;
    result.aidFirstYear = aidFirstYear;
    result.renewalPolicy = renewalPolicy;
    result.estimatedFourYearCost = estimatedFourYearCost;
    result.academicScore = evaluation.academic;
    result.holisticScore = evaluation.holistic;
    result.selectivityScore = evaluation.selectivity;
    result.scoreGap = evaluation.score - evaluation.selectivity;
    result.stressPenaltyScore = evaluation.stressPenalty;
    result.reasons = Array.from(new Set([...reasons, "申诉补充材料"])).slice(0, 4);
    result.tips = getImprovementTips(evaluation);
    result.decisionDrivers = buildDecisionDrivers(school, evaluation, result.roundChoice);
    result.revealed = false;
    result.appealReviewed = true;
    result.appealResultChanged = true;
    result.appealSubmittedAt = Date.now();
    state.log.unshift(`申诉回执：${school.name}，请查收招生邮件。`);
    pushReplayNode(`申诉回执：${school.name}`);
    updateAchievements();
    updateUI();
    return changedReply;
  }

  result.revealed = true;
  result.appealReviewed = true;
  result.appealResultChanged = false;
  result.appealSubmittedAt = Date.now();
  state.log.unshift(`申诉回执：${school.name}，结果未改变。`);
  pushReplayNode(`申诉回执：${school.name}`);
  updateUI();
  return unchangedReply;
}

function evaluateGradAppealChance(roleId, text, result, donationBonus = 0, evidenceBonus = 0) {
  const cleaned = String(text || "").toLowerCase().replace(/\s/g, "");
  const length = cleaned.length;
  const updateKeywords = [
    "更新",
    "补充",
    "新增",
    "论文",
    "投稿",
    "发表",
    "研究",
    "课题",
    "实习",
    "项目",
    "奖项",
    "推荐",
    "成绩",
    "gpa",
    "产出",
  ];
  const updateHits = updateKeywords.filter((word) => cleaned.includes(word)).length;
  const hasUpdate = updateHits > 0;
  const programType = result.programType === "phd" ? "phd" : "masters";
  let chance = result.status === "候补" ? (programType === "phd" ? 0.28 : 0.32) : programType === "phd" ? 0.13 : 0.18;
  chance += clamp(length / 210, 0, 0.1);
  if (hasUpdate) {
    chance += 0.08 + Math.min(0.04, updateHits * 0.012);
  }
  const profileStrength =
    programType === "phd"
      ? clamp(((state.mastersProfile?.research || 0) + (state.mastersProfile?.thesis || 0)) / 200, 0, 1)
      : clamp(((state.undergradProfile?.research || 0) + (state.undergradProfile?.internship || 0)) / 200, 0, 1);
  chance += profileStrength * 0.07;
  chance += evidenceBonus;
  chance += donationBonus;
  const relationship = state.chatRelationships[roleId] ?? getDefaultRelationship(roleId);
  chance += (relationship - 50) / 520;
  const cap = result.status === "候补" ? 0.72 : 0.42;
  return { chance: clamp(chance, 0.05, cap), length, hasUpdate };
}

function handleGradAdmissionsAppeal(roleId, school, result, text) {
  const memoryLine = getMemoryLine(roleId);
  const changedReply = "结果已改变，请拆信查看。";
  const unchangedReply = "结果未改变。";
  if (!result) {
    return `${memoryLine} 当前没有该校研究生申请记录。`;
  }
  if (result.revealed === false) {
    return `${memoryLine} 请先拆开该校研究生结果邮件后再申诉。`;
  }
  if (result.status === "录取") {
    return `${memoryLine} 当前已录取，无需申诉。`;
  }
  const appealKey = getAdmissionsAppealKey("grad", school.id, result.programType);
  if (hasAdmissionsAppeal(appealKey)) {
    if (result.appealReviewed) {
      if (result.appealResultChanged && result.revealed === false) {
        return changedReply;
      }
      if (!result.appealResultChanged) {
        return unchangedReply;
      }
    }
    return `${memoryLine} 该学校该项目已提交过一次申诉。`;
  }

  const donationAmount =
    state.chatContext?.appealDonation && state.chatContext.appealDonation > 0
      ? state.chatContext.appealDonation
      : extractDonationAmount(text);
  const evidenceEval = evaluateAppealEvidence();
  const baseEval = evaluateGradAppealChance(roleId, text, result, 0, evidenceEval.bonus);
  if ((baseEval.length < 16 && evidenceEval.selectedCount === 0) || (!baseEval.hasUpdate && evidenceEval.selectedCount === 0)) {
    const donationHint = donationAmount ? "捐款需要搭配具体更新信息才会计入。" : "";
    const evidenceHint = evidenceEval.selectedCount
      ? "当前附件仍不足以形成有效更新，建议补充更强证据。"
      : "可先在“申诉附件槽位”补充成绩/项目/推荐证据。";
    return `${memoryLine} 申诉需要具体补充信息（如新论文/新项目/新推荐）。${evidenceHint}${donationHint}`;
  }

  let donationBonus = 0;
  if (donationAmount > 0) {
    if (donationAmount > state.cash) {
      // no-op: over budget donations do not count
    } else {
      state.cash -= donationAmount;
      donationBonus = computeDonationBonus(donationAmount);
      state.log.unshift(`研究生申诉捐款：${formatUsd(donationAmount)}（${school.name}）`);
    }
  }
  if (evidenceEval.selectedItems.length) {
    state.log.unshift(`研究生申诉附件：${school.name} · ${evidenceEval.selectedItems.map((item) => item.name).join("、")}`);
  }
  state.chatContext.appealDonation = 0;
  if (donationRange && donationValue) {
    donationRange.value = "0";
    donationValue.textContent = formatUsd(0);
  }

  const finalEval = donationBonus
    ? evaluateGradAppealChance(roleId, text, result, donationBonus, evidenceEval.bonus)
    : baseEval;
  markAdmissionsAppeal(appealKey);
  const roll = Math.random();
  let newStatus = null;
  if (result.status === "候补") {
    if (roll <= finalEval.chance) newStatus = "录取";
  } else if (result.status === "拒绝") {
    if (roll <= finalEval.chance * 0.32) {
      newStatus = "录取";
    } else if (roll <= finalEval.chance) {
      newStatus = "候补";
    }
  }

  if (newStatus) {
    const majorId = getValidMajorId(result.majorId || getGradApplyMajorIdForProgramType(result.programType));
    const chance =
      result.programType === "phd"
        ? evaluatePhdChance(school, { majorId })
        : evaluateMastersChance(school, { programMode: result.programType === "msphd" ? "msphd" : "masters", majorId });
    const reasonPack = buildGradDecisionReason(
      result.programType === "phd" ? "phd" : "masters",
      school,
      newStatus,
      chance,
      { programMode: result.programType === "msphd" ? "msphd" : "masters", majorId },
    );
    const aidPack =
      newStatus === "录取"
        ? calculateGraduateAidOffer(school, result.programType === "phd" ? "phd" : "masters", {
            programType: result.programType === "phd" ? "phd" : result.programType === "msphd" ? "msphd" : "masters",
            majorId,
            chance,
          })
        : null;
    result.status = newStatus;
    result.chance = chance;
    result.fitScore = calculateFitScore(school, majorId);
    result.majorId = majorId;
    result.majorName = getMajorName(majorId);
    result.reason = reasonPack.reason;
    result.reasons = reasonPack.reasons;
    result.aidPercent = aidPack?.aidPercent ?? null;
    result.netCost = aidPack?.netCost ?? null;
    result.tuition = aidPack?.tuition ?? null;
    result.scholarshipLabel = aidPack?.scholarshipLabel ?? null;
    result.revealed = false;
    result.appealReviewed = true;
    result.appealResultChanged = true;
    result.appealSubmittedAt = Date.now();
    state.log.unshift(`研究生申诉回执：${school.name}，请拆信查看。`);
    pushReplayNode(`研究生申诉回执：${school.name}`);
    updateAchievements();
    updateUI();
    return changedReply;
  }

  result.revealed = true;
  result.appealReviewed = true;
  result.appealResultChanged = false;
  result.appealSubmittedAt = Date.now();
  state.log.unshift(`研究生申诉回执：${school.name}，结果未改变。`);
  pushReplayNode(`研究生申诉回执：${school.name}`);
  updateUI();
  return unchangedReply;
}

function handleCombinedDegreeRequest(roleId, school, result) {
  const memoryLine = getMemoryLine(roleId);
  const windowKey = getUndergradCombinedWindowKey(school?.id);
  const appliedTerm = state.undergradStarted ? getHigherEdCurrentTermNumber("undergrad") : 0;
  if (result.status !== "录取") {
    return `${memoryLine} 本硕连读仅面向已录取学生开放。`;
  }
  if (!state.finalChoice) {
    return `${memoryLine} 请先确认最终去向后，再提交本硕连读申请。`;
  }
  if (state.finalChoice !== school.id) {
    return `${memoryLine} 本硕连读申请需向你的最终就读学校提交。`;
  }
  if (!windowKey) {
    return `${memoryLine} 本硕连读申请仅开放在本科第一学期前，或本科最后两个学期。`;
  }
  if (state.combinedDegreeApproved) {
    return `${memoryLine} 你已通过本硕连读预审，后续按学院培养方案执行。`;
  }
  if (!hasUnusedCombinedWindow(state.combinedDegreeLastWindow, windowKey, state.combinedDegreeApproved)) {
    return `${memoryLine} 你已在${getCombinedWindowLabel(windowKey)}提交过本硕连读申请，本窗口无需重复提交。`;
  }
  if (!canApplyCombinedDegreeForSchool(school, result)) {
    return `${memoryLine} 当前档案未达到本硕连读直通标准，建议入学后通过 GPA 与科研成果再申请。`;
  }

  const academic = result.academicScore ?? 0;
  const holistic = result.holisticScore ?? 0;
  const fit = result.fitScore ?? 0;
  const relationship = state.chatRelationships[roleId] ?? getDefaultRelationship(roleId);
  let chance = 0.34 + academic * 0.22 + holistic * 0.12 + fit * 0.14;
  chance += (relationship - 50) / 500;
  chance = clamp(chance, 0.28, 0.9);
  const passed = Math.random() <= chance;
  state.combinedDegreeApplied = true;
  state.combinedDegreeLastWindow = windowKey;
  state.combinedDegreeApproved = passed;
  state.combinedDegreeSchoolId = school.id;
  queueCombinedDecisionAnnouncement({ type: "bsms", school, passed, windowKey, appliedTerm });
  if (passed) {
    state.combinedDegreeEligible = true;
    state.log.unshift(`本硕连读通过：${school.name}`);
    if (state.undergradStarted && state.undergradProfile) {
      state.undergradProfile.gpa = Number(clamp(state.undergradProfile.gpa + 0.04, 2.2, 4).toFixed(2));
      state.undergradProfile.research = Math.round(clamp((state.undergradProfile.research || 0) + 6, 0, 100));
    }
    pushReplayNode("本硕连读通过");
    updateAchievements();
    updateUI();
    return `${memoryLine} 已收到你的本硕连读申请，结果会在下一个学期开学前或毕业去向阶段自动通知。`;
  }
  state.log.unshift(`本硕连读未通过：${school.name}`);
  pushReplayNode("本硕连读未通过");
  updateUI();
  return `${memoryLine} 已收到你的本硕连读申请，结果会在下一个学期开学前或毕业去向阶段自动通知。`;
}

function handleCombinedDoctoralRequest(roleId, school, result) {
  const memoryLine = getMemoryLine(roleId);
  const windowKey = getUndergradCombinedWindowKey(school?.id);
  const appliedTerm = state.undergradStarted ? getHigherEdCurrentTermNumber("undergrad") : 0;
  if (!result || result.status !== "录取") {
    return `${memoryLine} 本硕博连读仅面向已录取学生开放。`;
  }
  if (!state.finalChoice) {
    return `${memoryLine} 请先确认最终去向后，再提交本硕博连读申请。`;
  }
  if (state.finalChoice !== school.id) {
    return `${memoryLine} 本硕博连读申请需向你的最终就读学校提交。`;
  }
  if (state.mastersStarted || state.phdStarted) {
    return `${memoryLine} 本硕博连读申请需在硕士/博士阶段启动前提交。`;
  }
  if (!windowKey) {
    return `${memoryLine} 本硕博连读申请仅开放在本科第一学期前，或本科最后两个学期。`;
  }
  if (state.directPhdApproved) {
    return `${memoryLine} 你已通过本硕博连读预审。`;
  }
  if (!hasUnusedCombinedWindow(state.directPhdLastWindow, windowKey, state.directPhdApproved)) {
    return `${memoryLine} 你已在${getCombinedWindowLabel(windowKey)}提交过本硕博连读申请，本窗口无需重复提交。`;
  }
  if (!canApplyCombinedDoctoralForSchool(school, result)) {
    return `${memoryLine} 当前档案暂未达到本硕博连读门槛，建议先补强学术、科研与专业匹配度。`;
  }

  const relationship = state.chatRelationships[roleId] ?? getDefaultRelationship(roleId);
  const counselor = COUNSELORS.find((item) => item.id === state.counselorId);
  const counselorBoost = getCounselorQuality(counselor) * 0.06;
  const academic = clamp(result.academicScore ?? 0, 0, 1);
  const fit = clamp(result.fitScore ?? 0, 0, 1);
  let chance = 0.28 + academic * 0.24 + fit * 0.2 + counselorBoost;
  if (state.undergradStarted || state.undergradGraduated) {
    const profile = state.undergradProfile || getDefaultUndergradProfile();
    const ugGpa = clamp(((profile.gpa || 2.9) - 2.2) / 1.8, 0, 1);
    const ugResearch = clamp((profile.research || 0) / 100, 0, 1);
    const ugLeadership = clamp((profile.leadership || 0) / 100, 0, 1);
    const ugStressControl = clamp(1 - (profile.stress || 0) / 100, 0, 1);
    chance += ugGpa * 0.16 + ugResearch * 0.18 + ugLeadership * 0.08 + ugStressControl * 0.04;
  } else {
    const awards = clamp((state.stats.awards ?? 0) / 100, 0, 1);
    const activities = clamp((state.stats.activities ?? 0) / 100, 0, 1);
    chance += awards * 0.14 + activities * 0.14;
  }
  chance += (relationship - 50) / 500;
  if (state.difficultyId === "relaxed") chance += 0.04;
  if (state.difficultyId === "hard") chance -= 0.03;
  chance = clamp(chance, 0.22, 0.9);
  const passed = Math.random() <= chance;

  state.directPhdApplied = true;
  state.directPhdLastWindow = windowKey;
  state.directPhdApproved = passed;
  state.directPhdSchoolId = passed ? school.id : null;
  queueCombinedDecisionAnnouncement({ type: "bsmsphd", school, passed, windowKey, appliedTerm });
  if (passed) {
    state.combinedDegreeSchoolId = school.id;
    state.combinedDegreeApplied = true;
    state.combinedDegreeApproved = true;
    state.log.unshift(`本硕博连读通过：${school.name}`);
    pushReplayNode("本硕博连读通过");
    updateAchievements();
    updateUI();
    return `${memoryLine} 已收到你的本硕博连读申请，结果会在下一个学期开学前或毕业去向阶段自动通知。`;
  }
  state.log.unshift(`本硕博连读未通过：${school.name}`);
  pushReplayNode("本硕博连读未通过");
  updateUI();
  return `${memoryLine} 已收到你的本硕博连读申请，结果会在下一个学期开学前或毕业去向阶段自动通知。`;
}

function handleMsPhdRequest(roleId, school, gradResultInput = null) {
  const memoryLine = getMemoryLine(roleId);
  const gradResult = gradResultInput || getAdmissionsGradResult(school.id);
  const windowKey = getMastersCombinedWindowKey(school?.id);
  const appliedTerm = state.mastersStarted ? getHigherEdCurrentTermNumber("masters") : 0;
  if (state.phdStarted) {
    return `${memoryLine} 博士阶段已启动，当前无法再申请硕博连读。`;
  }
  if (state.msPhdApproved && state.msPhdSchoolId === school.id) {
    return `${memoryLine} 你已通过硕博连读评估。`;
  }
  if (!windowKey) {
    return `${memoryLine} 硕博连读申请仅开放在硕士入学前、第一学期，或硕士最后两个学期。`;
  }
  if (!hasUnusedCombinedWindow(state.msPhdLastWindow, windowKey, state.msPhdApproved)) {
    return `${memoryLine} 你已在${getCombinedWindowLabel(windowKey)}提交过硕博连读申请，本窗口无需重复提交。`;
  }
  if (!canApplyMsPhdForSchool(school, gradResult)) {
    return `${memoryLine} 当前不满足硕博连读申请条件。`;
  }

  const relationship = state.chatRelationships[roleId] ?? getDefaultRelationship(roleId);
  let chance = 0.34;
  if (state.mastersStarted && state.mastersSchoolId === school.id) {
    const profile = state.mastersProfile || getDefaultMastersProfile();
    const gpa = clamp((profile.gpa - 2.4) / 1.6, 0, 1);
    const research = clamp((profile.research || 0) / 100, 0, 1);
    const thesis = clamp((profile.thesis || 0) / 100, 0, 1);
    const stressControl = clamp(1 - (profile.stress || 0) / 100, 0, 1);
    chance += gpa * 0.2 + research * 0.24 + thesis * 0.14 + stressControl * 0.08;
  } else {
    const mastersChance = evaluateMastersChance(school, { programMode: "msphd" });
    chance += mastersChance * 0.42;
  }
  chance += (relationship - 50) / 550;
  if (state.difficultyId === "relaxed") chance += 0.03;
  if (state.difficultyId === "hard") chance -= 0.02;
  chance = clamp(chance, 0.2, 0.9);
  const passed = Math.random() <= chance;

  state.msPhdApplied = true;
  state.msPhdLastWindow = windowKey;
  state.msPhdApproved = passed;
  state.msPhdSchoolId = passed ? school.id : null;
  queueCombinedDecisionAnnouncement({ type: "msphd", school, passed, windowKey, appliedTerm });
  if (passed) {
    if (gradResult && gradResult.programType !== "phd") {
      gradResult.programType = "msphd";
    }
    if (state.mastersStarted && state.mastersSchoolId === school.id) {
      state.mastersProgramType = "msphd";
    }
    state.log.unshift(`硕博连读通过：${school.name}`);
    pushReplayNode("硕博连读通过");
    updateAchievements();
    updateUI();
    return `${memoryLine} 已收到你的硕博连读申请，结果会在下一个学期开学前或毕业去向阶段自动通知。`;
  }
  state.log.unshift(`硕博连读未通过：${school.name}`);
  pushReplayNode("硕博连读未通过");
  updateUI();
  return `${memoryLine} 已收到你的硕博连读申请，结果会在下一个学期开学前或毕业去向阶段自动通知。`;
}

function getPendingInterviewApplications() {
  if (!state.jobOutcome || !Array.isArray(state.jobOutcome.applications)) return [];
  return state.jobOutcome.applications
    .filter((item) => item && item.status === "面试中")
    .sort((a, b) => {
      const stageGap = getHiringStageIndex(b.hiringStage || "ATS筛选") - getHiringStageIndex(a.hiringStage || "ATS筛选");
      if (stageGap !== 0) return stageGap;
      return (b.chance || 0) - (a.chance || 0);
    });
}

function findInterviewApplicationByText(text, applications) {
  const content = normalizeText(text || "");
  if (!content) return null;
  return (
    applications.find((app) => {
      const company = normalizeText(app.company || "");
      const role = normalizeText(app.role || "");
      return (company && content.includes(company)) || (role && content.includes(role));
    }) || null
  );
}

function getCompanyByInterviewApplication(app) {
  if (!app) return null;
  return ALL_JOB_COMPANIES.find((company) => company.id === app.companyId) || null;
}

function getInterviewPriorityTags(app) {
  const role = String(app?.role || "").toLowerCase();
  const company = String(app?.company || "").toLowerCase();
  const companyProfile = getCompanyByInterviewApplication(app);
  const preferredTags = Array.isArray(app?.preferredTags) && app.preferredTags.length
    ? app.preferredTags
    : Array.isArray(companyProfile?.preferredTags)
      ? companyProfile.preferredTags
      : [];
  const tags = ["general", "behavioral"];

  const add = (value) => {
    if (!value) return;
    if (!tags.includes(value)) tags.push(value);
  };

  if (/engineer|developer|swe|backend|frontend|platform|systems|infrastructure/.test(role)) {
    add("technical");
    add("data");
  }
  if (/ml|ai|algorithm|scientist|research|bioinformatics|clinical data/.test(role)) {
    add("research");
    add("technical");
    add("data");
  }
  if (/product|program manager|pm|operations|growth/.test(role)) {
    add("product");
    add("business");
  }
  if (/finance|quant|investment|analyst|trading/.test(role)) {
    add("finance");
    add("business");
    add("data");
  }
  if (/legal|compliance|governance|policy/.test(role) || /legal|policy/.test(company)) {
    add("legal");
    add("policy");
  }
  if (/design|artist|ux|ui|creative/.test(role)) {
    add("design");
    add("product");
  }

  preferredTags.forEach((tag) => {
    if (tag === "科研") {
      add("research");
      add("technical");
      add("data");
    } else if (tag === "商业") {
      add("business");
      add("product");
      add("finance");
    } else if (tag === "人文") {
      add("policy");
      add("legal");
      add("behavioral");
    } else if (tag === "艺术") {
      add("design");
      add("product");
    }
  });

  return tags;
}

function buildInterviewQuestionPoolForApp(app) {
  const priorityTags = getInterviewPriorityTags(app);
  const role = String(app?.role || "").toLowerCase();
  const advancedRole =
    /research|scientist|phd|quant|ml|ai|legal|policy|compliance/.test(role) || (app?.difficulty || 0) >= 0.86;
  const scored = INTERVIEW_QUESTION_BANK.map((question) => {
    const qTags = Array.isArray(question?.tags) ? question.tags : [];
    let score = 0;
    priorityTags.forEach((tag, index) => {
      if (qTags.includes(tag)) {
        score += Math.max(1, 8 - index);
      }
    });
    if (qTags.includes("general")) score += 1.5;
    if (qTags.includes("behavioral")) score += 1;
    if (question?.id === "self_intro" || question?.id === "motivation") score += 2.6;
    if (question?.id === "project_ownership" || question?.id === "learning_speed") score += 1.4;
    const complexity = Number(question?.complexity || 1.5);
    score -= complexity * 1.6;
    if (!advancedRole && complexity >= 2.2) score -= 3.2;
    if (!advancedRole && qTags.includes("technical")) score -= 0.8;
    if (qTags.length === 0) score += 0.5;
    return { question, score };
  })
    .sort((a, b) => b.score - a.score)
    .map((item) => item.question);
  return scored.length ? scored : INTERVIEW_QUESTION_BANK;
}

function getInterviewCandidatePoolForIndex(pool, questionIndex, usedIds, usedTypes) {
  const available = pool.filter((item) => item && !usedIds.has(item.id));
  if (!available.length) return pool;

  const openerIds = new Set(["self_intro", "motivation", "project_ownership", "learning_speed", "collaboration_conflict", "future_plan"]);
  if (questionIndex === 0) {
    const openers = available.filter(
      (item) => openerIds.has(item.id) || ((item.type === "general" || item.type === "behavioral") && (item.complexity || 1.5) <= 1.5),
    );
    if (openers.length) return openers;
  }

  const preferredMaxComplexity = questionIndex === 0 ? 1.6 : 2.15;
  const preferred = available.filter(
    (item) => (item.complexity || 1.5) <= preferredMaxComplexity && !usedTypes.has(item.type || "general"),
  );
  if (preferred.length) return preferred;

  const easy = available.filter((item) => (item.complexity || 1.5) <= preferredMaxComplexity + 0.35);
  if (easy.length) return easy;
  return available;
}

function pickInterviewQuestionForApp(app, questionIndex) {
  if (!INTERVIEW_QUESTION_BANK.length) {
    return {
      id: "fallback",
      prompt: () => "请介绍你的核心优势以及与岗位的匹配点。",
      keywords: ["优势", "匹配", "项目", "结果"],
    };
  }
  const pool = buildInterviewQuestionPoolForApp(app);
  const seed = Math.abs(hashString(`${app?.companyId || "company"}-${app?.role || "role"}-${app?.interviewRound || 1}`));
  const step = 7;
  const targetIndex = Math.max(0, Math.round(questionIndex || 0));
  const used = new Set();
  const usedTypes = new Set();
  let picked = pool[0];
  for (let i = 0; i <= targetIndex; i += 1) {
    const candidatePool = getInterviewCandidatePoolForIndex(pool, i, used, usedTypes);
    let idx = (seed + i * step) % candidatePool.length;
    let guard = 0;
    while (guard < candidatePool.length && used.has(candidatePool[idx]?.id)) {
      idx = (idx + 1) % candidatePool.length;
      guard += 1;
    }
    const candidate = candidatePool[idx] || candidatePool[0] || pool[0];
    if (!candidate) break;
    const candidateType = candidate.type || "general";
    if (usedTypes.has(candidateType)) {
      const replacement = candidatePool.find(
        (item) => item && !used.has(item.id) && !usedTypes.has(item.type || "general"),
      ) || pool.find(
        (item) => item && !used.has(item.id) && !usedTypes.has(item.type || "general"),
      );
      if (replacement) {
        used.add(replacement.id);
        usedTypes.add(replacement.type || "general");
        picked = replacement;
        continue;
      }
    }
    used.add(candidate.id);
    usedTypes.add(candidateType);
    picked = candidate;
  }
  return picked || pool[0];
}

function getInterviewQuestionTypeLabel(question) {
  const type = question?.type || (Array.isArray(question?.tags) ? question.tags[0] : "") || "general";
  if (type === "technical") return "技术题";
  if (type === "behavioral") return "行为题";
  if (type === "case") return "案例题";
  if (type === "research") return "研究题";
  if (type === "business") return "商业题";
  return "综合题";
}

function getInterviewDimensionWeights(question) {
  const weights = { ...DEFAULT_INTERVIEW_DIMENSION_WEIGHTS, ...(question?.dimensions || {}) };
  const total = Object.values(weights).reduce((sum, value) => sum + Number(value || 0), 0) || 1;
  return Object.fromEntries(
    Object.entries(weights).map(([key, value]) => [key, clamp(Number(value || 0) / total, 0, 1)]),
  );
}

function evaluateInterviewAnswerContent(answer, question) {
  const text = (answer || "").trim();
  const keywords = Array.isArray(question?.keywords) ? question.keywords : [];
  if (!text) {
    return {
      score: 10,
      matched: 0,
      dimensions: { structure: 10, relevance: 8, evidence: 6, clarity: 12 },
      feedback: "回答过短，建议补充场景、行动和结果。",
    };
  }
  const normalized = text.toLowerCase();
  const matched = keywords.filter((word) => normalized.includes(String(word).toLowerCase())).length;
  const keywordRatio = keywords.length ? matched / keywords.length : 0.5;
  const keywordScore = keywordRatio * 100;
  const lengthScore = clamp(text.length / 90, 0, 1) * 100;
  const tokenList = (text.match(/[a-zA-Z0-9\u4e00-\u9fa5]+/g) || []).map((item) => item.toLowerCase());
  const uniqueTokenRatio = tokenList.length
    ? clamp(new Set(tokenList).size / tokenList.length, 0, 1)
    : 0.3;
  const diversityScore = uniqueTokenRatio * 100;
  const structureSignals = ["因为", "所以", "例如", "结果", "改进", "复盘", "挑战", "解决", "数据", "指标"];
  const structureHit = structureSignals.filter((token) => text.includes(token)).length;
  const starSignals = ["情境", "任务", "行动", "结果", "复盘", "目标", "影响", "权衡", "取舍", "后来", "最后"];
  const starHit = starSignals.filter((token) => text.includes(token)).length;
  const detailSignals = ["例如", "比如", "一次", "当时", "后来", "最后", "项目", "团队", "用户", "客户", "实验"];
  const detailHit = detailSignals.filter((token) => text.includes(token)).length;
  const structureScore = clamp(structureHit / 5 + starHit / 6 + detailHit / 8, 0, 1) * 100;
  const evidenceHit = (text.match(/(\d+%|\d+\.\d+%|\d+个月|\d+天|\d+周|\d+个|kpi|roi|ctr|a\/b|ab)/gi) || []).length;
  const evidenceScore = clamp(evidenceHit / 2 + detailHit / 6 + (text.includes("数据") ? 0.2 : 0), 0, 1) * 100;
  const keywordMentions = keywords.reduce((sum, word) => {
    const safe = String(word || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    if (!safe) return sum;
    const reg = new RegExp(safe, "gi");
    const hits = text.match(reg);
    return sum + (hits ? hits.length : 0);
  }, 0);
  const listyPattern = /[、,，/；;]+/.test(text) && text.length < 80;
  const templateCopy =
    /关键词建议|问题\s*\d+\/\d+|场景-任务-行动-结果-复盘/.test(text) ||
    /^\s*(匹配|经历|技能|贡献|结果|数据|结构|表达)[、,，/；;\s]+/.test(text);
  const stuffingPenalty = keywordMentions > keywords.length + 2 ? Math.min(18, (keywordMentions - keywords.length) * 2.2) : 0;
  const lowDiversityPenalty = uniqueTokenRatio < 0.42 ? (0.42 - uniqueTokenRatio) * 55 : 0;
  const templatePenalty = templateCopy ? 20 : 0;
  const listPenalty = listyPattern ? 8 : 0;
  const conciseBonus = text.length >= 18 && text.length <= 120 ? 8 : text.length <= 180 ? 4 : 0;
  const clarityPenalty =
    (text.length < 14 ? 0.2 : 0) +
    (/不知道|不清楚|没想好|不会|随便/.test(text) ? 0.36 : 0) +
    (/没做过|没有经验/.test(text) ? 0.24 : 0);
  const clarityScore = clamp(lengthScore / 100 - clarityPenalty + 0.42, 0, 1) * 100;
  const dimensions = {
    structure: Math.round(clamp(structureScore * 0.74 + detailHit * 4, 0, 100)),
    relevance: Math.round(clamp(keywordScore * 0.65 + lengthScore * 0.15 + detailHit * 4, 0, 100)),
    evidence: Math.round(clamp(evidenceScore * 0.6 + keywordScore * 0.15 + detailHit * 5, 0, 100)),
    clarity: Math.round(clamp(clarityScore + conciseBonus, 0, 100)),
  };
  const weights = getInterviewDimensionWeights(question);
  const weighted =
    dimensions.structure * (weights.structure || 0) +
    dimensions.relevance * (weights.relevance || 0) +
    dimensions.evidence * (weights.evidence || 0) +
    dimensions.clarity * (weights.clarity || 0);
  const diversityBlend = diversityScore * 0.1;
  let penalty = stuffingPenalty + lowDiversityPenalty + templatePenalty + listPenalty;
  if (text.length < 10) penalty += 12;
  else if (text.length < 18) penalty += 4;
  if (/不知道|不清楚|没想好|不会|随便/.test(text)) penalty += 16;
  if (/没做过|没有经验/.test(text)) penalty += 10;
  const score = clamp(Math.round(weighted + diversityBlend + conciseBonus - penalty), 8, 100);
  const weakest = Object.entries(dimensions).sort((a, b) => a[1] - b[1])[0]?.[0] || "structure";
  const feedback =
    score >= 80
      ? "回答简洁清楚，岗位匹配表达不错"
      : score >= 60
        ? `回答已达标，建议再补强${INTERVIEW_DIMENSION_LABELS[weakest] || "关键维度"}`
        : templatePenalty > 0 || stuffingPenalty > 0
          ? "关键词堆叠明显，建议改成自然表达和真实例子"
          : "说服力偏弱，建议用 2-4 句说清场景、做法和结果";
  return { score, matched, dimensions, feedback };
}

function getInterviewFocusForApplication(app) {
  const role = (app?.role || "").toLowerCase();
  if (/product|pm/.test(role)) {
    return "重点考察：问题拆解、用户价值和指标闭环。";
  }
  if (/research|scientist|ml|ai/.test(role)) {
    return "重点考察：研究深度、实验复盘和技术表达。";
  }
  if (/finance|investment|trading/.test(role)) {
    return "重点考察：商业判断、风险控制和数字敏感度。";
  }
  if (/designer|ux|ui/.test(role)) {
    return "重点考察：设计逻辑、用户洞察和迭代方法。";
  }
  return "重点考察：岗位匹配、问题解决和沟通结构。";
}

function buildInterviewQuestionPrompt(app, question, index) {
  const typeLabel = getInterviewQuestionTypeLabel(question);
  const weights = getInterviewDimensionWeights(question);
  const dimensionLine = Object.entries(weights)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 2)
    .map(([key]) => INTERVIEW_DIMENSION_LABELS[key] || key)
    .join(" / ");
  const questionText = question?.prompt ? question.prompt(app) : "请介绍你的岗位匹配优势。";
  return `问题 ${index + 1}/${INTERVIEW_SESSION_QUESTION_COUNT}（${typeLabel}）：${questionText} 简短回答即可：用 2-4 句说清场景、你的做法和结果/收获；有 1 个具体细节会更好。重点维度：${dimensionLine}。`.trim();
}

function buildInterviewEvalLine(evaluated, question) {
  const keywordTotal = Array.isArray(question?.keywords) ? question.keywords.length : 0;
  const hitLine = keywordTotal > 0 ? `关键词命中 ${evaluated.matched}/${keywordTotal}` : "关键词不计分";
  const dimensionLine = evaluated?.dimensions
    ? Object.entries(evaluated.dimensions)
        .map(([key, value]) => `${INTERVIEW_DIMENSION_LABELS[key] || key}${value}`)
        .join(" · ")
    : "";
  const actionLine =
    evaluated.score >= 80
      ? "继续保持这种简洁但具体的表达。"
      : evaluated.score >= 60
        ? "可再补 1 个具体结果或收获，会更有说服力。"
        : "建议下题用 2-4 句说清场景、做法和结果。";
  return `${evaluated.feedback}（${evaluated.score}分，${hitLine}${dimensionLine ? `，${dimensionLine}` : ""}）。${actionLine}`;
}

function buildInterviewFollowupPrompt(app, question, evaluated) {
  const role = app?.role || "目标岗位";
  if (evaluated.score < 42) {
    return `请用 2-4 句重答一次：说清场景、你的动作，以及结果或收获（最好和 ${role} 相关）。`;
  }
  const keywords = Array.isArray(question?.keywords) ? question.keywords.slice(0, 2) : [];
  if (keywords.length) {
    return `请补充一个细节：围绕“${keywords.join("、")}”再说具体一点。`;
  }
  return "请再补一句具体案例，强调你的行动和结果。";
}

function shouldAskInterviewFollowup(answer, evaluated, session, qIndex) {
  const followupMap = session?.questionFollowups && typeof session.questionFollowups === "object"
    ? session.questionFollowups
    : {};
  const asked = Number(followupMap[qIndex] || 0);
  if (asked >= INTERVIEW_MAX_FOLLOWUPS_PER_QUESTION) return false;
  const text = String(answer || "").trim();
  if (!text) return true;
  if (evaluated.score >= INTERVIEW_FOLLOWUP_SCORE_THRESHOLD) return false;
  if (/不知道|不清楚|没想好|不会|随便/.test(text)) return true;
  return text.length < 24 || evaluated.score < 54;
}

function mergeInterviewFollowupScore(baseScore, followupScore) {
  const bonus = followupScore > baseScore ? 4 : 0;
  return clamp(Math.round(baseScore * 0.4 + followupScore * 0.6 + bonus), 5, 100);
}

function buildInterviewDecisionReason(app, avgScore, passChance, passed) {
  const strengths = [];
  const risks = [];
  const majorFitPct = Math.round(clamp(app?.majorFit || 0, 0, 1) * 100);
  const difficultyLabel = app?.difficultyLabel || getJobDifficultyLabel(app?.difficulty || 0.7);

  if (avgScore >= 85) strengths.push("回答简洁清楚，例子具体且岗位相关");
  else if (avgScore >= 72) strengths.push("回答基本完整，表达和岗位匹配较好");
  else risks.push("回答说服力偏弱，案例细节或结果说明不足");

  if ((app?.majorFit || 0) >= 0.9) strengths.push("专业与岗位高度匹配");
  else if ((app?.majorFit || 0) >= 0.78) strengths.push("专业与岗位方向匹配");
  else risks.push("专业与岗位匹配度一般");

  if ((app?.difficulty || 0) >= 0.85 && avgScore < 80) {
    risks.push("岗位难度较高，当前回答深度未完全达到要求");
  }
  if (passChance < 0.5) {
    risks.push("综合通过概率偏低，竞争环境较强");
  }

  const positiveLine = strengths.length ? strengths.slice(0, 2).join("；") : "岗位基础匹配达标";
  const riskLine = risks.length ? risks.slice(0, 2).join("；") : "未发现显著短板";
  if (passed) {
    return `录用原因：${positiveLine}。评估备注：岗位匹配 ${majorFitPct}% · 难度 ${difficultyLabel}。`;
  }
  return `未录用原因：${riskLine}。评估备注：岗位匹配 ${majorFitPct}% · 难度 ${difficultyLabel}。`;
}

function finalizeInterviewByChat(app, session) {
  const scores = Array.isArray(session?.scores) ? session.scores : [];
  const avgScore = scores.length
    ? Math.round(scores.reduce((sum, value) => sum + value, 0) / scores.length)
    : 0;
  const careerSignals = getCareerSignalsForJob();
  const universitySignal = getCareerUniversitySignal();
  const answerSignal = clamp(avgScore / 100, 0, 1);
  const currentStage =
    typeof app.hiringStage === "string" && HIRING_PIPELINE_FLOW.includes(app.hiringStage)
      ? app.hiringStage
      : app.status === "面试中"
        ? "终面"
        : "技术面";
  const stageBonus = HIRING_STAGE_PASS_BONUS[currentStage] ?? 0;
  let passChance = clamp(
    (app.baseChance || app.chance || 0.25) * 0.5 +
      answerSignal * 0.46 +
      careerSignals.candidateSignal * 0.08 +
      careerSignals.degreeBonus * 0.16 +
      universitySignal * 0.04 +
      getJobDifficultyBias() * 0.26 -
      (app.difficulty || 0) * 0.05 +
      stageBonus,
    HIRING_CHAT_PASS_CHANCE_MIN,
    HIRING_CHAT_PASS_CHANCE_MAX,
  );
  if (avgScore >= 70) passChance = clamp(passChance + 0.04, HIRING_CHAT_PASS_CHANCE_MIN, HIRING_CHAT_PASS_CHANCE_MAX);
  if (avgScore <= 40) passChance = Math.min(passChance, 0.42);
  if (avgScore >= 88) passChance = Math.max(passChance, clamp(0.58 - (app.difficulty || 0) * 0.08, 0.4, 0.78));
  if (state.difficultyId === "relaxed") {
    passChance = clamp(passChance + 0.04, HIRING_CHAT_PASS_CHANCE_MIN, HIRING_CHAT_PASS_CHANCE_MAX);
  }
  if (state.difficultyId === "hard") {
    passChance = clamp(passChance - 0.02, HIRING_CHAT_PASS_CHANCE_MIN, HIRING_CHAT_PASS_CHANCE_MAX);
  }
  const passed = Math.random() <= passChance;
  const finalPassed = passed;
  const nextStage = finalPassed ? "录用" : currentStage;

  app.chatInterviewPending = false;
  app.interviewTranscript = [
    ...(Array.isArray(app.interviewTranscript) ? app.interviewTranscript : []),
    {
      round: app.interviewRound || state.jobOutcome?.interviewRound || 1,
      stage: currentStage,
      score: avgScore,
      chance: passChance,
      passed,
      ts: Date.now(),
    },
  ].slice(-6);
  app.chance = clamp((app.baseChance || app.chance || 0.25) * 0.82 + answerSignal * 0.18, 0.03, 0.98);
  app.hiringStage = nextStage;
  app.hiringHistory = [
    ...(Array.isArray(app.hiringHistory) ? app.hiringHistory : []),
    { stage: nextStage, at: Date.now(), pass: passed },
  ].slice(-10);
  app.interviewRound = Math.max(1, getHiringStageIndex(currentStage));
  app.status = finalPassed ? "录用" : "拒绝";
  const stageReason = formatHiringStageReason(nextStage);
  app.reason = finalPassed
    ? `${buildInterviewDecisionReason(app, avgScore, passChance, true)} · 流程结论：${stageReason}`
    : passed
      ? `通过当前轮次，已进入${nextStage}。流程说明：${stageReason}`
      : `${buildInterviewDecisionReason(app, avgScore, passChance, false)} · 流程结论：${stageReason}`;

  state.jobOutcome.applications = state.jobOutcome.applications
    .map((item) => (item.companyId === app.companyId ? app : item))
    .sort((a, b) => {
      const byStatus = (JOB_STATUS_ORDER[a.status] ?? 9) - (JOB_STATUS_ORDER[b.status] ?? 9);
      if (byStatus !== 0) return byStatus;
      return (b.chance || 0) - (a.chance || 0);
    });
  state.jobOutcome.interviewRound = Math.max(
    state.jobOutcome.interviewRound || 1,
    app.interviewRound || 1,
  );
  state.jobOutcome.score = careerSignals.candidateSignal;
  state.jobOutcome.universitySignal = universitySignal;
  state.jobOutcome.educationLabel = careerSignals.educationLabel;
  state.jobOutcome.majorName = careerSignals.majorName;
  buildJobOutcomeLines(state.jobOutcome, careerSignals);

  state.log.unshift(
    `交流室评估${passed ? "通过" : "未通过"}：${app.company} · ${app.role}（${avgScore}分，${currentStage} -> ${nextStage}）`,
  );
  if (!getPendingInterviewApplications().length) {
    state.log.unshift("交流室面试已全部完成。");
    pushReplayNode("交流室面试完成");
  }
  updateAchievements();
  updateUI();

  const passPct = Math.round(passChance * 100);
  if (finalPassed) {
    return `面试结论：通过并录用。${app.company} 综合评分 ${avgScore} 分（通过阈值概率 ${passPct}%）。${app.reason}`;
  }
  return `面试结论：未通过。${app.company} 综合评分 ${avgScore} 分（通过阈值概率 ${passPct}%）。${app.reason}`;
}

function isInterviewWithdrawIntent(text = "") {
  const normalized = String(text || "").toLowerCase();
  return INTERVIEW_WITHDRAW_KEYWORDS.some((keyword) => normalized.includes(String(keyword).toLowerCase()));
}

function rejectInterviewApplicationByUser(app, reasonText = "候选人主动放弃面试流程") {
  if (!app || !state.jobOutcome || !Array.isArray(state.jobOutcome.applications)) return "";
  app.status = "拒绝";
  app.hiringStage = "候选人放弃";
  app.chatInterviewPending = false;
  app.revealed = true;
  app.reason = `未录用原因：${reasonText}。流程结论：候选人主动终止。`;
  app.hiringHistory = [
    ...(Array.isArray(app.hiringHistory) ? app.hiringHistory : []),
    { stage: "候选人放弃", at: Date.now(), pass: false },
  ].slice(-10);
  app.interviewTranscript = [
    ...(Array.isArray(app.interviewTranscript) ? app.interviewTranscript : []),
    {
      round: app.interviewRound || state.jobOutcome.interviewRound || 1,
      stage: "候选人放弃",
      score: 0,
      chance: 0,
      passed: false,
      ts: Date.now(),
    },
  ].slice(-6);
  state.jobOutcome.applications = state.jobOutcome.applications
    .map((item) => (item.companyId === app.companyId ? app : item))
    .sort((a, b) => {
      const byStatus = (JOB_STATUS_ORDER[a.status] ?? 9) - (JOB_STATUS_ORDER[b.status] ?? 9);
      if (byStatus !== 0) return byStatus;
      return (b.chance || 0) - (a.chance || 0);
    });
  buildJobOutcomeLines(state.jobOutcome, {
    candidateSignal: state.jobOutcome.score || 0,
    educationLabel: state.jobOutcome.educationLabel || "毕业",
    majorName: state.jobOutcome.majorName || "未定专业",
  });
  state.log.unshift(`面试放弃：${app.company} · ${app.role}`);
  const pending = getPendingInterviewApplications().length;
  const offers = state.jobOutcome.applications.filter((item) => item.status === "录用").length;
  if (!pending && offers > 0) {
    state.log.unshift("你已放弃剩余面试，可直接选择最终工作。");
  }
  pushReplayNode("面试主动放弃");
  updateAchievements();
  updateUI();
  return offers > 0
    ? `已将 ${app.company} · ${app.role} 标记为拒绝。当前仍有 ${offers} 个录用，可直接选择最终工作。`
    : `已将 ${app.company} · ${app.role} 标记为拒绝。当前无录用岗位。`;
}

function generateInterviewerReply(userText, roleId = "interviewer") {
  const memoryLine = [maybeIncludeMemory(roleId), getRoleCardHint(roleId)].filter(Boolean).join(" ").trim();
  if (!state.jobOutcome || !Array.isArray(state.jobOutcome.applications) || !state.jobOutcome.applications.length) {
    return `${memoryLine} 当前没有求职投递记录，请先在求职阶段提交公司申请。`.trim();
  }
  const targetCompanyId = getInterviewerCompanyIdByRole(roleId);
  const targetApp = targetCompanyId
    ? state.jobOutcome.applications.find((item) => item.companyId === targetCompanyId) || null
    : null;

  const pendingApps = targetApp
    ? targetApp.status === "面试中"
      ? [targetApp]
      : []
    : getPendingInterviewApplications();

  if (isInterviewWithdrawIntent(userText)) {
    const toReject = targetApp?.status === "面试中" ? targetApp : pendingApps[0];
    if (toReject) {
      state.chatContext.interviewSession = null;
      return `${memoryLine} ${rejectInterviewApplicationByUser(toReject)}`.trim();
    }
  }

  if (!pendingApps.length) {
    if (targetApp) {
      if (Array.isArray(targetApp.interviewTranscript) && targetApp.interviewTranscript.length) {
        const latest = targetApp.interviewTranscript[targetApp.interviewTranscript.length - 1];
        return `${memoryLine} ${targetApp.company} · ${targetApp.role} 面试已结束，当前状态：${targetApp.status}（最近评分 ${latest.score} 分）。`.trim();
      }
      return `${memoryLine} ${targetApp.company} · ${targetApp.role} 当前没有进行中的面试流程。`.trim();
    }
    state.chatContext.interviewSession = null;
    return `${memoryLine} 当前没有待面试公司，结果已根据已完成问答更新。`.trim();
  }

  let session = state.chatContext.interviewSession;
  if (session && typeof session !== "object") {
    session = null;
  }
  const hasActiveSession =
    session &&
    pendingApps.some((item) => item.companyId === session.companyId) &&
    typeof session.questionIndex === "number";

  if (!hasActiveSession) {
    const picked = targetApp || findInterviewApplicationByText(userText, pendingApps) || pendingApps[0];
    const startedRound = picked.interviewRound || state.jobOutcome.interviewRound || 1;
    const focusLine = getInterviewFocusForApplication(picked);
    const openedByInvite = targetCompanyId && (picked.interviewerInviteRound || 0) >= startedRound;
    const looksLikeStart = /开始|start|hello|hi|你好|在吗/.test((userText || "").toLowerCase());
    if (openedByInvite && !looksLikeStart) {
      const firstQuestion = pickInterviewQuestionForApp(picked, 0);
      if (/不知道|不会|怎么答|没思路|不清楚/.test(String(userText || "").toLowerCase())) {
        state.chatContext.interviewSession = {
          companyId: picked.companyId,
          questionIndex: 0,
          scores: [],
          startedRound,
        };
        return `${memoryLine} ${focusLine} 你可以先这样答：用 2-4 句，先说场景，再说你的做法，最后说结果或收获。${buildInterviewQuestionPrompt(
          picked,
          firstQuestion,
          0,
        )}`.trim();
      }
      const firstEval = evaluateInterviewAnswerContent(userText, firstQuestion);
      state.chatContext.interviewSession = {
        companyId: picked.companyId,
        questionIndex: 1,
        scores: [firstEval.score],
        startedRound,
      };
      const nextQuestion = pickInterviewQuestionForApp(picked, 1);
      return `${memoryLine} ${focusLine} 回答评估：${buildInterviewEvalLine(
        firstEval,
        firstQuestion,
      )} ${buildInterviewQuestionPrompt(picked, nextQuestion, 1)}`.trim();
    }
    const nextSession = {
      companyId: picked.companyId,
      questionIndex: 0,
      scores: [],
      startedRound,
    };
    state.chatContext.interviewSession = nextSession;
    const question = pickInterviewQuestionForApp(picked, 0);
    return `${memoryLine} 已开始 ${picked.company} · ${picked.role} 的面试（第 ${nextSession.startedRound} 轮）。${focusLine} ${buildInterviewQuestionPrompt(
      picked,
      question,
      0,
    )}`.trim();
  }

  const currentApp = pendingApps.find((item) => item.companyId === session.companyId);
  if (!currentApp) {
    state.chatContext.interviewSession = null;
    return `${memoryLine} 当前面试对象状态已变化，请发送“开始面试”继续下一家。`.trim();
  }

  if (isInterviewWithdrawIntent(userText)) {
    state.chatContext.interviewSession = null;
    return `${memoryLine} ${rejectInterviewApplicationByUser(currentApp)}`.trim();
  }

  if (/下一家|换一|跳过/.test(userText)) {
    if (targetApp) {
      return `${memoryLine} 你当前在 ${targetApp.company} 联系人窗口，请直接继续作答。`.trim();
    }
    const nextApp = pendingApps.find((item) => item.companyId !== currentApp.companyId);
    if (!nextApp) {
      return `${memoryLine} 当前只剩 ${currentApp.company} 这家待面试，请继续回答问题。`.trim();
    }
    const nextSession = {
      companyId: nextApp.companyId,
      questionIndex: 0,
      scores: [],
      startedRound: nextApp.interviewRound || state.jobOutcome.interviewRound || 1,
    };
    state.chatContext.interviewSession = nextSession;
    const question = pickInterviewQuestionForApp(nextApp, 0);
    return `${memoryLine} 已切换到 ${nextApp.company} · ${nextApp.role}。${getInterviewFocusForApplication(
      nextApp,
    )} ${buildInterviewQuestionPrompt(nextApp, question, 0)}`.trim();
  }

  const qIndex = clamp(Math.round(session.questionIndex || 0), 0, INTERVIEW_SESSION_QUESTION_COUNT - 1);
  const question = pickInterviewQuestionForApp(currentApp, qIndex);
  if (/不知道|不会|怎么答|没思路|不清楚/.test(String(userText || "").toLowerCase())) {
    return `${memoryLine} 建议直接用 2-4 句回答：先讲场景，再讲你的做法，最后说结果或收获。${buildInterviewQuestionPrompt(
      currentApp,
      question,
      qIndex,
    )}`.trim();
  }

  const evaluated = evaluateInterviewAnswerContent(userText, question);
  const nextScores = Array.isArray(session.scores) ? [...session.scores, evaluated.score] : [evaluated.score];

  if (qIndex + 1 < INTERVIEW_SESSION_QUESTION_COUNT) {
    const nextIndex = qIndex + 1;
    state.chatContext.interviewSession = {
      ...session,
      questionIndex: nextIndex,
      scores: nextScores,
    };
    const nextQuestion = pickInterviewQuestionForApp(currentApp, nextIndex);
    return `${memoryLine} 回答评估：${buildInterviewEvalLine(evaluated, question)} ${buildInterviewQuestionPrompt(
      currentApp,
      nextQuestion,
      nextIndex,
    )}`.trim();
  }

  const finalText = finalizeInterviewByChat(currentApp, { ...session, scores: nextScores });
  state.chatContext.interviewSession = null;
  const remaining = getPendingInterviewApplications().length;
  return `${memoryLine} ${finalText}${
    remaining > 0 ? ` 还剩 ${remaining} 家待面试，可切换其他公司面试官继续。` : ""
  }`.trim();
}

function getGradProgramTypeLabel(programType) {
  if (programType === "phd") return "博士";
  if (programType === "msphd") return "硕博连读";
  return "硕士";
}

function generateAdmissionsReply(roleId, school, userText) {
  const memoryLine = [getMemoryLine(roleId), getRoleCardHint(roleId)].filter(Boolean).join(" ").trim();
  const worldLine = getWorldContextSummaryLine();
  if (state.termIndex < 6) {
    return `${memoryLine} 申请季才开放正式沟通渠道，请在申请季再联系。`;
  }

  const intent = detectIntent(userText);
  const undergradResult = getAdmissionsUndergradResult(school.id);
  const gradResult = getAdmissionsGradResult(school.id);
  const selectedInGrad = (state.gradSelectedSchools || []).includes(school.id);
  const pendingGradApply =
    state.termIndex === 7 &&
    !gradResult &&
    selectedInGrad &&
    ((state.postGradPath === POSTGRAD_PATHS.MASTERS && !state.mastersStarted) ||
      (state.postGradPath === POSTGRAD_PATHS.PHD && !state.phdStarted));
  const inMastersSchoolWindow = !!state.mastersSchoolId && state.mastersSchoolId === school.id && state.mastersStarted;
  const hasGradContext = !!gradResult || pendingGradApply || inMastersSchoolWindow;

  if (state.termIndex === 6) {
    if (isCombinedDegreeIntent(userText) || isCombinedDoctoralIntent(userText) || isMsPhdIntent(userText)) {
      return `${memoryLine} 连读申请仅在录取后开放，请放榜后再提交。`;
    }
    const roundChoice = getRoundChoiceForSchool(school.id);
    const evaluation = evaluateApplication(school, { preview: true, roundOverride: roundChoice });
    const fitPercent = Math.round(evaluation.fitScore * 100);
    const chance = Math.round(evaluation.chance * 100);
    const reasons = getDecisionReasons(school, evaluation, "候补", roundChoice);
    const tips = getImprovementTips(evaluation).slice(0, 2);
    const profile = getSchoolProfile(school);
    const focusLine = profile?.preferredTags?.length
      ? `我们通常关注：${profile.preferredTags.join(" / ")}。`
      : "我们关注学术准备、长期投入与专业匹配。";
    const styleLine = profile?.admissionsStyle ? `招生偏好：${profile.admissionsStyle}` : "";
    const opener = pickVariant(
      ["感谢你的来信。", "很高兴了解你的申请情况。", "我们已收到你的咨询。"],
      `admissions-${school.id}-opener`,
    );
    return `${opener} ${memoryLine} ${school.name} 目前匹配度 ${fitPercent} / 100（${describeFitLevel(
      evaluation.fitScore,
    )}），预计录取机会约 ${chance}%。评估重点：${reasons.join("、") || "综合评估"}。${
      tips.length ? `建议优先补强：${tips.join("；")}。` : ""
    }${focusLine}${
      styleLine ? ` ${styleLine}` : ""
    } ${worldLine}`;
  }

  if (hasGradContext) {
    if (isMsPhdIntent(userText)) {
      return handleMsPhdRequest(roleId, school, gradResult);
    }
    if (isCombinedDoctoralIntent(userText)) {
      return `${memoryLine} 本硕博连读仅在本科录取后向最终本科去向学校申请。`;
    }
    if (isCombinedDegreeIntent(userText)) {
      return `${memoryLine} 本硕连读属于本科录取后通道，请在本科去向学校窗口申请。`;
    }
    if (intent.combinedProgram) {
      return `${memoryLine} 当前正处于硕博连读开放窗口（硕士入学前、第一学期或最后两个学期），可直接点击自动申请按钮或发送“申请硕博连读”。`;
    }
    if (isAppealIntent(userText)) {
      if (!gradResult) {
        return `${memoryLine} 当前没有可申诉的研究生结果。`;
      }
      return handleGradAdmissionsAppeal(roleId, school, gradResult, userText);
    }
    if (pendingGradApply) {
      const programType = state.postGradPath === POSTGRAD_PATHS.PHD ? "phd" : "masters";
      const applyMajorId = getGradApplyMajorIdForProgramType(programType);
      const chanceRaw =
        programType === "phd"
          ? evaluatePhdChance(school, { majorId: applyMajorId })
          : evaluateMastersChance(school, { programMode: programType, majorId: applyMajorId });
      const chance = Math.round(chanceRaw * 100);
      const fit = Math.round(calculateFitScore(school, applyMajorId) * 100);
      const tipProgram = programType === "phd" ? "phd" : "masters";
      const weakTips = getGradProfileWeaknessTips(tipProgram, 2);
      return `${memoryLine} ${school.name} ${getGradProgramTypeLabel(programType)}通道（${getMajorName(
        applyMajorId,
      )}）预估匹配 ${fit} / 100，机会约 ${chance}%。${
        weakTips.length ? `当前建议：${weakTips.join("；")}。` : "建议优先完善研究主线、推荐与陈述。"
      } ${worldLine}`;
    }

    let currentGradResult = gradResult;
    if (!currentGradResult && inMastersSchoolWindow) {
      const syntheticProgramType = state.mastersProgramType || "masters";
      const syntheticMajorId = state.mastersMajorId || state.mastersApplyMajorId || state.majorId;
      const syntheticChance = evaluateMastersChance(school, {
        programMode: state.mastersProgramType === "msphd" ? "msphd" : "masters",
        majorId: syntheticMajorId,
      });
      const syntheticAid = calculateGraduateAidOffer(school, "masters", {
        programType: syntheticProgramType === "msphd" ? "msphd" : "masters",
        majorId: syntheticMajorId,
        chance: syntheticChance,
      });
      currentGradResult = {
        id: school.id,
        name: school.name,
        status: "录取",
        programType: syntheticProgramType,
        chance: syntheticChance,
        majorId: syntheticMajorId,
        majorName: getMajorName(syntheticMajorId),
        aidPercent: syntheticAid.aidPercent,
        netCost: syntheticAid.netCost,
        tuition: syntheticAid.tuition,
        scholarshipLabel: syntheticAid.scholarshipLabel,
        revealed: true,
      };
    }
    if (!currentGradResult) {
      return `${memoryLine} 当前没有 ${school.name} 的研究生申请记录。`;
    }
    if (currentGradResult.revealed === false) {
      return `${memoryLine} 请先拆开 ${school.name} 的研究生结果邮件。`;
    }

    const programLabel = getGradProgramTypeLabel(currentGradResult.programType);
    const chancePct = Math.round(clamp(currentGradResult.chance ?? 0.1, 0, 1) * 100);
    const scholarshipLine =
      currentGradResult.status === "录取"
        ? buildScholarshipSummaryLine(currentGradResult.aidPercent, currentGradResult.netCost, currentGradResult.tuition)
        : "";
    const reasonLine =
      currentGradResult.reason ||
      (currentGradResult.status === "录取"
        ? "学术与研究潜力匹配。"
        : currentGradResult.status === "候补"
          ? "整体竞争激烈，暂处候补。"
          : "当前综合指标未达到该项目阈值。");
    if (intent.results || /为什么|原因|why|拒绝|候补/.test(userText)) {
      const tipProgram = currentGradResult.programType === "phd" ? "phd" : "masters";
      const weakTips = getGradProfileWeaknessTips(tipProgram, 2);
      return `${memoryLine} 关于 ${school.name} ${programLabel}结果：${currentGradResult.status}。主要原因：${reasonLine}${
        scholarshipLine ? ` ${scholarshipLine}。` : ""
      }${
        weakTips.length ? ` 后续建议：${weakTips.join("；")}。` : ""
      }`;
    }
    if (intent.school || intent.major || intent.stageProgress) {
      const tipProgram = currentGradResult.programType === "phd" ? "phd" : "masters";
      const weakTips = getGradProfileWeaknessTips(tipProgram, 2);
      const majorId = getValidMajorId(currentGradResult.majorId || getGradApplyMajorIdForProgramType(currentGradResult.programType));
      return `${memoryLine} ${school.name} ${programLabel}匹配度参考：${Math.round(
        (currentGradResult.fitScore ?? calculateFitScore(school, majorId)) * 100,
      )}/100，专业 ${getMajorName(majorId)}，状态 ${currentGradResult.status}。${
        scholarshipLine ? `${scholarshipLine}。` : ""
      }${
        weakTips.length ? `建议：${weakTips.join("；")}。` : "建议保持研究输出连续性。"
      } `;
    }
    const tipLine =
      currentGradResult.status === "拒绝"
        ? "建议补强研究输出、项目深度与推荐信强度后再冲刺。"
        : currentGradResult.status === "候补"
          ? "建议补充新成果并保持沟通，提升候补转正概率。"
          : "建议继续保持学术与研究稳定输出，便于后续奖助续评。";
    return `${memoryLine} ${school.name} ${programLabel}当前状态：${currentGradResult.status}（预估机会 ${chancePct}%）。${
      scholarshipLine ? `${scholarshipLine}。` : ""
    }${tipLine}`;
  }

  const result = undergradResult;
  if (!result) {
    return `${memoryLine} 你的申请名单中没有 ${school.name} 的记录。`;
  }
  const evaluation = evaluateApplication(school, { preview: true, roundOverride: result.roundChoice });
  if (isCombinedDoctoralIntent(userText)) {
    return handleCombinedDoctoralRequest(roleId, school, result);
  }
  if (isMsPhdIntent(userText)) {
    return `${memoryLine} 硕博连读属于硕士阶段通道，请在硕士录取学校招生窗口申请。`;
  }
  if (isCombinedDegreeIntent(userText) || intent.combinedProgram) {
    return handleCombinedDegreeRequest(roleId, school, result);
  }
  if (isAppealIntent(userText)) {
    return handleAdmissionsAppeal(roleId, school, result, userText);
  }
  if (intent.results || /为什么|原因|why|拒绝|候补/.test(userText)) {
    const reasons = result.reasons?.length
      ? result.reasons
      : getDecisionReasons(school, evaluation, result.status, result.roundChoice);
    const prefix = pickVariant(
      ["我们理解你的关切。", "这是个常见问题。", "感谢你认真地追问。"],
      `admissions-${school.id}-result`,
    );
    return `${prefix} ${memoryLine} 关于 ${school.name} 的结果：${result.status}。主要考量：${
      reasons.join("、") || "综合评估与名额限制"
    }。`;
  }
  if (intent.school || intent.major || intent.stageProgress) {
    const chancePct = Math.round(clamp(result.chance ?? evaluation.chance ?? 0, 0, 1) * 100);
    const tips = result.tips?.length ? result.tips.slice(0, 2) : getImprovementTips(evaluation).slice(0, 2);
    return `${memoryLine} ${school.name} 当前状态 ${result.status}，匹配度 ${Math.round((result.fitScore || 0) * 100)} / 100，参考机会 ${chancePct}%。${
      tips.length ? `建议：${tips.join("；")}。` : "建议保持持续投入。"
    }`;
  }

  const tips = result.tips?.length ? result.tips : getImprovementTips(evaluation);
  const fitPercent = Math.round(result.fitScore * 100);
  const appealHint =
    (result.status === "候补" || result.status === "拒绝") &&
    !hasAdmissionsAppeal(getAdmissionsAppealKey("undergrad", school.id), school.id)
      ? "如需复核，请补充新增成果并在申诉附件槽位上传有效证明。"
      : "";
  const closer = pickVariant(
    ["如需补充材料，请说明新增成果。", "如有更新，我们会记录在案。", "祝你后续进展顺利。"],
    `admissions-${school.id}-closer`,
  );
  return `${memoryLine} ${school.name} 当前结果：${result.status}，匹配度 ${fitPercent} / 100（${describeFitLevel(
    result.fitScore,
  )}）。${tips.length ? `建议：${tips.join("；")}` : "建议保持持续投入。"} ${appealHint} ${worldLine} ${closer}`;
}

function generateReply(roleId, userText) {
  if (!state.started) {
    return "先完成起点设置并开始旅程，我才能结合你的数据给建议。";
  }
  if (isInterviewerRole(roleId)) {
    const intent = detectIntent(userText);
    const roleState = advanceRoleDialogueState(roleId, intent, userText);
    const statePrefix = buildStatefulReplyPrefix(roleId, roleState);
    const reply = generateInterviewerReply(userText, roleId);
    state.chatContext.lastRole = roleId;
    state.chatContext.lastIntent = intent;
    return statePrefix ? `${statePrefix} ${reply}` : reply;
  }
  if (isAdmissionsRole(roleId)) {
    const school = getAdmissionsSchoolByRole(roleId);
    if (!school) {
      return "该招生委员会目前不可用，请在申请季选择学校后再联系。";
    }
    const intent = detectIntent(userText);
    const roleState = advanceRoleDialogueState(roleId, intent, userText);
    const statePrefix = buildStatefulReplyPrefix(roleId, roleState);
    clearAdmissionsDialogueSession(roleId);
    const reply = generateAdmissionsReply(roleId, school, userText);
    state.chatContext.lastRole = roleId;
    state.chatContext.lastIntent = intent;
    return statePrefix ? `${statePrefix} ${reply}` : reply;
  }
  const intent = detectIntent(userText);
  const weakness = getWeaknessSummary().join("、");
  const strength = getStrengthSummary().join("、");
  const stress = Math.round(state.stats.stress);
  const cash = formatUsd(state.cash);
  const timeLine = `${state.timeUsed} / ${state.timeBudget}`;
  const worldLine = getWorldContextSummaryLine();
  const memoryLine = [maybeIncludeMemory(roleId), getRoleCardHint(roleId)].filter(Boolean).join(" ").trim();
  const roleState = advanceRoleDialogueState(roleId, intent, userText);
  const statePrefix = buildStatefulReplyPrefix(roleId, roleState);
  const modeHint = `${statePrefix ? `${statePrefix} ` : ""}${roleState.pendingTask ? `下一步：${roleState.pendingTask} ` : ""}`;
  state.chatContext.lastRole = roleId;
  state.chatContext.lastIntent = intent;
  const lastQuestion = consumeFollowUp();

  if (roleId === "counselor") {
    const digest = buildJourneyDigestLine();
    if (lastQuestion) {
      if (intent.school) {
        return `${memoryLine} 明白。你刚才提的“${lastQuestion.text}”会影响选校结构，我先给你一个平衡方案，再根据你的偏好微调。`;
      }
      if (intent.finance) {
        return `${memoryLine} 收到。关于“${lastQuestion.text}”，我会把预算当作硬约束来做规划。`;
      }
      if (intent.project) {
        return `${memoryLine} 收到。你对“${lastQuestion.text}”的回答会影响主线项目，我会优先做长期主线。`;
      }
      return `${memoryLine} 收到。关于“${lastQuestion.text}”，我先给你一个初版方案。`;
    }
    if (intent.greet) {
      const q = "你现在最想先解决哪一块：选校、文书、项目还是预算？";
      recordFollowUp(q);
      return `${modeHint}${memoryLine} 我在。${digest} ${worldLine} ${q}`;
    }
    if (intent.planTerm) {
      const higherEdStage = getActiveHigherEdStage();
      const result = higherEdStage ? planHigherEdTermWithAI(higherEdStage) : planTermWithAI();
      if (higherEdStage) {
        setHigherEdActionNote(higherEdStage, result.message);
      } else if (aiPlanNote) {
        aiPlanNote.textContent = result.message;
      }
      return result.message;
    }
    if (intent.planSchool) {
      if (getActiveHigherEdStage()) {
        return `${memoryLine} 当前处于在读阶段，选校规划仅在申请季开放。`;
      }
      const result = planSchoolListWithAI();
      if (aiSchoolNote) aiSchoolNote.textContent = result.message;
      return result.message;
    }
    if (intent.planEssay) {
      if (getActiveHigherEdStage()) {
        return `${memoryLine} 当前处于在读阶段，文书分配仅在申请季开放。`;
      }
      const result = assignEssaysWithAI();
      if (aiEssayNote) aiEssayNote.textContent = result.message;
      return result.message;
    }
    if (intent.compare) {
      const mentioned = findSchoolsByText(userText, 2);
      if (mentioned.length >= 2) {
        return `${memoryLine} 对比结果：${compareSchoolsForReply(mentioned[0], mentioned[1])}`;
      }
      return `${memoryLine} 你可以直接输入两所学校名，我会给你匹配度、录取机会和净费用对比。`;
    }
    if (intent.checklist) {
      const steps = buildExecutionChecklist(3);
      return `${modeHint}${memoryLine} 给你一个可执行清单：1) ${steps[0]} 2) ${steps[1] || "完成后回到我这复盘"} 3) ${
        steps[2] || "再根据结果微调策略"
      }`;
    }
    if (intent.postAdmit && state.termIndex === 7) {
      if (!state.finalChoice) {
        return `${memoryLine} 先确定最终去向，再做签证/住宿/奖助谈判会更有效。`;
      }
      const remaining = POST_ADMIT_ACTIONS.filter((item) => !state.postAdmitActionsUsed.has(item.id));
      return `${memoryLine} 录取后建议优先顺序：签证准备 -> 住宿锁位 -> 奖助谈判。当前可执行 ${remaining.length} 项。`;
    }
    if (intent.interview && state.postGradPath === POSTGRAD_PATHS.JOB) {
      const waiting = getPendingInterviewApplications().length;
      if (!state.jobOutcome) {
        return `${memoryLine} 先提交公司投递，生成面试池后再去交流室找“面试官”。`;
      }
      if (!waiting) {
        return `${memoryLine} 当前没有待面试公司，结果已固定。`;
      }
      return `${memoryLine} 当前还有 ${waiting} 家待面试。请切换到对应公司的“面试官”联系人，按问题结构作答完成评估。`;
    }
    if (intent.combinedProgram && state.termIndex === 7) {
      if (!state.finalChoice) return `${memoryLine} 先确定最终去向，再向该校招生办申请连读通道。`;
      const chosen = getFinalChoiceResult();
      if (!chosen || chosen.status !== "录取") return `${memoryLine} 当前没有可申请连读的录取学校。`;
      if (state.combinedDegreeApproved || state.directPhdApproved) return `${memoryLine} 你已通过连读预审，可以直接推进后续培养规划。`;
      const chosenSchool = UNIVERSITIES.find((school) => school.id === chosen.id) || chosen;
      const actions = getAdmissionsQuickActions(`admissions-${chosen.id}`, chosenSchool);
      if (!actions.length) {
        return `${memoryLine} 当前不在连读申请开放窗口。入学前和最后两个学期可再到该校招生委员会窗口提交。`;
      }
      return `${memoryLine} 你已具备申请资格，切换到“招生委员会 · ${chosen.name}”可直接点击：${actions
        .map((action) => action.label)
        .join(" / ")}。`;
    }
    if (intent.stageProgress || intent.graduate || intent.career) {
      const higherEdStage = getActiveHigherEdStage();
      if (higherEdStage) {
        return `${modeHint}${memoryLine} ${buildJourneyDigestLine()} ${buildHigherEdTermFocusLine(higherEdStage)} ${worldLine}`;
      }
      if (state.postGradPath === POSTGRAD_PATHS.JOB) {
        const apps = state.jobOutcome?.applications || [];
        const pending = apps.filter((item) => item.status === "面试中").length;
        return `${modeHint}${memoryLine} 求职阶段：已投递 ${apps.length} 家，待面试 ${pending} 家。建议先完成所有面试问答再选最终 Offer。${worldLine}`;
      }
      return `${modeHint}${memoryLine} ${buildJourneyDigestLine()} 建议先按当前阶段的关键动作推进。${worldLine}`;
    }
    if (intent.incident) {
      const higherEdStage = getActiveHigherEdStage();
      if (higherEdStage) {
        return `${memoryLine} 当前阶段会触发随机意外事件，建议预留至少 ${formatUsd(2200)} 机动资金并保留 1 点时间冗余。${worldLine}`;
      }
      return `${memoryLine} 意外事件主要影响资金、时间和压力，建议不要把预算和时间点数用满。${worldLine}`;
    }
    if (intent.appeal && state.termIndex === 7) {
      return `${memoryLine} 申诉要点：先补“有效更新”再发信，附件优先成绩/成果/推荐，捐款仅在有更新时才计入加成。`;
    }
    if (intent.project) {
      const higherEdStage = getActiveHigherEdStage();
      if (higherEdStage) {
        return `${memoryLine} ${buildHigherEdTermFocusLine(higherEdStage)}`;
      }
      const recommendation = getCounselorEventRecommendation();
      const mini = getMiniActionSuggestions(2);
      const miniLine = mini.length ? `小行动：${mini.join(" / ")}` : "";
      return `${memoryLine} ${recommendation.line} ${miniLine}`.trim();
    }
    if (intent.round) {
      const top = buildSchoolSuggestions();
      return `${memoryLine} 轮次策略：先走 ED（仅 1 所）再走 RD（多校）。ED 更看匹配与稳定性，RD 用于分散风险。${top}`;
    }
    if (intent.test) {
      return `${memoryLine} 标化方面建议集中冲刺 1-2 次，配合申请季行动补分。当前标化 ${Math.round(
        state.stats.test,
      )}，目标可设在 1350+。`;
    }
    if (intent.aid) {
      return `${memoryLine} 奖助策略可以结合家庭预算和录取概率，低收入背景有额外加成。你可以优先考虑 need-based。`;
    }
    if (intent.loan) {
      return `${memoryLine} 可以申请贷款解燃眉之急，但会计利息并增加压力，建议控制次数。`;
    }
    if (intent.gapYear) {
      return `${memoryLine} 再读一年会花费 ${formatUsd(EXTRA_YEAR_COST)}，压力 +${EXTRA_YEAR_STRESS}；若现金不够，会自动记入贷款，但你可以重刷成果。`;
    }
    if (intent.donation) {
      return `${memoryLine} 申诉时可选择捐款滑条，捐款越多加成越高，但需要有更新材料才生效。`;
    }
    if (intent.major) {
      const major = MAJORS.find((item) => item.id === state.majorId);
      return `${memoryLine} 当前意向专业是 ${major?.name || "未定"}，建议把项目和文书围绕这个主线打穿。`;
    }
    if (intent.time) {
      const higherEdStage = getActiveHigherEdStage();
      if (higherEdStage) {
        const termState = getHigherEdStageTermState(higherEdStage);
        const selectedEvents = (termState.currentEvents || []).filter((item) => (termState.selectedEventIds || []).includes(item.id));
        const selectedMini = getHigherEdMiniActions(higherEdStage).filter((item) => (termState.selectedMiniIds || []).includes(item.id));
        const used =
          selectedEvents.reduce((sum, item) => sum + getHigherEdEventTime(higherEdStage, item), 0) +
          selectedMini.reduce((sum, item) => sum + Number(item.time || 0), 0);
        return `${memoryLine} 当前${getHigherEdStageLabel(higherEdStage)}学期时间点数 ${used} / ${termState.timeBudget}。建议至少留 1 点冗余应对意外。`;
      }
      return `${memoryLine} 当前时间点数 ${state.timeUsed} / ${state.timeBudget}。建议优先高性价比项目。`;
    }
    if (intent.school) {
      const opener = pickVariant(
        ["我们先把选校结构搭好。", "选校策略我来帮你拆解。", "我们先把组合做成三档。"],
        "counselor-school",
      );
      const follow = formatFollowUp(roleId, intent);
      if (follow) recordFollowUp(follow);
      return `${modeHint}${opener} ${memoryLine} ${buildSchoolSuggestions()} 你的优势在 ${strength}，短板是 ${weakness}。${digest}${follow ? ` ${follow}` : ""}`;
    }
    if (intent.essay) {
      const opener = pickVariant(
        ["文书要有清晰主线。", "文书是你的叙事核心。", "文书要把你的优势放大。"],
        "counselor-essay",
      );
      return `${opener} ${memoryLine} 优先补强 ${weakness}，同时突出 ${strength}。文书进度 ${
        state.stats.essayTrack ?? 0
      } / 100。`;
    }
    if (intent.finance) {
      const opener = pickVariant(
        ["预算是策略的一部分。", "资金安排会影响整体节奏。", "我们先把现金流梳理清楚。"],
        "counselor-finance",
      );
      const follow = "你预算上限大概是多少？";
      recordFollowUp(follow);
      return `${modeHint}${opener} ${memoryLine} 当前可用资金 ${cash}，建议控制高成本项目频次，合理利用奖学金策略。${digest} ${follow}`;
    }
    if (intent.stress) {
      const opener = pickVariant(
        ["节奏稳住更重要。", "别把压力顶太高。", "先把可持续性放在第一位。"],
        "counselor-stress",
      );
      const follow = "你更想降压力还是保住进度？";
      recordFollowUp(follow);
      return `${opener} ${memoryLine} 你当前压力 ${stress}，建议减少高强度项目，留出时间点数（${timeLine}）。${buildCounselorAdvice(
        intent,
      )} ${digest} ${follow}`;
    }
    if (intent.results) {
      if (state.postGradPath === POSTGRAD_PATHS.JOB && state.jobOutcome) {
        const apps = state.jobOutcome.applications || [];
        const offer = apps.filter((item) => item.status === "录用").length;
        const pending = apps.filter((item) => item.status === "面试中").length;
        return `${modeHint}${memoryLine} 求职结果：录用 ${offer} 家，待面试 ${pending} 家。建议先完成待面试再确定最终工作。`;
      }
      if ((state.postGradPath === POSTGRAD_PATHS.MASTERS || state.postGradPath === POSTGRAD_PATHS.PHD) && Array.isArray(state.gradResults) && state.gradResults.length) {
        const admits = state.gradResults.filter((item) => item.status === "录取").length;
        const waits = state.gradResults.filter((item) => item.status === "候补").length;
        return `${modeHint}${memoryLine} 研究生结果：录取 ${admits} 所、候补 ${waits} 所。建议先拆完全部邮件再决定去向。`;
      }
      const admitCount = state.results.filter((result) => result.status === "录取").length;
      const waitlistCount = state.results.filter((result) => result.status === "候补").length;
      const follow = "你想优先冲候补，还是准备再读一年？";
      recordFollowUp(follow);
      return `${modeHint}${memoryLine} 当前结果：录取 ${admitCount} 所、候补 ${waitlistCount} 所。可以考虑候补更新与申诉策略。${digest} ${follow}`;
    }
    if (intent.complaint) {
      return `${modeHint}${memoryLine} 明白你的感受。我们可以先把目标缩小到一件最紧急的事：选校、文书或项目，你想先抓哪个？`;
    }
    const opener = pickVariant(
      ["我们先把策略框架搭起来。", "我会把路线拆成可执行的步骤。", "我帮你把节奏和目标拉齐。"],
      `counselor-general-${roleState.turns % 3}`,
    );
    const follow = formatFollowUp(roleId, intent);
    if (follow) recordFollowUp(follow);
    return `${modeHint}${opener} ${memoryLine} 我可以帮你做选校、文书、预算规划。${buildCounselorAdvice(
      intent,
    )} ${digest} ${worldLine} 现在优势是 ${strength}，短板是 ${weakness}。${follow ? ` ${follow}` : ""}`;
  }

  if (roleId === "family") {
    const digest = buildJourneyDigestLine();
    const familyHint = statePrefix ? `${statePrefix} ` : "";
    if (lastQuestion) {
      return `${memoryLine} 好的，我记下你对“${lastQuestion.text}”的回答了。我们一起稳住。`;
    }
    if (intent.checklist) {
      const steps = buildExecutionChecklist(3);
      return `${familyHint}${memoryLine} 家庭视角下的优先顺序：1) ${steps[0]} 2) ${steps[1] || "控制预算"} 3) ${
        steps[2] || "注意休息"
      }`;
    }
    if (intent.postAdmit && state.termIndex === 7) {
      return `${memoryLine} 录取后先把签证和住宿办稳，再看课程与奖助细节。`;
    }
    if (intent.stageProgress || intent.graduate || intent.career) {
      return `${familyHint}${memoryLine} ${buildJourneyDigestLine()} 先把当前阶段的关键节点做完，我们再看下一阶段。`;
    }
    if (intent.incident) {
      return `${memoryLine} 意外事件来了也别慌，先保资金安全和身心状态，再决定是否冲高风险选项。`;
    }
    if (intent.combinedProgram) {
      return `${memoryLine} 连读通道能省申请成本，但门槛高，建议先确认资格，再准备博士或就业备选。`;
    }
    if (intent.loan) {
      return `${memoryLine} 贷款会有利息和压力，尽量作为兜底方案。我们一起算一下预算更稳。`;
    }
    if (intent.gapYear) {
      return `${memoryLine} 再读一年会增加成本和压力，但如果能明显补短板，也值得讨论。`;
    }
    if (intent.project) {
      return `${memoryLine} 项目别贪多，稳住节奏更重要。你现在优势在 ${strength}。`;
    }
    if (intent.finance) {
      const opener = pickVariant(["我们最在意预算可控。", "钱的安排要稳。", "别让资金压力拖累节奏。"], "family-finance");
      return `${opener} ${memoryLine} 目前资金 ${cash}。可以优先选择性价比高的项目，减少不必要支出。${digest}`;
    }
    if (intent.stress) {
      const opener = pickVariant(["我们有点心疼你。", "别把自己逼太紧。", "身体和心态更重要。"], "family-stress");
      return `${opener} ${memoryLine} 看到你最近压力 ${stress}，适当休息也很重要。`;
    }
    if (intent.results) {
      return `${memoryLine} 结果只是阶段性的，别否定自己。我们会一起想办法。`;
    }
    const opener = pickVariant(["我们一直支持你。", "别担心，我们在你身后。", "你已经很努力了。"], "family-general");
    const follow = formatFollowUp(roleId, intent);
    if (follow) recordFollowUp(follow);
    return `${familyHint}${opener} ${memoryLine} 但也希望你注意节奏。${digest} 优势是 ${strength}，短板是 ${weakness}，一起稳住。${
        follow ? ` ${follow}` : ""
      }`;
  }

  if (roleId === "teacher") {
    const teacherHint = statePrefix ? `${statePrefix} ` : "";
    const major = MAJORS.find((item) => item.id === state.majorId);
    if (lastQuestion) {
      return `${memoryLine} 收到你对“${lastQuestion.text}”的回答。接下来建议用一个可量化成果去验证。`;
    }
    if (intent.project) {
      return `${teacherHint}${memoryLine} 先把项目做“深”而不是做“多”。建议围绕 ${major?.name || "当前专业"} 完成一条完整产出链：问题定义→方法→结果→反思。`;
    }
    if (intent.essay) {
      return `${teacherHint}${memoryLine} 文书建议用“问题-行动-结果-复盘”结构，并用具体证据支撑，不要只写感受。`;
    }
    if (intent.results) {
      return `${teacherHint}${memoryLine} 结果背后通常是证据强度与叙事一致性。你可以补一项高质量更新材料再行动。`;
    }
    if (intent.interview || intent.career) {
      return `${teacherHint}${memoryLine} 面试回答建议遵循 STAR：情境、任务、行动、结果，最后补一句反思与迁移。`;
    }
    if (intent.major || intent.school) {
      return `${teacherHint}${memoryLine} 目标是让活动、文书和推荐形成同一条学术主线，避免“广而散”。`;
    }
    if (intent.checklist) {
      return `${teacherHint}${memoryLine} 本周建议：1) 完成一项可展示成果 2) 写出 150 字复盘 3) 找到一位可验证成果的推荐人。`;
    }
    return `${teacherHint}${memoryLine} 从老师视角看，你当前优势是 ${strength}，短板是 ${weakness}。建议优先补短板并保留证据。`;
  }

  if (roleId === "peer") {
    const digest = buildJourneyDigestLine();
    const peerHint = statePrefix ? `${statePrefix} ` : "";
    if (lastQuestion) {
      return `${memoryLine} 了解，你刚才对“${lastQuestion.text}”的回答挺关键的，我们再一起看看下一步。`;
    }
    if (intent.compare) {
      const mentioned = findSchoolsByText(userText, 2);
      if (mentioned.length >= 2) {
        return `${memoryLine} 我帮你看了：${compareSchoolsForReply(mentioned[0], mentioned[1])}`;
      }
      return `${memoryLine} 你发两所学校名，我帮你做快速对比。`;
    }
    if (intent.checklist) {
      const steps = buildExecutionChecklist(3);
      return `${peerHint}${memoryLine} 我会这么排：1) ${steps[0]} 2) ${steps[1] || "再补一项短板"} 3) ${
        steps[2] || "最后复盘"
      }`;
    }
    if (intent.project) {
      return `${memoryLine} 项目这块我觉得“长期主线”最重要，你现在可以集中打穿一个方向。`;
    }
    if (intent.stageProgress || intent.graduate || intent.career) {
      return `${peerHint}${memoryLine} ${buildJourneyDigestLine()} 我建议你先把这学期重点项目锁满，再补 1-2 个小行动。`;
    }
    if (intent.incident) {
      return `${memoryLine} 突发事件一般是钱和时间被打乱，先保主线项目别断。`;
    }
    if (intent.combinedProgram) {
      return `${memoryLine} 连读通道如果能过会省事，但你也要准备博士和就业备选方案。`;
    }
    if (intent.test) {
      return `${memoryLine} 标化我最近也在刷，感觉冲刺一两次最有效。`;
    }
    if (intent.round) {
      return `${memoryLine} 我会先选 1 所 ED，再把其余目标放到 RD。`;
    }
    if (intent.school) {
      const opener = pickVariant(
        ["最近大家都在聊选校。", "同学们冲刺校挺多的。", "听说今年竞争又卷了。"],
        "peer-school",
      );
      return `${peerHint}${opener} ${memoryLine} 保底也要选 2 所。${digest} 你可以试试 ${buildSchoolSuggestions()}`;
    }
    if (intent.results) {
      const opener = pickVariant(["放榜季太刺激了。", "最近大家都很紧张。", "结果出来那刻真的心跳。"], "peer-results");
      return `${opener} ${memoryLine} 你现在优势在 ${strength}，加油。`;
    }
    if (intent.complaint) {
      return `${memoryLine} 我也觉得有点难，但我们可以先把一个小目标做完。`;
    }
    const opener = pickVariant(["最近大家都在拼。", "我们班气氛有点卷。", "我也在赶文书。"], "peer-general");
    const follow = formatFollowUp(roleId, intent);
    if (follow) recordFollowUp(follow);
    return `${peerHint}${opener} ${memoryLine} ${digest} 我觉得你优势在 ${strength}。一起冲！${follow ? ` ${follow}` : ""}`;
  }

  return "我在这儿，随时可以聊。";
}

function sendChat() {
  if (!chatInput || !chatRole) return;
  if (chatSendBusy) return;
  const text = chatInput.value.trim();
  if (!text) return;
  const roleId = chatRole.value || "counselor";
  chatInput.value = "";
  void processChatTurn(roleId, text).catch((error) => {
    setChatAiStatus(`发送失败：${error.message || "未知错误"}`);
  });
}

function renderProjectProgress() {
  if (!projectProgress) return;
  projectProgress.innerHTML = "";
  if (!state.started) {
    projectProgress.innerHTML = `<p class="note">旅程开始后显示长期项目进度。</p>`;
    return;
  }
  const projectLabels = {
    "research-track": "科研主线",
    "writing-archive": "写作专栏",
    "art-portfolio": "作品集",
    "startup-track": "创业项目",
    "impact-project": "社区影响力",
  };
  const entries = Object.entries(projectLabels).map(([key, label]) => {
    const value = state.projectStreaks[key] || 0;
    return { key, label, value };
  });
  entries.forEach((entry) => {
    const item = document.createElement("div");
    item.className = "project-item";
    const percent = Math.min(100, entry.value * 25);
    item.innerHTML = `
      <span>${entry.label} · 连续 ${entry.value} 学期</span>
      <div class="project-bar"><span style="width:${percent}%"></span></div>
    `;
    projectProgress.appendChild(item);
  });
}

function getMainViewStage() {
  if (!state.started) return "setup";
  if (state.termIndex <= 5) return "highschool";
  if (state.termIndex === 6) return "application";
  if (state.termIndex !== 7) return "highschool";
  if ((isEdReleaseStage() || isRdReleaseStage()) && !state.finalChoice && !state.undergradStarted && !state.undergradGraduated) {
    return "release";
  }

  if (!state.finalChoice && !state.undergradStarted && !state.undergradGraduated) {
    return "release";
  }
  if (!state.undergradStarted || !state.undergradGraduated) {
    return "undergrad";
  }
  if (state.mastersStarted && !state.mastersGraduated) {
    return "masters";
  }
  if (state.phdStarted && !state.phdGraduated) {
    return "phd";
  }
  if (state.postGradPath === POSTGRAD_PATHS.JOB || !!state.jobOutcome) {
    return "career";
  }
  return "grad";
}

function getMemoryLimitForRole(roleId) {
  if (isAdmissionsRole(roleId)) {
    return toPositiveInt(CHAT_MEMORY_LIMIT_BY_ROLE.admissions, 8);
  }
  if (isInterviewerRole(roleId)) {
    return toPositiveInt(CHAT_MEMORY_LIMIT_BY_ROLE.interviewer, 8);
  }
  if (roleId === "counselor") {
    return toPositiveInt(CHAT_MEMORY_LIMIT_BY_ROLE.counselor, 10);
  }
  if (roleId === "family") {
    return toPositiveInt(CHAT_MEMORY_LIMIT_BY_ROLE.family, 8);
  }
  if (roleId === "peer") {
    return toPositiveInt(CHAT_MEMORY_LIMIT_BY_ROLE.peer, 8);
  }
  if (roleId === "teacher") {
    return toPositiveInt(CHAT_MEMORY_LIMIT_BY_ROLE.teacher, 8);
  }
  return toPositiveInt(CHAT_MEMORY_LIMIT_BY_ROLE.default, 8);
}

function resolveActionStageNoticeElement(actionKey) {
  const map = {
    confirmTerm: eventNotice,
    submitApplications: appNotice,
    releaseNextResultBatch: releaseNote,
    resolveWaitlist: waitlistNote,
    openOfferDialog: offerNote,
    startUndergradJourney: undergradNote,
    choosePostGradPath: postGradNote,
    submitMastersApplications: postGradNote,
    submitPhdApplications: postGradNote,
    chooseGraduateOffer: postGradNote,
    submitJobApplications: postGradNote,
    advanceInterviewRound: postGradNote,
    revealNextGradResult: gradReleaseNote,
    revealNextCareerResult: careerReleaseNote,
    chooseFinalJobOffer: careerReleaseNote,
    confirmUndergradTerm: undergradEventNotice,
    confirmMastersTerm: mastersEventNotice,
    confirmPhdTerm: phdEventNotice,
  };
  return map[actionKey] || null;
}

function guardActionByMainStage(actionKey, customMessage = "") {
  const allowedStages = Array.isArray(STATE_MACHINE_GUARDS[actionKey]) ? STATE_MACHINE_GUARDS[actionKey] : [];
  if (!allowedStages.length) return true;
  const currentStage = getMainViewStage();
  if (allowedStages.includes(currentStage)) return true;
  const target = resolveActionStageNoticeElement(actionKey);
  if (target) {
    const readableAllowed = allowedStages.join(" / ");
    target.textContent =
      customMessage || `当前阶段不可执行该操作（当前 ${currentStage}，需 ${readableAllowed}）。`;
  }
  return false;
}

function enforceStateMachineConsistency() {
  if (!state.started) return;

  if (state.termIndex <= 5 && state.applicationStage !== APPLICATION_STAGES.ED_APPLY) {
    state.applicationStage = APPLICATION_STAGES.ED_APPLY;
    state.resultReleaseStage = "early";
  }

  if (!state.undergradGraduated && state.postGradPath === POSTGRAD_PATHS.PHD) {
    state.postGradPath = null;
    state.gradApplicationType = null;
  }

  if (state.postGradPath === POSTGRAD_PATHS.PHD && !state.mastersGraduated && !state.phdStarted) {
    state.postGradPath = null;
    state.gradApplicationType = null;
  }

  if (state.postGradPath === POSTGRAD_PATHS.JOB && !state.undergradGraduated && !state.devMode) {
    state.postGradPath = null;
    state.jobSelectedCompanies = [];
    state.jobOutcome = null;
  }

  if (!state.mastersStarted && state.mastersGraduated) {
    state.mastersStarted = true;
  }
  if (!state.phdStarted && state.phdGraduated) {
    state.phdStarted = true;
  }

  if (state.jobOutcome && !Array.isArray(state.jobOutcome.applications)) {
    state.jobOutcome = null;
  }
}

function renderPhase() {
  if (!state.started) {
    termLabel.textContent = "等待启程";
    termHint.textContent = "选择起点背景后开始旅程。";
    progressBar.style.width = "0%";
    progressText.textContent = `0 / ${TERMS.length}`;
    return;
  }

  const stageView = getMainViewStage();
  if (stageView === "undergrad") {
    const currentTerm = state.undergradStarted ? getCurrentUndergradTerm() : 0;
    termLabel.textContent = state.undergradStarted ? `本科第 ${currentTerm} 学期` : "本科阶段准备";
    termHint.textContent = state.undergradStarted
      ? "本科阶段独立界面：每学期最多 2 个重点项目 + 小行动。"
      : "已进入本科流程，可启动 8 学期培养。";
    const progress = state.undergradStarted ? (currentTerm / UNDERGRAD_TOTAL_TERMS) * 100 : 0;
    progressBar.style.width = `${progress}%`;
    progressText.textContent = `${currentTerm} / ${UNDERGRAD_TOTAL_TERMS}`;
    termTimeInfo.textContent = "本科阶段：每学期 2 个重点项目 + 小行动";
    return;
  }

  if (stageView === "grad") {
    if (!state.postGradPath) {
      termLabel.textContent = "毕业后规划";
      termHint.textContent = "请选择硕士或就业路径（博士需硕士后申请）。";
      progressBar.style.width = "0%";
      progressText.textContent = "0 / 1";
      termTimeInfo.textContent = "研究生阶段：先确定路径再申请";
      return;
    }
    if (state.postGradPath === POSTGRAD_PATHS.PHD) {
      const revealed = (state.gradResults || []).filter((item) => item.revealed).length;
      const total = (state.gradResults || []).length;
      termLabel.textContent = total ? "博士放榜季" : "博士申请季";
      termHint.textContent = total ? "请先拆完所有博士结果邮件，再决定去向。" : "选择博士目标学校并提交申请。";
      progressBar.style.width = `${total ? (revealed / Math.max(total, 1)) * 100 : 0}%`;
      progressText.textContent = total ? `${revealed} / ${total}` : "0 / 1";
      termTimeInfo.textContent = "研究生阶段：申请与放榜独立进行";
      return;
    }
    const revealed = (state.gradResults || []).filter((item) => item.revealed).length;
    const total = (state.gradResults || []).length;
    termLabel.textContent = total ? "硕士放榜季" : "硕士申请季";
    termHint.textContent = total ? "请先拆完所有硕士结果邮件，再决定去向。" : "选择硕士目标学校并提交申请。";
    progressBar.style.width = `${total ? (revealed / Math.max(total, 1)) * 100 : 0}%`;
    progressText.textContent = total ? `${revealed} / ${total}` : "0 / 1";
    termTimeInfo.textContent = "研究生阶段：申请与放榜独立进行";
    return;
  }

  if (stageView === "masters") {
    const currentTerm = getCurrentMastersTerm();
    termLabel.textContent = `硕士第 ${currentTerm} 学期`;
    termHint.textContent = "硕士阶段独立界面：课程、科研与论文并行。";
    progressBar.style.width = `${(currentTerm / MASTERS_TOTAL_TERMS) * 100}%`;
    progressText.textContent = `${currentTerm} / ${MASTERS_TOTAL_TERMS}`;
    termTimeInfo.textContent = "硕士阶段：每学期 2 个重点项目 + 小行动";
    return;
  }

  if (stageView === "phd") {
    const currentTerm = getCurrentPhdTerm();
    termLabel.textContent = `博士第 ${currentTerm} 学期`;
    termHint.textContent = "博士阶段独立界面：课题、发表与教学协同推进。";
    progressBar.style.width = `${(currentTerm / PHD_TOTAL_TERMS) * 100}%`;
    progressText.textContent = `${currentTerm} / ${PHD_TOTAL_TERMS}`;
    termTimeInfo.textContent = "博士阶段：每学期 2 个重点项目 + 小行动";
    return;
  }

  if (stageView === "career") {
    const total = state.jobOutcome?.applications?.length || 0;
    const revealed = (state.jobOutcome?.applications || []).filter((item) => item.revealed).length;
    const chosen = !!state.jobOutcome?.chosenOfferCompanyId;
    termLabel.textContent = chosen ? "终局结算" : total ? "求职放榜季" : "求职申请季";
    termHint.textContent = chosen
      ? "已确认最终工作，可查看全流程结算回顾。"
      : total
        ? "逐封拆开求职结果邮件，并完成交流室面试。"
        : "选择目标岗位并提交投递。";
    progressBar.style.width = `${chosen ? 100 : total ? (revealed / Math.max(total, 1)) * 100 : 0}%`;
    progressText.textContent = chosen ? "已完成" : total ? `${revealed} / ${total}` : "0 / 1";
    termTimeInfo.textContent = chosen ? "终局：工作确认与全流程结算" : "求职阶段：投递、拆邮件、面试问答";
    return;
  }

  const term = TERMS[state.termIndex] || TERMS[TERMS.length - 1];
  termLabel.textContent = term.name;
  termHint.textContent = term.hint;
  if (state.termIndex <= 6) {
    termTimeInfo.textContent = `时间点数：${state.timeUsed} / ${state.timeBudget}`;
  }
  const progress = ((state.termIndex + 1) / TERMS.length) * 100;
  progressBar.style.width = `${progress}%`;
  progressText.textContent = `${state.termIndex + 1} / ${TERMS.length}`;
}

function addNarrativePulse() {
  const pool = [
    "同学之间的比较让你重新思考自己的节奏。",
    "一个突如其来的机会让你短暂松了一口气。",
    "家庭的一次谈话让你更明确自己的方向。",
    "你开始意识到压力管理和效率同样重要。",
  ];
  if (Math.random() > 0.35) return;
  const line = pool[Math.floor(Math.random() * pool.length)];
  state.log.unshift(`叙事节点：${line}`);
}

function updateUI() {
  enforceStateMachineConsistency();
  maybeAutoSettleEdWaitlistsForRdRelease();
  normalizeWorldState();
  normalizeNarrativeState();
  renderPhase();
  renderStats();
  renderTimeline();
  renderLog();
  renderAdvisor();
  renderRouteFeedback();
  renderProjectProgress();
  renderAchievements();
  renderLegacyPanel();
  renderDevPanel();
  renderFileModeBanner();
  pushInterviewerProactiveMessages("reminder");
  initChatRoles();
  flushPendingCombinedAnnouncements();
  triggerPendingAdmissionsCombinedPrompt();
  renderChat();
  renderSavePanel();

  const mainViewStage = getMainViewStage();
  const showEvents = state.started && mainViewStage === "highschool";
  eventArea.classList.toggle("hidden", !showEvents);
  if (showEvents) {
    renderEvents();
    updateEventCount();
    if (aiPlanNote && !aiPlanNote.textContent) {
      aiPlanNote.textContent = "可用 AI 自动规划本学期。";
    }
  } else {
    eventNotice.textContent = "";
    if (aiPlanNote) aiPlanNote.textContent = "";
    if (fxNote) fxNote.textContent = "";
  }

  const showApplications = state.started && mainViewStage === "application";
  applicationArea.classList.toggle("hidden", !showApplications);
  if (showApplications) {
    const stage = getApplicationStage();
    const stageRound = getCurrentApplicationRound();
    if (stage === APPLICATION_STAGES.ED_APPLY && state.selectedSchools.size > 1) {
      const [first] = Array.from(state.selectedSchools);
      state.selectedSchools = new Set(first ? [first] : []);
    }
    state.defaultRoundChoice = stageRound;
    if (applicationTitle) {
      applicationTitle.textContent =
        stage === APPLICATION_STAGES.ED_APPLY ? "ED 申请阶段" : "RD 申请阶段";
    }
    if (applicationSubtitle) {
      applicationSubtitle.textContent =
        stage === APPLICATION_STAGES.ED_APPLY
          ? "先选择 1 所 ED 学校并提交，放榜后再进入 RD。"
          : "ED 放榜已完成，当前为 RD 选校与提交阶段。";
    }
    if (schoolPanelTitle) {
      schoolPanelTitle.textContent =
        stage === APPLICATION_STAGES.ED_APPLY ? "选择 ED 学校（仅 1 所）" : "选择 RD 学校（不限）";
    }
    if (roundStageTitle) {
      roundStageTitle.textContent = "当前申请轮次";
    }
    if (roundStageNote) {
      roundStageNote.textContent =
        stage === APPLICATION_STAGES.ED_APPLY
          ? "ED 阶段轮次固定为 Early Decision。"
          : "RD 阶段轮次固定为 Regular Decision。";
    }
    if (submitAppBtn) {
      submitAppBtn.textContent =
        stage === APPLICATION_STAGES.ED_APPLY ? "提交 ED 申请" : "提交 RD 申请";
    }
    if (state.timeBudget === 0) {
      state.timeBudget = getApplicationTimeBudget();
      state.timeUsed = 0;
    }
    renderChoices();
    renderSchoolList();
    updateSchoolCount();
    renderAppChecklist();
    if (aiSchoolNote && !aiSchoolNote.textContent) {
      aiSchoolNote.textContent =
        stage === APPLICATION_STAGES.ED_APPLY
          ? "可用 AI 生成 1 所 ED 候选学校。"
          : "可用 AI 生成 RD 多校草案。";
    }
    if (aiEssayNote && !aiEssayNote.textContent) {
      aiEssayNote.textContent = "可用 AI 自动分配文书主题。";
    }
  } else {
    appNotice.textContent = "";
    dataNotice.textContent = "";
    if (aiSchoolNote) aiSchoolNote.textContent = "";
    if (aiEssayNote) aiEssayNote.textContent = "";
    if (appChecklist) appChecklist.innerHTML = "";
  }

  const showResults = state.started && mainViewStage === "release";
  resultsArea.classList.toggle("hidden", !showResults);
  if (showResults) {
    const stage = getApplicationStage();
    if (resultsTitle) {
      resultsTitle.textContent =
        stage === APPLICATION_STAGES.ED_RELEASE
          ? "ED 放榜"
          : stage === APPLICATION_STAGES.RD_RELEASE
            ? "RD 放榜"
            : "放榜季结果";
    }
    if (resultsSubtitle) {
      resultsSubtitle.textContent =
        stage === APPLICATION_STAGES.ED_RELEASE
          ? "先拆完 ED 邮件；若为候补/拒绝，可在交流室切换到对应学校招生委员会，通过聊天窗复议。"
          : stage === APPLICATION_STAGES.RD_RELEASE
            ? "RD 邮件按学校逐封查看；若为候补/拒绝，可在交流室切换到对应学校招生委员会，通过聊天窗复议。"
            : "所有申请结果已进入复盘阶段；候补/拒绝仍可在交流室通过聊天窗复议。";
    }
    renderResults();
  }

  if (state.started && state.termIndex === 7) {
    renderUndergradPanel();
  } else if (undergradPanel) {
    undergradPanel.classList.add("hidden");
    if (postGradPanel) postGradPanel.classList.add("hidden");
    if (mastersArea) mastersArea.classList.add("hidden");
    if (mastersPanel) mastersPanel.classList.add("hidden");
    if (phdArea) phdArea.classList.add("hidden");
    if (phdPanel) phdPanel.classList.add("hidden");
  }

  if (collegeArea || gradArea || mastersArea || phdArea || careerArea) {
    const showCollege = mainViewStage === "undergrad";
    if (collegeArea) {
      collegeArea.classList.toggle("hidden", !showCollege);
    }
    const showGrad = mainViewStage === "grad";
    if (gradArea) {
      gradArea.classList.toggle("hidden", !showGrad);
    }
    const showMasters = mainViewStage === "masters";
    if (mastersArea) {
      mastersArea.classList.toggle("hidden", !showMasters);
    }
    const showPhd = mainViewStage === "phd";
    if (phdArea) {
      phdArea.classList.toggle("hidden", !showPhd);
    }
    const showCareer = mainViewStage === "career";
    if (careerArea) {
      careerArea.classList.toggle("hidden", !showCareer);
    }
    if (!showCareer && careerResultsGrid) {
      careerResultsGrid.innerHTML = "";
    }
    if (!showGrad && gradResultsGrid) {
      gradResultsGrid.innerHTML = "";
    }
  }
}

