function buildReportSection(title, lines = []) {
  return {
    title,
    lines: Array.isArray(lines) ? lines.filter((line) => !!line) : [],
  };
}

function formatReportPercent(value, fallback = "--") {
  if (!Number.isFinite(Number(value))) return fallback;
  return `${Math.round(Number(value) * 100)}%`;
}

function summarizeApplicationResults(results) {
  const list = Array.isArray(results) ? results : [];
  const total = list.length;
  const revealed = list.filter((item) => item?.revealed).length;
  const admit = list.filter((item) => item?.status === "录取").length;
  const wait = list.filter((item) => item?.status === "候补").length;
  const reject = list.filter((item) => item?.status === "拒绝").length;
  return { total, revealed, admit, wait, reject };
}

function buildProfessionalFinalReportSections() {
  const profile = PROFILES.find((item) => item.id === state.profileId);
  const background = BACKGROUNDS.find((item) => item.id === state.backgroundId);
  const region = REGIONS.find((item) => item.id === state.regionId);
  const counselor = COUNSELORS.find((item) => item.id === state.counselorId);
  const major = MAJORS.find((item) => item.id === state.majorId);
  const difficulty = DIFFICULTY_LEVELS.find((item) => item.id === state.difficultyId);
  const testPlan = TEST_PLAN_CHOICES.find((item) => item.id === state.testPlanId);
  const finalSchool = getFinalChoiceResult();
  const undergrad = state.undergradProfile || getDefaultUndergradProfile();
  const masters = state.mastersProfile || getDefaultMastersProfile();
  const phd = state.phdProfile || getDefaultPhdProfile();
  const undergradFeeLifetime = summarizeUndergradApplicationFees();
  const undergradFeeCurrentCycle = summarizeUndergradApplicationFees(getCurrentUndergradApplicationCycle());
  const applicationSummary = summarizeApplicationResults(state.results);
  const gradSummary = summarizeApplicationResults(state.gradResults);
  const calibration = state.balanceCalibration || null;
  const structure = getSelectedSchoolStructureProfile();
  const jobApps = Array.isArray(state.jobOutcome?.applications) ? state.jobOutcome.applications : [];
  const jobOfferCount = jobApps.filter((item) => item.status === "录用").length;
  const jobInterviewCount = jobApps.filter((item) => item.status === "面试中").length;
  const jobRejectCount = jobApps.filter((item) => item.status === "拒绝").length;
  const chosenJob =
    state.jobOutcome?.chosenOfferCompanyId && jobApps.length
      ? jobApps.find(
          (item) => item.companyId === state.jobOutcome.chosenOfferCompanyId && item.status === "录用",
        ) || null
      : null;

  const sections = [];
  sections.push(
    buildReportSection("基础档案", [
      `姓名：${state.playerName || "未填写"}`,
      `画像：${profile?.name || "未选择"} / ${background?.name || "未选择"} / ${region?.name || "未选择"}`,
      `难度：${difficulty?.name || "未选择"} · 中介：${counselor?.name || "未选择"}`,
      `主专业：${major?.name || "未选择"} · 标化策略：${testPlan?.name || "未选择"}`,
      state.backgroundId === "legacy"
        ? `Legacy 院校：${state.legacySchoolName || "未分配"}`
        : "Legacy 院校：无",
    ]),
  );

  sections.push(
    buildReportSection("申请结果", [
      `本科申请：已查看 ${applicationSummary.revealed}/${applicationSummary.total} · 录取 ${applicationSummary.admit} / 候补 ${applicationSummary.wait} / 拒绝 ${applicationSummary.reject}`,
      `选校结构：${structure.summary}（${structure.label}）`,
      finalSchool
        ? `本科最终去向：${finalSchool.name}（${finalSchool.status}${
            finalSchool.aidPercent ? ` · 奖助 ${Math.round(finalSchool.aidPercent * 100)}%` : ""
          }）`
        : "本科最终去向：未确定",
      `研究生申请：已查看 ${gradSummary.revealed}/${gradSummary.total} · 录取 ${gradSummary.admit} / 候补 ${gradSummary.wait} / 拒绝 ${gradSummary.reject}`,
      calibration
        ? `平衡校准：录取 ${formatReportPercent(calibration.admitRate)} · 候补 ${formatReportPercent(
            calibration.waitlistRate,
          )} · 建议 ${calibration.suggestion || "无"}`
        : "平衡校准：未运行",
    ]),
  );

  sections.push(
    buildReportSection("阶段成长", [
      `本科：${state.undergradStarted ? (state.undergradGraduated ? "已毕业" : "进行中") : "未开始"} · GPA ${Number(
        undergrad.gpa || 0,
      ).toFixed(2)} · 科研 ${Math.round(undergrad.research || 0)} · 实习 ${Math.round(undergrad.internship || 0)} · 领导力 ${Math.round(
        undergrad.leadership || 0,
      )}`,
      `硕士：${state.mastersStarted ? (state.mastersGraduated ? "已毕业" : "进行中") : "未开始"} · GPA ${Number(
        masters.gpa || 0,
      ).toFixed(2)} · 科研 ${Math.round(masters.research || 0)} · 论文 ${Math.round(masters.thesis || 0)}`,
      `博士：${state.phdStarted ? (state.phdGraduated ? "已毕业" : "进行中") : "未开始"} · 研究 ${Math.round(
        phd.research || 0,
      )} · 发表 ${Math.round(phd.publication || 0)} · 教学 ${Math.round(phd.teaching || 0)}`,
      `连读状态：本硕 ${state.combinedDegreeApproved ? "通过" : state.combinedDegreeApplied ? "已申请未通过" : "未申请"} · 硕博 ${
        state.msPhdApproved ? "通过" : state.msPhdApplied ? "已申请未通过" : "未申请"
      } · 直博 ${state.directPhdApproved ? "通过" : state.directPhdApplied ? "已申请未通过" : "未申请"}`,
    ]),
  );

  const dominantRoute = getDominantRouteProfile();
  const routeScores = getSortedRouteEntries();
  const recentCombos = (state.comboHistory || []).slice(0, 3);
  sections.push(
    buildReportSection("路线画像", [
      dominantRoute.id
        ? `当前主路线：${dominantRoute.label}${dominantRoute.second ? ` · 次路线 ${dominantRoute.second.label}` : ""}`
        : "当前主路线：尚未成型",
      routeScores.length
        ? `路线强度：${routeScores.map((item) => `${item.short} ${Math.round(item.value)}`).join(" / ")}`
        : "路线强度：暂无",
      recentCombos.length
        ? `最近组合技：${recentCombos
            .map((item) => `${item.label}（${item.stage === "highschool" ? "高中" : getHigherEdStageLabel(item.stage)}）`)
            .join("；")}`
        : "最近组合技：尚未触发",
      `专业偏好：${major?.name || "未定"} 当前更偏向 ${dominantRoute.label || "综合积累"}。`,
    ]),
  );

  sections.push(
    buildReportSection("财务结算", [
      `当前资金：${formatUsd(state.cash || 0)} · 贷款余额：${formatUsd(state.loanBalance || 0)}`,
      `本科申请费累计：${formatUsd(undergradFeeLifetime.total)}（本申请季 ED ${formatUsd(
        undergradFeeCurrentCycle.ed,
      )} + RD ${formatUsd(undergradFeeCurrentCycle.rd)}）`,
      `汇率系数：x${Number(state.fxRate || 1).toFixed(2)} · 过劳债务：${state.overworkDebt || 0} · 再读一年：${state.extraYearCount || 0} 次`,
      `学业支持：录取后行动 ${state.postAdmitActionsUsed?.size || 0} 项 · 奖助自动发放（按学校等级与实力匹配）`,
    ]),
  );

  const world = state.worldState || createDefaultWorldState();
  const sandbox = state.worldSandbox || createDefaultWorldSandboxState();
  const worldHistory = (state.worldHistory || []).slice(0, 3);
  const sandboxHistory = (state.worldSandboxHistory || []).slice(0, 3);
  const activeArcs = (state.storyArcs?.active || []).slice(0, 2);
  const storyHistory = (state.storyArcs?.history || []).slice(0, 3);
  const sandboxTop = WORLD_SANDBOX_REGION_CODES.map((regionCode) => {
    const row = sandbox?.[regionCode] || { admission: 50, graduate: 50, career: 50 };
    const score = Math.round((Number(row.admission || 50) + Number(row.graduate || 50) + Number(row.career || 50)) / 3);
    return { regionCode, score };
  }).sort((a, b) => b.score - a.score).slice(0, 2);
  sections.push(
    buildReportSection("世界状态与剧情", [
      `世界信号：签证 ${Math.round(world.visaEase)} / 政策 ${Math.round(world.policySupport)} / 行业 ${Math.round(
        world.industryBoom,
      )} / 经济 ${Math.round(world.economyStrength)}`,
      sandboxTop.length
        ? `地区沙盘：${sandboxTop
            .map((item) => `${getSandboxRegionLabel(item.regionCode)} ${item.score}`)
            .join("；")}`
        : "地区沙盘：无",
      activeArcs.length
        ? `进行中剧情链：${activeArcs
            .map(
              (item) =>
                `${getStoryArcDefinition(item.id)?.title || item.id}（${item.stage === "highschool" ? "高中" : getHigherEdStageLabel(item.stage)}第 ${
                  item.dueTerm
                } 学期）`,
            )
            .join("；")}`
        : "进行中剧情链：无",
      worldHistory.length
        ? `最近世界动态：${worldHistory.map((item) => item.title || item.source).join("；")}`
        : "最近世界动态：无",
      sandboxHistory.length
        ? `最近地区动态：${sandboxHistory.map((item) => item.title || item.source).join("；")}`
        : "最近地区动态：无",
      getCurrentWorldTailwinds(2).length
        ? `当前顺风：${getCurrentWorldTailwinds(2).join("；")}`
        : "当前顺风：无明显外部加成",
      getCurrentWorldHeadwinds(2).length
        ? `当前逆风：${getCurrentWorldHeadwinds(2).join("；")}`
        : "当前逆风：无明显外部压力",
      storyHistory.length
        ? `剧情回顾：${storyHistory.map((item) => `${item.label || item.id}（${item.result || "完成"}）`).join("；")}`
        : "剧情回顾：无",
    ]),
  );

  sections.push(
    buildReportSection("就业结论", [
      state.jobOutcome
        ? `投递 ${jobApps.length} 家 · 录用 ${jobOfferCount} / 面试中 ${jobInterviewCount} / 拒绝 ${jobRejectCount}`
        : "尚未进入就业阶段",
      chosenJob
        ? `最终工作：${chosenJob.company} · ${chosenJob.role} · 薪资 ${formatUsd(chosenJob.salaryLow)} - ${formatUsd(
            chosenJob.salaryHigh,
          )}`
        : state.jobOutcome?.bestOfferCompany
          ? `最佳录用：${state.jobOutcome.bestOfferCompany}（尚未确认最终工作）`
          : state.jobOutcome
            ? "当前无可确认 Offer"
            : "",
      state.jobOutcome
        ? `综合信号：${state.jobOutcome.educationLabel || "学历未定"} · 专业 ${state.jobOutcome.majorName || "未定"} · 候选强度 ${Math.round(
            Number(state.jobOutcome.score || 0) * 100,
          )}`
        : "",
      state.seasonRun?.finished
        ? `赛季结算：${Number(state.seasonRun.score || 0)} 分 · 挑战完成 ${
            Array.isArray(state.seasonRun.completedChallenges) ? state.seasonRun.completedChallenges.length : 0
          }/${SEASON_CHALLENGES.length} · 排名 ${
            state.seasonRun.leaderboardRank ? `#${state.seasonRun.leaderboardRank}` : "--"
          }`
        : "赛季结算：未完成",
    ]),
  );

  const riskLines = [];
  if ((state.stats?.stress ?? 0) >= 85) {
    riskLines.push(`高压风险：压力 ${Math.round(state.stats.stress)}，建议优先降载。`);
  } else {
    riskLines.push(`压力状态：${Math.round(state.stats?.stress || 0)}（可控）。`);
  }
  if ((state.loanBalance || 0) > 0) {
    riskLines.push(`债务风险：当前贷款 ${formatUsd(state.loanBalance)}，需控制后续利息。`);
  }
  if (applicationSummary.wait > 0 || gradSummary.wait > 0) {
    riskLines.push("候补风险：存在未转正候补，建议优先补强有效更新材料。");
  }
  if (calibration?.byTier?.top20) {
    const top20Rate = Number(calibration.byTier.top20.admitRate || 0);
    const top20Min = Number(calibration.byTier.top20.targetMin || 0);
    const top20Max = Number(calibration.byTier.top20.targetMax || 1);
    if (top20Rate > top20Max) {
      riskLines.push("难度风险：Top20 偏易，建议提高顶尖校阈值。");
    } else if (top20Rate < top20Min) {
      riskLines.push("难度风险：Top20 偏难，建议增加高分档保护。");
    } else {
      riskLines.push("难度状态：Top20 录取率在目标区间。");
    }
  }
  sections.push(buildReportSection("风险复盘", riskLines));

  const legacy = state.legacyProgress || createDefaultLegacyProgress();
  const lastRun = legacy.lastRun;
  sections.push(
    buildReportSection("多周目传承", [
      legacy.completedRuns
        ? `历史完成局数：${legacy.completedRuns} · 历史最佳赛季 ${legacy.bestScore} 分`
        : "历史完成局数：0（当前为首局）",
      legacy.bestSchoolRank ? `历史最佳录取：QS ${legacy.bestSchoolRank}` : "历史最佳录取：暂无",
      legacy.bestSalary ? `历史最高薪资：${formatUsd(legacy.bestSalary)}` : "历史最高薪资：暂无",
      lastRun
        ? `上一局回顾：${lastRun.finalSchool || "未定学校"}${lastRun.chosenJob ? ` → ${lastRun.chosenJob}` : ""} · ${lastRun.dominantRouteLabel || "综合路线"}`
        : "上一局回顾：暂无",
    ]),
  );

  const timelineLines = buildCareerSettlementTimelineLines(36);
  sections.push(
    buildReportSection(
      "关键时间线",
      timelineLines.length ? timelineLines : state.log.slice(0, 20),
    ),
  );

  return sections;
}

function stringifyFinalReportSections(sections) {
  const lines = [];
  sections.forEach((section) => {
    lines.push(`【${section.title}】`);
    if (!section.lines.length) {
      lines.push("- 暂无记录");
    } else {
      section.lines.forEach((line) => lines.push(`- ${line}`));
    }
    lines.push("");
  });
  return lines.join("\n").trim();
}

function exportSummary() {
  if (!state.started) {
    exportText.textContent = "尚未开始旅程。";
  } else {
    const sections = buildProfessionalFinalReportSections();
    exportText.textContent = stringifyFinalReportSections(sections);
  }

  if (typeof exportDialog.showModal === "function") {
    exportDialog.showModal();
  } else {
    exportDialog.setAttribute("open", "true");
  }
}

